{
  "name": "EcoCycle AI - E-Waste Management",
  "description": "An AI-powered e-waste recycling platform that identifies items via camera, manages pickups, and rewards users with points.",
  "requestFramePermissions": [
    "camera",
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Role {
  USER = 'USER',
  COLLECTOR = 'COLLECTOR',
  ADMIN = 'ADMIN'
}

export enum ItemStatus {
  STORED = 'STORED',
  PICKUP_REQUESTED = 'PICKUP_REQUESTED',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED'
}

export enum PickupStatus {
  PENDING = 'PENDING',
  IN_PROGRESS = 'IN_PROGRESS',
  COMPLETED = 'COMPLETED'
}

export interface EWasteItem {
  id: string;
  name: string;
  category: string;
  description: string;
  estimatedPoints: number;
  imageUrl: string;
  status: ItemStatus;
  userId: string;
  createdAt: number;
}

export interface PickupRequest {
  id: string;
  userId: string;
  itemIds: string[];
  status: PickupStatus;
  location: {
    address: string;
    coords?: {
      lat: number;
      lng: number;
    };
  };
  collectorId?: string;
  totalPoints: number;
  createdAt: number;
  completedAt?: number;
}

export interface AppState {
  currentUser: {
    id: string;
    role: Role;
    points: number;
    name: string;
  };
  items: EWasteItem[];
  pickups: PickupRequest[];
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface ClassificationResult {
  name: string;
  category: string;
  estimatedPoints: number;
  description: string;
}

export const classifyEWaste = async (base64Image: string): Promise<ClassificationResult> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        {
          parts: [
            {
              inlineData: {
                mimeType: 'image/jpeg',
                data: base64Image.split(',')[1] || base64Image
              }
            },
            {
              text: "Analyze this image of electronic waste. Identify the device, its category (e.g., Computer, Smartphone, Home Appliance), and estimate its recycling value in points (between 10 and 500). Be accurate and professional."
            }
          ]
        }
      ],
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            category: { type: Type.STRING },
            estimatedPoints: { type: Type.NUMBER },
            description: { type: Type.STRING }
          },
          required: ["name", "category", "estimatedPoints", "description"]
        }
      }
    });

    return JSON.parse(response.text);
  } catch (error) {
    console.error("Gemini Classification Error:", error);
    throw new Error("Failed to classify e-waste item.");
  }
};

import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { Role, AppState, EWasteItem, PickupRequest, ItemStatus, PickupStatus } from './types';

interface AppContextType extends AppState {
  setRole: (role: Role) => void;
  addItem: (item: Omit<EWasteItem, 'id' | 'status' | 'userId' | 'createdAt'>) => void;
  requestPickup: (itemIds: string[], address: string, coords?: { lat: number, lng: number }) => void;
  assignPickup: (pickupId: string, collectorId: string) => void;
  updatePickupStatus: (pickupId: string, status: PickupStatus) => void;
  deleteItem: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const INITIAL_USERS = {
  [Role.USER]: { id: 'user-1', role: Role.USER, points: 1250, name: 'John Doe' },
  [Role.COLLECTOR]: { id: 'coll-1', role: Role.COLLECTOR, points: 0, name: 'Mike Green' },
  [Role.ADMIN]: { id: 'admin-1', role: Role.ADMIN, points: 0, name: 'Admin Sarah' },
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [role, setRoleState] = useState<Role>(Role.USER);
  const [points, setPoints] = useState(INITIAL_USERS[Role.USER].points);
  const [items, setItems] = useState<EWasteItem[]>([]);
  const [pickups, setPickups] = useState<PickupRequest[]>([]);

  const setRole = (newRole: Role) => {
    setRoleState(newRole);
    // In a real app, points would be fetched from a DB per user
    if (newRole === Role.USER) {
        setPoints(points);
    }
  };

  const addItem = (itemData: Omit<EWasteItem, 'id' | 'status' | 'userId' | 'createdAt'>) => {
    const newItem: EWasteItem = {
      ...itemData,
      id: Math.random().toString(36).substr(2, 9),
      status: ItemStatus.STORED,
      userId: INITIAL_USERS[Role.USER].id,
      createdAt: Date.now(),
    };
    setItems(prev => [newItem, ...prev]);
  };

  const deleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const requestPickup = (itemIds: string[], address: string, coords?: { lat: number, lng: number }) => {
    const selectedItems = items.filter(i => itemIds.includes(i.id));
    const totalPoints = selectedItems.reduce((acc, curr) => acc + curr.estimatedPoints, 0);

    const newPickup: PickupRequest = {
      id: `p-${Math.random().toString(36).substr(2, 5)}`,
      userId: INITIAL_USERS[Role.USER].id,
      itemIds,
      status: PickupStatus.PENDING,
      location: { address, coords },
      totalPoints,
      createdAt: Date.now(),
    };

    setPickups(prev => [newPickup, ...prev]);

    // Update items status
    setItems(prev => prev.map(item => 
      itemIds.includes(item.id) ? { ...item, status: ItemStatus.PICKUP_REQUESTED } : item
    ));
  };

  const updatePickupStatus = (pickupId: string, status: PickupStatus) => {
    setPickups(prev => prev.map(p => {
      if (p.id === pickupId) {
        const updatedPickup = { ...p, status };
        if (status === PickupStatus.COMPLETED) {
          updatedPickup.completedAt = Date.now();
          // Business Logic: Award points and update items only on completion
          setPoints(current => current + p.totalPoints);
          setItems(currentItems => currentItems.map(item => 
            p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.COMPLETED } : item
          ));
        } else if (status === PickupStatus.IN_PROGRESS) {
             setItems(currentItems => currentItems.map(item => 
            p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.IN_PROGRESS } : item
          ));
        }
        return updatedPickup;
      }
      return p;
    }));
  };

  const assignPickup = (pickupId: string, collectorId: string) => {
    setPickups(prev => prev.map(p => 
      p.id === pickupId ? { ...p, collectorId, status: PickupStatus.IN_PROGRESS } : p
    ));
    const pickup = pickups.find(p => p.id === pickupId);
    if (pickup) {
        setItems(prev => prev.map(item => 
            pickup.itemIds.includes(item.id) ? { ...item, status: ItemStatus.IN_PROGRESS } : item
        ));
    }
  };

  const value = {
    currentUser: { ...INITIAL_USERS[role], points: role === Role.USER ? points : 0 },
    items,
    pickups,
    setRole,
    addItem,
    requestPickup,
    assignPickup,
    updatePickupStatus,
    deleteItem
  };

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within an AppProvider');
  return context;
};

import React, { useRef, useState, useCallback } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
      setError(null);
    } catch (err) {
      setError("Unable to access camera. Please check permissions.");
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    setIsScanning(true);
    setError(null);

    const video = videoRef.current;
    const canvas = canvasRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(video, 0, 0);

    const base64 = canvas.toDataURL('image/jpeg');
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err) {
      setError("AI Classification failed. Try again.");
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
      });
      onClose();
    }
  };

  React.useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-50 flex flex-col">
      <div className="flex items-center justify-between p-4 text-white">
        <h2 className="text-xl font-bold">Scan E-Waste</h2>
        <button onClick={onClose} className="p-2 bg-white/10 rounded-full">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
          </svg>
        </button>
      </div>

      <div className="flex-1 relative flex items-center justify-center overflow-hidden bg-zinc-900">
        {!previewImage ? (
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            className="w-full h-full object-cover"
          />
        ) : (
          <img src={previewImage} className="w-full h-full object-contain" />
        )}

        {isScanning && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/50">
            <div className="text-center">
              <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mx-auto mb-4"></div>
              <p className="text-white font-medium">AI Analyzing...</p>
            </div>
          </div>
        )}

        {error && (
          <div className="absolute bottom-24 left-4 right-4 bg-red-500 text-white p-4 rounded-lg shadow-lg">
            {error}
          </div>
        )}
      </div>

      <div className="bg-zinc-900 p-6">
        {!result ? (
          <div className="flex justify-center">
            <button 
              onClick={capture}
              disabled={isScanning}
              className="w-20 h-20 rounded-full border-4 border-white bg-emerald-500 flex items-center justify-center shadow-lg active:scale-95 transition-transform"
            >
               <div className="w-16 h-16 rounded-full border-2 border-emerald-400 bg-white"></div>
            </button>
          </div>
        ) : (
          <div className="bg-white rounded-2xl p-4 text-zinc-900 shadow-xl max-h-[40vh] overflow-y-auto">
            <div className="flex justify-between items-start mb-2">
              <div>
                <h3 className="text-lg font-bold">{result.name}</h3>
                <span className="text-sm px-2 py-1 bg-emerald-100 text-emerald-700 rounded-full uppercase font-semibold">{result.category}</span>
              </div>
              <div className="text-emerald-600 font-bold text-xl">
                +{result.estimatedPoints} pts
              </div>
            </div>
            <p className="text-sm text-zinc-600 mb-4">{result.description}</p>
            <div className="flex gap-3">
              <button 
                onClick={() => {
                  setResult(null);
                  setPreviewImage(null);
                  startCamera();
                }}
                className="flex-1 py-3 border border-zinc-300 rounded-xl font-semibold hover:bg-zinc-50"
              >
                Retake
              </button>
              <button 
                onClick={handleSave}
                className="flex-1 py-3 bg-emerald-600 text-white rounded-xl font-semibold shadow-md shadow-emerald-200"
              >
                Save Item
              </button>
            </div>
          </div>
        )}
      </div>

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

import React, { useState } from 'react';
import { useApp } from '../store';
import { EWasteItem, ItemStatus } from '../types';

interface Props {
  onClose: () => void;
  selectedItems: EWasteItem[];
}

export const PickupRequestModal: React.FC<Props> = ({ onClose, selectedItems }) => {
  const [address, setAddress] = useState('');
  const [coords, setCoords] = useState<{ lat: number; lng: number } | undefined>();
  const [isLoadingLocation, setIsLoadingLocation] = useState(false);
  const { requestPickup } = useApp();

  const handleGetCurrentLocation = () => {
    setIsLoadingLocation(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          setCoords({
            lat: position.coords.latitude,
            lng: position.coords.longitude
          });
          setAddress(`Current Location: ${position.coords.latitude.toFixed(4)}, ${position.coords.longitude.toFixed(4)}`);
          setIsLoadingLocation(false);
        },
        () => {
          setIsLoadingLocation(false);
          alert("Unable to retrieve location. Please enter address manually.");
        }
      );
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!address.trim()) return;

    requestPickup(selectedItems.map(i => i.id), address, coords);
    onClose();
  };

  const totalPoints = selectedItems.reduce((acc, curr) => acc + curr.estimatedPoints, 0);

  return (
    <div className="fixed inset-0 bg-black/60 z-[60] flex items-end sm:items-center justify-center p-0 sm:p-4">
      <div className="bg-white w-full max-w-lg rounded-t-3xl sm:rounded-3xl overflow-hidden shadow-2xl animate-in slide-in-from-bottom duration-300">
        <div className="p-6 border-b flex justify-between items-center bg-zinc-50">
          <h2 className="text-xl font-bold text-zinc-900">Request Pickup</h2>
          <button onClick={onClose} className="text-zinc-400 hover:text-zinc-600">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
            </svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-6">
          <div className="mb-6">
            <h3 className="text-sm font-semibold text-zinc-500 uppercase tracking-wider mb-3">Items Selected ({selectedItems.length})</h3>
            <div className="flex -space-x-2 overflow-hidden py-1">
              {selectedItems.map(item => (
                <img 
                  key={item.id} 
                  src={item.imageUrl} 
                  className="inline-block h-12 w-12 rounded-full ring-2 ring-white object-cover" 
                />
              ))}
            </div>
            <div className="mt-2 text-emerald-600 font-bold text-lg">
              Total Points Value: {totalPoints}
            </div>
          </div>

          <div className="mb-6">
            <label className="block text-sm font-semibold text-zinc-700 mb-2">Pickup Address</label>
            <textarea
              required
              className="w-full px-4 py-3 bg-zinc-50 border border-zinc-200 rounded-xl focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all outline-none resize-none"
              rows={3}
              placeholder="Enter full address where items are located..."
              value={address}
              onChange={(e) => setAddress(e.target.value)}
            />
            <button
              type="button"
              onClick={handleGetCurrentLocation}
              disabled={isLoadingLocation}
              className="mt-3 flex items-center text-emerald-600 text-sm font-semibold hover:text-emerald-700 transition-colors"
            >
              <svg className="w-4 h-4 mr-1" fill="currentColor" viewBox="0 0 20 20">
                <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
              </svg>
              {isLoadingLocation ? 'Locating...' : 'Use Current Location'}
            </button>
          </div>

          <button
            type="submit"
            className="w-full bg-emerald-600 text-white py-4 rounded-xl font-bold text-lg shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all active:scale-[0.98]"
          >
            Confirm Request
          </button>
          <p className="text-center text-zinc-400 text-xs mt-4">
            A collector will be assigned to your request within 24 hours.
          </p>
        </form>
      </div>
    </div>
  );
};

