export const CollectorDashboard: React.FC = () => {
  const { pickups, updatePickupStatus, items, currentUser } = useApp();
  const [activeTab, setActiveTab] = useState<'todo' | 'done'>('todo');

  if (!currentUser) return null;

  const assignedPickups = pickups.filter(p => p.status !== PickupStatus.COMPLETED);
  const completedPickups = pickups.filter(p => p.status === PickupStatus.COMPLETED);

  return (
    <div className="h-full flex flex-col space-y-6">
      <div className="bg-indigo-700 rounded-[32px] p-8 text-white shadow-xl">
        <p className="text-indigo-200 text-xs font-bold uppercase tracking-widest">Collector Terminal</p>
        <h2 className="text-3xl font-black mb-6">Route Overview</h2>
        <div className="grid grid-cols-2 gap-4">
           <div className="bg-white/10 p-4 rounded-2xl">
              <p className="text-[10px] font-bold opacity-60 uppercase">Queued</p>
              <p className="text-2xl font-black">{assignedPickups.length}</p>
           </div>
           <div className="bg-white/10 p-4 rounded-2xl">
              <p className="text-[10px] font-bold opacity-60 uppercase">Completed</p>
              <p className="text-2xl font-black">{completedPickups.length}</p>
           </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto pb-32 space-y-4">
        <div className="flex bg-zinc-100 p-1 rounded-2xl mb-4">
          <button onClick={() => setActiveTab('todo')} className={`flex-1 py-3 rounded-xl text-xs font-black uppercase ${activeTab === 'todo' ? 'bg-white shadow-sm text-indigo-700' : 'text-zinc-400'}`}>Assigned</button>
          <button onClick={() => setActiveTab('done')} className={`flex-1 py-3 rounded-xl text-xs font-black uppercase ${activeTab === 'done' ? 'bg-white shadow-sm text-indigo-700' : 'text-zinc-400'}`}>Finished</button>
