import React, { useRef, useState, useCallback } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
      setError(null);
    } catch (err) {
      setError("Unable to access camera. Check device settings.");
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    setIsScanning(true);
    setError(null);

    const video = videoRef.current;
    const canvas = canvasRef.current;
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    ctx?.drawImage(video, 0, 0);

    const base64 = canvas.toDataURL('image/jpeg');
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err) {
      setError("AI failed to recognize the item.");
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
      });
      onClose();
    }
  };

  React.useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col animate-in fade-in duration-500">
      {/* AppBar */}
      <div className="flex items-center justify-between p-6 text-white bg-gradient-to-b from-black/50 to-transparent">
        <h2 className="text-xl font-black uppercase tracking-widest">Vision Scanner</h2>
        <button onClick={onClose} className="p-3 bg-white/10 rounded-2xl backdrop-blur-md active:scale-90 transition-all">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 relative flex items-center justify-center bg-zinc-950 overflow-hidden">
        {!previewImage ? (
          <div className="w-full h-full relative">
            <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
            {/* Camera Guide UI */}
            <div className="absolute inset-0 border-[40px] border-black/20 pointer-events-none flex items-center justify-center">
                <div className="w-64 h-64 border-2 border-emerald-500/50 rounded-[40px] relative">
                   <div className="absolute -top-1 -left-1 w-8 h-8 border-t-4 border-l-4 border-emerald-500 rounded-tl-2xl"></div>
                   <div className="absolute -top-1 -right-1 w-8 h-8 border-t-4 border-r-4 border-emerald-500 rounded-tr-2xl"></div>
                   <div className="absolute -bottom-1 -left-1 w-8 h-8 border-b-4 border-l-4 border-emerald-500 rounded-bl-2xl"></div>
                   <div className="absolute -bottom-1 -right-1 w-8 h-8 border-b-4 border-r-4 border-emerald-500 rounded-br-2xl"></div>
                </div>
            </div>
          </div>
        ) : (
          <img src={previewImage} className="w-full h-full object-contain p-4" />
        )}

        {isScanning && (
          <div className="absolute inset-0 flex items-center justify-center bg-zinc-950/80 backdrop-blur-sm">
            <div className="text-center animate-bounce">
              <div className="w-16 h-16 border-8 border-emerald-500 border-t-transparent rounded-full animate-spin mx-auto mb-6 shadow-xl shadow-emerald-500/20"></div>
              <p className="text-emerald-400 font-black uppercase tracking-[0.3em] text-xs">Processing Pixels</p>
            </div>
          </div>
        )}

        {error && (
          <div className="absolute bottom-32 left-8 right-8 bg-red-600/90 backdrop-blur text-white p-6 rounded-3xl shadow-2xl flex items-center gap-4 animate-in slide-in-from-bottom-4">
             <div className="w-10 h-10 bg-white/20 rounded-xl flex items-center justify-center flex-shrink-0">!</div>
             <p className="font-bold text-sm">{error}</p>
          </div>
        )}
      </div>

      {/* Bottom Sheet Action Area */}
      <div className="bg-zinc-950 p-10 pt-4 flex justify-center items-center">
        {!result ? (
           <div className="flex flex-col items-center gap-4">
              <p className="text-zinc-500 font-bold uppercase tracking-widest text-[10px]">Center item in frame</p>
              <button 
                onClick={capture}
                disabled={isScanning}
                className="w-24 h-24 rounded-full border-[6px] border-white/20 p-2 active:scale-90 transition-all"
              >
                <div className="w-full h-full rounded-full bg-white flex items-center justify-center shadow-2xl shadow-white/20">
                    <div className="w-16 h-16 rounded-full border-2 border-zinc-200"></div>
                </div>
              </button>
           </div>
        ) : (
          <div className="bg-white w-full rounded-[32px] p-6 text-zinc-900 shadow-2xl animate-in slide-in-from-bottom-8">
            <div className="flex justify-between items-start mb-4">
              <div className="min-w-0 flex-1">
                <p className="text-[10px] font-black text-emerald-600 uppercase tracking-widest mb-1">{result.category}</p>
                <h3 className="text-2xl font-black truncate leading-tight">{result.name}</h3>
              </div>
              <div className="bg-emerald-50 text-emerald-700 px-4 py-2 rounded-2xl font-black text-lg">
                +{result.estimatedPoints}
              </div>
            </div>
            <p className="text-sm text-zinc-500 font-medium mb-8 leading-relaxed">{result.description}</p>
            <div className="flex gap-4">
              <button 
                onClick={() => { setResult(null); setPreviewImage(null); startCamera(); }}
                className="flex-1 py-4 bg-zinc-100 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-zinc-200"
              >
                Retake
              </button>
              <button 
                onClick={handleSave}
                className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-emerald-200 hover:bg-emerald-700 active:scale-95 transition-all"
              >
                Store Item
              </button>
            </div>
          </div>
        )}
      </div>

      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

