import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

// Always use named parameter for apiKey. API_KEY is fetched from environment.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface ClassificationResult {
  name: string;
  category: string;
  estimatedPoints: number;
  description: string;
}

/**
 * Classifies an image of electronic waste using Gemini 3 Flash.
 */
export const classifyEWaste = async (base64Image: string): Promise<ClassificationResult> => {
  try {
    // Using gemini-3-flash-preview for multimodal classification tasks.
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] || base64Image
            }
          },
          {
            text: "Analyze this image of electronic waste. Identify the device, its category (e.g., Computer, Smartphone, Home Appliance), and estimate its recycling value in points (between 10 and 500). Be accurate and professional."
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { 
              type: Type.STRING,
              description: "The common name of the electronic device."
            },
            category: { 
              type: Type.STRING,
              description: "The recycling category of the device."
            },
            estimatedPoints: { 
              type: Type.NUMBER,
              description: "Estimated point value based on materials and complexity."
            },
            description: { 
              type: Type.STRING,
              description: "A short professional summary of the item."
            }
          },
          required: ["name", "category", "estimatedPoints", "description"],
          propertyOrdering: ["name", "category", "estimatedPoints", "description"]
        }
      }
    });

    // Access the .text property directly (do not call as a method).
    const textOutput = response.text;
    if (!textOutput) {
      throw new Error("No text returned from the model.");
    }

    return JSON.parse(textOutput.trim());
  } catch (error) {
    console.error("Gemini Classification Error:", error);
    throw new Error("Failed to classify e-waste item.");
  }
};

