/**
 * Finds local recycling centers using Google Maps grounding
 */
export const findRecyclingCenters = async (query: string, lat?: number, lng?: number): Promise<GroundingResult> => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: `Find recycling centers or drop-off points for: ${query}. Be specific to the current area if coordinates are provided.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: (lat && lng) ? { latitude: lat, longitude: lng } : undefined
          }
        }
      },
    });

    const text = response.text || "I couldn't find any centers nearby.";

    // Extract grounding chunks
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        title: c.maps.title || "View on Google Maps",
        uri: c.maps.uri
      }));

    return { text, links };
  } catch (error) {
    console.error("Grounding Error:", error);
    throw new Error("Failed to search local centers.");
  }
};

import React, { useState } from 'react';
import { findRecyclingCenters, GroundingResult } from '../geminiService';

export const MapSearch: React.FC = () => {
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<GroundingResult | null>(null);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!query.trim()) return;

    setLoading(true);
    try {
      // Try to get location first
      let lat, lng;
      try {
        const pos = await new Promise<GeolocationPosition>((resolve, reject) => {
          navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 5000 });
        });
        lat = pos.coords.latitude;
        lng = pos.coords.longitude;
      } catch (e) {
        console.warn("Location access denied or timed out");
      }

      const data = await findRecyclingCenters(query, lat, lng);
      setResult(data);
    } catch (err) {
      alert("Search failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6 animate-in fade-in duration-300">
      <div className="p-1">
        <h3 className="text-xl font-black text-zinc-900 mb-4">Find Disposal Centers</h3>
        <form onSubmit={handleSearch} className="relative">
          <input
            type="text"
            className="w-full pl-12 pr-4 py-4 bg-white border border-zinc-100 rounded-[24px] shadow-sm focus:ring-2 focus:ring-emerald-500 outline-none font-medium transition-all"
            placeholder="What do you need to recycle?"
            value={query}
            onChange={(e) => setQuery(e.target.value)}
          />
          <div className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-600">
