import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === "undefined") return null;
  return new GoogleGenAI({ apiKey });
};

export interface ClassificationResult {
  name: string;
  category: string;
  estimatedPoints: number;
  description: string;
  impact: {
    co2SavedKg: number;
    materialsSaved: string[];
    hazards: string[];
  };
  handlingSteps: string[];
}

export interface GroundingResult {
  text: string;
  links: { title: string; uri: string }[];
}

export const classifyEWaste = async (base64Image: string): Promise<ClassificationResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("API Key not configured.");

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] || base64Image
            }
          },
          {
            text: `Analyze this e-waste item for a sustainability thesis. 
            Identify the item and provide a detailed JSON response including:
            1. Name and Category.
            2. Estimated Recycling Points (10-500).
            3. A technical description.
            4. Environmental Impact: CO2 saved (kg), reusable materials (list), and toxic hazards (list).
            5. Handling Steps: Safety instructions for disposal.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            category: { type: Type.STRING },
            estimatedPoints: { type: Type.NUMBER },
            description: { type: Type.STRING },
            impact: {
              type: Type.OBJECT,
              properties: {
                co2SavedKg: { type: Type.NUMBER },
                materialsSaved: { type: Type.ARRAY, items: { type: Type.STRING } },
                hazards: { type: Type.ARRAY, items: { type: Type.STRING } }
              },
              required: ["co2SavedKg", "materialsSaved", "hazards"]
            },
            handlingSteps: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["name", "category", "estimatedPoints", "description", "impact", "handlingSteps"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No data received.");
    return JSON.parse(text.trim());
  } catch (error) {
    console.error("AI Error:", error);
    throw new Error("Detailed recognition failed. Check lighting and try again.");
  }
};

export const findRecyclingCenters = async (query: string, lat?: number, lng?: number): Promise<GroundingResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("API Key not configured.");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: `Find certified e-waste recycling centers for: ${query}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: (lat && lng) ? { latitude: lat, longitude: lng } : undefined
          }
        }
      },
    });

    const text = response.text || "No centers found nearby.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        title: c.maps.title || "View Location",
        uri: c.maps.uri
      }));

    return { text, links };
  } catch (error) {
    console.error("Grounding Error:", error);
    throw new Error("Search failed.");
  }
};

import React, { useRef, useState, useCallback } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
      setStream(s);
      if (videoRef.current) videoRef.current.srcObject = s;
    } catch (err) {
      setError("Camera access denied.");
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
  }, [stream]);

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current) return;
    setIsScanning(true);
    setError(null);

    const canvas = canvasRef.current;
    canvas.width = videoRef.current.videoWidth;
    canvas.height = videoRef.current.videoHeight;
    canvas.getContext('2d')?.drawImage(videoRef.current, 0, 0);

    const base64 = canvas.toDataURL('image/jpeg');
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err) {
      setError("Analysis failed. Please retry.");
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
        impact: result.impact,
        handlingSteps: result.handlingSteps
      });
      onClose();
    }
  };

  React.useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col animate-in fade-in duration-300">
      <div className="p-6 flex justify-between items-center text-white bg-black/40 backdrop-blur-md">
        <h2 className="font-black text-xs uppercase tracking-[0.3em]">AI Deep Scan</h2>
        <button onClick={onClose} className="p-2 bg-white/10 rounded-full">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 relative bg-zinc-950 overflow-hidden flex items-center justify-center">
        {!previewImage ? (
          <video ref={videoRef} autoPlay playsInline className="w-full h-full object-cover" />
        ) : (
          <img src={previewImage} className="w-full h-full object-contain p-4" />
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/60 flex items-center justify-center backdrop-blur-sm z-50">
            <div className="text-center">
              <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4 mx-auto"></div>
              <p className="text-white font-black text-[10px] uppercase tracking-widest animate-pulse">Running Environmental Analysis...</p>
            </div>
          </div>
        )}
      </div>

      <div className="bg-white rounded-t-[40px] p-8 pb-12 shadow-2xl transition-all duration-500 overflow-y-auto max-h-[70vh]">
        {!result ? (
          <div className="text-center space-y-6">
            <p className="text-zinc-400 font-bold text-xs uppercase tracking-widest">Position product within frame</p>
            <button onClick={capture} disabled={isScanning} className="w-20 h-20 rounded-full bg-emerald-600 p-1 ring-8 ring-emerald-100 active:scale-90 transition-all shadow-xl">
              <div className="w-full h-full rounded-full border-4 border-white/20 flex items-center justify-center">
                <div className="w-8 h-8 rounded-full bg-white"></div>
              </div>
            </button>
          </div>
        ) : (
          <div className="space-y-6">
            <div className="flex justify-between items-start">
              <div className="flex-1 min-w-0">
                <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase tracking-widest">{result.category}</span>
                <h3 className="text-2xl font-black text-zinc-900 mt-2 truncate">{result.name}</h3>
              </div>
              <div className="text-right">
                <p className="text-[10px] font-black text-zinc-400 uppercase">Points</p>
                <p className="text-2xl font-black text-emerald-600">+{result.estimatedPoints}</p>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div className="p-4 bg-emerald-50 rounded-2xl border border-emerald-100">
                <p className="text-[9px] font-black text-emerald-700 uppercase mb-1">CO2 Saved</p>
                <p className="text-lg font-black text-emerald-900">{result.impact.co2SavedKg}kg</p>
              </div>
              <div className="p-4 bg-amber-50 rounded-2xl border border-amber-100">
                <p className="text-[9px] font-black text-amber-700 uppercase mb-1">Hazards Found</p>
                <p className="text-lg font-black text-amber-900">{result.impact.hazards.length}</p>
              </div>
            </div>

            <div>
              <p className="text-[10px] font-black text-zinc-400 uppercase tracking-widest mb-3">Materials Recovery</p>
              <div className="flex flex-wrap gap-2">
