import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === "undefined") return null;
  return new GoogleGenAI({ apiKey });
};

export interface ClassificationResult {
  name: string;
  brand: string;
  model: string;
  category: string;
  estimatedPoints: number;
  description: string;
  impact: {
    co2SavedKg: number;
    materialsSaved: string[];
    hazards: string[];
    recyclabilityScore: number;
    metalRecovery: { element: string, percentage: number, marketValueUsd: number }[];
  };
  handlingSteps: string[];
}

export const classifyEWaste = async (base64Image: string): Promise<ClassificationResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("API Key not configured.");

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Image.split(',')[1] || base64Image
            }
          },
          {
            text: `Act as a Senior Environmental Materials Scientist. Analyze this electronic device for a Master's Thesis. 
            Identify the specific Brand and Model if possible.
            Provide a detailed JSON response including:
            1. Brand, Model, and technical name.
            2. Recyclability Score (0-100).
            3. Detailed Material Recovery: Estimate percentages of elements like Copper, Gold, Silver, and Aluminum and their approx scrap market value.
            4. Hazardous list: Specific chemicals (Lead, Cadmium, Mercury).
            5. Handling: Technical disposal protocol.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            brand: { type: Type.STRING },
            model: { type: Type.STRING },
            category: { type: Type.STRING },
            estimatedPoints: { type: Type.NUMBER },
            description: { type: Type.STRING },
            impact: {
              type: Type.OBJECT,
              properties: {
                co2SavedKg: { type: Type.NUMBER },
                materialsSaved: { type: Type.ARRAY, items: { type: Type.STRING } },
                hazards: { type: Type.ARRAY, items: { type: Type.STRING } },
                recyclabilityScore: { type: Type.NUMBER },
                metalRecovery: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      element: { type: Type.STRING },
                      percentage: { type: Type.NUMBER },
                      marketValueUsd: { type: Type.NUMBER }
                    },
                    required: ["element", "percentage", "marketValueUsd"]
                  }
                }
              },
              required: ["co2SavedKg", "materialsSaved", "hazards", "recyclabilityScore", "metalRecovery"]
            },
            handlingSteps: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["name", "brand", "model", "category", "estimatedPoints", "description", "impact", "handlingSteps"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No analysis received.");
    return JSON.parse(text.trim());
  } catch (error) {
    console.error("AI Analysis Error:", error);
    throw new Error("Analysis failed. Try taking a clearer photo.");
  }
};

export interface GroundingResult {
  text: string;
  links: { title: string; uri: string }[];
}

export const findRecyclingCenters = async (query: string, lat?: number, lng?: number): Promise<GroundingResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("API Key not configured.");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: `Find certified e-waste recycling centers for: ${query}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: (lat && lng) ? { latitude: lat, longitude: lng } : undefined
          }
        }
      },
    });

    const text = response.text || "No centers found nearby.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        title: c.maps.title || "View Location",
        uri: c.maps.uri
      }));

    return { text, links };
  } catch (error) {
    console.error("Grounding Error:", error);
    throw new Error("Search failed.");
  }
};

