import React, { useRef, useState, useCallback, useEffect } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      setError(null);
      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      const constraints = {
        video: {
          facingMode: { ideal: 'environment' },
          width: { ideal: 1280 },
          height: { ideal: 720 }
        },
        audio: false
      };

      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        videoRef.current.srcObject = s;
        // Forces playback on mobile browsers
        const playPromise = videoRef.current.play();
        if (playPromise !== undefined) {
          playPromise.catch(e => {
            console.error("Autoplay prevented:", e);
            setError("Tap the button to start camera");
          });
        }
      }
    } catch (err: any) {
      console.error("Camera Hardware Error:", err);
      setError("Camera blocked. Please check permissions or use Gallery.");
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraActive(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      console.error("AI Analysis Error:", err);
      setError(err.message || "AI Analysis failed. Try again.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current || !isCameraActive) return;
    const canvas = canvasRef.current;
    const video = videoRef.current;

    // Use actual video dimensions
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0);
      // High quality JPEG for better AI recognition
      const base64 = canvas.toDataURL('image/jpeg', 0.92);
      await processImage(base64);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        brand: result.brand,
        model: result.model,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
        impact: result.impact,
        handlingSteps: result.handlingSteps
      });
      onClose();
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col font-sans">
      <div className="p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/60 to-transparent z-50">
        <div className="flex items-center gap-2">
          <div className={`w-2 h-2 rounded-full ${isCameraActive ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[10px] uppercase tracking-[0.3em]">AI Scan Terminal</h2>
        </div>
        <button onClick={onClose} className="w-10 h-10 flex items-center justify-center bg-white/10 rounded-full backdrop-blur-md">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {!previewImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              onPlaying={() => setIsCameraActive(true)}
              className="w-full h-full object-cover" 
            />
            {isCameraActive && (
              <div className="absolute inset-0 pointer-events-none border-[30px] border-black/10">
                 <div className="absolute top-0 left-0 w-8 h-8 border-l-4 border-t-4 border-emerald-400/50"></div>
                 <div className="absolute top-0 right-0 w-8 h-8 border-r-4 border-t-4 border-emerald-400/50"></div>
                 <div className="absolute bottom-0 left-0 w-8 h-8 border-l-4 border-b-4 border-emerald-400/50"></div>
                 <div className="absolute bottom-0 right-0 w-8 h-8 border-r-4 border-b-4 border-emerald-400/50"></div>
                 <div className="absolute left-0 right-0 top-1/2 h-[1px] bg-emerald-500/30 animate-[scan_3s_infinite]"></div>
              </div>
            )}
          </>
        ) : (
          <img src={previewImage} className="max-w-full max-h-full object-contain p-4 animate-in zoom-in-95 duration-500" />
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-md flex flex-col items-center justify-center z-[60] p-10 text-center">
            <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-6"></div>
            <p className="text-white font-black text-xl mb-1">Deep Learning Analysis</p>
            <p className="text-emerald-500/60 text-[10px] font-black uppercase tracking-[0.2em]">Material Database Search...</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-8 top-1/2 -translate-y-1/2 bg-white rounded-3xl p-8 text-center shadow-2xl z-50">
            <p className="text-zinc-900 font-bold mb-6 text-sm leading-relaxed">{error}</p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={() => { setError(null); startCamera(); }}
                className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg active:scale-95"
              >
                Start Camera
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full py-4 bg-zinc-100 text-zinc-600 rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95"
              >
                Choose from Gallery
              </button>
            </div>
          </div>
        )}
      </div>

      <div className="bg-white rounded-t-[48px] p-8 pb-12 shadow-[0_-20px_50px_rgba(0,0,0,0.1)] overflow-y-auto max-h-[75vh]">
        {!result ? (
          <div className="flex flex-col items-center gap-8">
            <div className="text-center">
              <h4 className="text-zinc-900 font-black text-2xl tracking-tight mb-1">Capture Device</h4>
              <p className="text-zinc-400 text-[10px] font-black uppercase tracking-[0.2em]">Auto-Detection System</p>
            </div>

            <div className="flex items-center gap-10">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-14 h-14 bg-zinc-50 border border-zinc-100 text-zinc-400 rounded-2xl flex items-center justify-center active:scale-90 transition-all"
               >
                 <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
               </button>

               <button 
                onClick={capture} 
                disabled={isScanning || !isCameraActive} 
                className={`w-24 h-24 rounded-full p-1.5 ring-8 transition-all shadow-2xl ${isCameraActive ? 'bg-emerald-600 ring-emerald-50 active:scale-95' : 'bg-zinc-200 ring-zinc-50 opacity-50'}`}
               >
                <div className="w-full h-full rounded-full border-4 border-white/30 flex items-center justify-center">
                  <div className="w-10 h-10 rounded-full bg-white"></div>
                </div>
               </button>

               <button 
                onClick={() => { stopCamera(); startCamera(); }}
                className="w-14 h-14 bg-zinc-50 border border-zinc-100 text-zinc-400 rounded-2xl flex items-center justify-center active:scale-90 transition-all"
               >
                 <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
               </button>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload} 
            />
          </div>
        ) : (
          <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
