      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      console.error("AI Capture Error:", err);
      setError(err.message || "Failed to analyze device. Try a clearer angle.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    // Check if camera is actually ready and video is playing
    if (!videoRef.current || !canvasRef.current || !isCameraLive) {
      if (!isCameraLive) {
        // Force try to play if it was stuck
        videoRef.current?.play().then(() => setIsCameraLive(true)).catch(() => {});
      }
      return;
    }

    const canvas = canvasRef.current;
    const video = videoRef.current;

    // Sync canvas resolution to the real video stream
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');

    if (ctx) {
      ctx.drawImage(video, 0, 0);
      const base64 = canvas.toDataURL('image/jpeg', 0.9);
      await processImage(base64);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        brand: result.brand,
        model: result.model,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
        impact: result.impact,
        handlingSteps: result.handlingSteps
      });
      onClose();
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col font-sans select-none overflow-hidden">
      {/* Header Bar */}
      <div className="p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/80 to-transparent z-50">
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full ${isCameraLive ? 'bg-emerald-500 shadow-[0_0_10px_#10b981] animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[11px] uppercase tracking-[0.4em]">Deep-Lens AI</h2>
        </div>
        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center bg-white/10 backdrop-blur-xl rounded-full border border-white/10 active:scale-90 transition-all">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      {/* Camera Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center">
        {!previewImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              onCanPlay={() => setIsCameraLive(true)}
              className={`w-full h-full object-cover transition-opacity duration-1000 ${isCameraLive ? 'opacity-100' : 'opacity-0'}`} 
            />

            {/* Visual Scan HUD */}
            {isCameraLive && (
              <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center">
                <div className="w-72 h-72 border-2 border-white/20 rounded-[40px] relative">
                  <div className="absolute -top-1 -left-1 w-12 h-12 border-t-4 border-l-4 border-emerald-500 rounded-tl-xl"></div>
                  <div className="absolute -top-1 -right-1 w-12 h-12 border-t-4 border-r-4 border-emerald-500 rounded-tr-xl"></div>
                  <div className="absolute -bottom-1 -left-1 w-12 h-12 border-b-4 border-l-4 border-emerald-500 rounded-bl-xl"></div>
                  <div className="absolute -bottom-1 -right-1 w-12 h-12 border-b-4 border-r-4 border-emerald-500 rounded-br-xl"></div>
                  <div className="absolute left-0 right-0 top-1/2 h-0.5 bg-emerald-500/30 animate-[scan_2s_infinite]"></div>
                </div>
                <p className="mt-8 text-white/40 text-[10px] font-black uppercase tracking-[0.3em]">Center device in frame</p>
              </div>
            )}

            {/* Manual Start Fallback (for mobile autoplay restrictions) */}
            {!isCameraLive && !error && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900 z-10 px-10 text-center">
                 <button 
                  onClick={() => { videoRef.current?.play(); setIsCameraLive(true); }}
                  className="w-24 h-24 bg-emerald-600 rounded-full flex items-center justify-center text-white shadow-2xl mb-6 active:scale-95 transition-transform"
                 >
                    <svg className="w-12 h-12 ml-1" fill="currentColor" viewBox="0 0 20 20"><path d="M4.516 7.548c0-.923.651-1.623 1.302-2.285l9.99-9.99c.66-.662 1.348-.309 1.348.651v19.992c0 .96-.688 1.313-1.348.651l-9.99-9.99c-.651-.662-1.302-1.362-1.302-2.285z"/></svg>
                 </button>
                 <h3 className="text-white font-black text-lg">Hardware Initializing</h3>
                 <p className="text-zinc-500 text-[10px] mt-2 uppercase tracking-[0.2em]">Tap button if view is black</p>
              </div>
            )}
          </>
        ) : (
          <div className="w-full h-full p-10 bg-zinc-900 flex items-center justify-center">
            <img src={previewImage} className="max-w-full max-h-full rounded-[40px] shadow-2xl ring-8 ring-white/5 animate-in zoom-in-95 duration-700" />
          </div>
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-2xl flex flex-col items-center justify-center z-[60] p-10 text-center">
            <div className="relative w-24 h-24 mb-10">
              <div className="absolute inset-0 border-8 border-emerald-500/10 rounded-full"></div>
              <div className="absolute inset-0 border-8 border-emerald-500 border-t-transparent rounded-full animate-spin"></div>
              <div className="absolute inset-0 flex items-center justify-center">
                <svg className="w-10 h-10 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
