            <h3 className="text-white font-black text-2xl mb-2 tracking-tight">AI Identification</h3>
            <p className="text-emerald-400 text-[10px] font-black uppercase tracking-[0.3em]">Querying Environmental Databases</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-8 top-1/2 -translate-y-1/2 bg-white rounded-[40px] p-10 text-center shadow-2xl z-50">
            <div className="w-20 h-20 bg-red-100 text-red-600 rounded-3xl flex items-center justify-center mx-auto mb-6">
              <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            </div>
            <p className="text-zinc-900 font-black text-lg mb-8 leading-tight">{error}</p>
            <div className="flex flex-col gap-4">
              <button 
                onClick={() => { setError(null); startCamera(); }}
                className="w-full py-5 bg-zinc-900 text-white rounded-[24px] font-black text-xs uppercase tracking-widest active:scale-95 transition-all"
              >
                Reset Camera
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()}
