      {/* Control Panel */}
      <div className="bg-white rounded-t-[56px] p-10 pb-16 shadow-[0_-20px_60px_rgba(0,0,0,0.15)] z-50 overflow-y-auto max-h-[80vh]">
        {!result ? (
          <div className="flex flex-col items-center gap-10">
            <div className="text-center">
              <h4 className="text-zinc-900 font-black text-3xl tracking-tighter mb-1">Visual Search</h4>
