            <div className="flex items-center gap-10">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-16 h-16 bg-zinc-50 border-2 border-zinc-100 text-zinc-400 rounded-3xl flex items-center justify-center active:scale-90 transition-all shadow-sm"
               >
                 <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
               </button>

               <button 
                onClick={capture} 
                disabled={isScanning || !isCameraLive} 
                className={`w-28 h-28 rounded-full p-2 transition-all shadow-2xl ${isCameraLive ? 'bg-emerald-600 ring-[12px] ring-emerald-50 active:scale-90' : 'bg-zinc-200 ring-[12px] ring-zinc-50 cursor-not-allowed'}`}
               >
                <div className="w-full h-full rounded-full border-4 border-white/20 flex items-center justify-center">
                  <div className="w-12 h-12 rounded-full bg-white shadow-[0_4px_10px_rgba(0,0,0,0.1)]"></div>
                </div>
               </button>

               <button 
                onClick={() => { stopCamera(); startCamera(); }}
                className="w-16 h-16 bg-zinc-50 border-2 border-zinc-100 text-zinc-400 rounded-3xl flex items-center justify-center active:scale-90 transition-all shadow-sm"
               >
                 <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
               </button>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              capture="environment"
              onChange={handleFileUpload} 
            />
          </div>
        ) : (
          <div className="space-y-10 animate-in slide-in-from-bottom duration-700">
            <header className="flex justify-between items-start gap-4">
              <div className="flex-1 min-w-0">
                <span className="inline-block px-3 py-1 bg-emerald-50 text-emerald-700 text-[10px] font-black uppercase tracking-widest rounded-lg mb-3">{result.category}</span>
                <h3 className="text-3xl font-black text-zinc-900 leading-[1.1] truncate">{result.brand} {result.model}</h3>
                <p className="text-zinc-500 text-sm font-semibold mt-1">{result.name}</p>
              </div>
              <div className="bg-emerald-600 text-white px-6 py-5 rounded-[28px] text-center shadow-xl shadow-emerald-200">
                <p className="text-[10px] font-black uppercase opacity-60 mb-0.5">Value</p>
                <p className="text-2xl font-black">{result.estimatedPoints}</p>
              </div>
            </header>

            <div className="grid grid-cols-2 gap-5">
               <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
                  <p className="text-[10px] font-black text-zinc-400 uppercase mb-4 tracking-widest">Recyclability</p>
                  <div className="flex items-center gap-3">
                    <span className="text-3xl font-black text-zinc-900">{result.impact.recyclabilityScore}</span>
                    <div className="flex-1 h-2 bg-zinc-200 rounded-full overflow-hidden">
                      <div className="h-full bg-emerald-500" style={{ width: `${result.impact.recyclabilityScore}%` }}></div>
                    </div>
                  </div>
               </div>
               <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
                  <p className="text-[10px] font-black text-zinc-400 uppercase mb-4 tracking-widest">Carbon Impact</p>
                  <p className="text-3xl font-black text-zinc-900">{result.impact.co2SavedKg}<span className="text-sm ml-1 opacity-40">kg</span></p>
               </div>
            </div>

            <div className="bg-red-50 rounded-[32px] p-8 border border-red-100/50">
               <p className="text-[10px] font-black text-red-700 uppercase tracking-widest mb-4">Toxic Material Detected</p>
               <div className="flex flex-wrap gap-2.5">
                 {result.impact.hazards.map((h, i) => (
                   <span key={i} className="px-4 py-2 bg-white text-red-600 rounded-2xl text-[11px] font-black border border-red-100 shadow-sm">{h}</span>
                 ))}
               </div>
            </div>

            <div className="flex gap-5 sticky bottom-0 bg-white pt-4 pb-2">
              <button 
                onClick={() => { setResult(null); setPreviewImage(null); startCamera(); }} 
                className="flex-1 py-6 bg-zinc-100 text-zinc-500 rounded-[28px] font-black text-xs uppercase tracking-[0.2em] active:scale-95 transition-all"
              >
                Retake
              </button>
              <button 
                onClick={handleSave} 
                className="flex-1 py-6 bg-emerald-600 text-white rounded-[28px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-emerald-200 active:scale-95 transition-all"
              >
                Accept Scan
              </button>
            </div>
          </div>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
      <style>{`
        @keyframes scan {
          0%, 100% { top: 0%; opacity: 0; }
          50% { top: 100%; opacity: 1; }
        }
      `}</style>
    </div>
  );
};

import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === "undefined") return null;
  return new GoogleGenAI({ apiKey });
};

export interface ClassificationResult {
  name: string;
  brand: string;
  model: string;
  category: string;
  estimatedPoints: number;
  description: string;
  impact: {
    co2SavedKg: number;
    materialsSaved: string[];
    hazards: string[];
    recyclabilityScore: number;
    metalRecovery: { element: string, percentage: number, marketValueUsd: number }[];
  };
  handlingSteps: string[];
}

export const classifyEWaste = async (base64Image: string): Promise<ClassificationResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("API Key not configured.");

  // Ensure we only send the raw base64 data, stripping any header prefix
  const base64Data = base64Image.includes('base64,') 
    ? base64Image.split('base64,')[1] 
    : base64Image;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Data
            }
          },
          {
            text: `Act as a Senior Environmental Materials Scientist. Analyze this electronic device for a Master's Thesis. 
            Identify the specific Brand and Model if possible.
            Provide a detailed JSON response including:
            1. Brand, Model, and technical name.
            2. Recyclability Score (0-100).
            3. Detailed Material Recovery: Estimate percentages of elements like Copper, Gold, Silver, and Aluminum and their approx scrap market value.
            4. Hazardous list: Specific chemicals (Lead, Cadmium, Mercury).
            5. Handling: Technical disposal protocol.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            brand: { type: Type.STRING },
            model: { type: Type.STRING },
            category: { type: Type.STRING },
            estimatedPoints: { type: Type.NUMBER },
            description: { type: Type.STRING },
            impact: {
              type: Type.OBJECT,
              properties: {
                co2SavedKg: { type: Type.NUMBER },
                materialsSaved: { type: Type.ARRAY, items: { type: Type.STRING } },
                hazards: { type: Type.ARRAY, items: { type: Type.STRING } },
                recyclabilityScore: { type: Type.NUMBER },
                metalRecovery: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      element: { type: Type.STRING },
                      percentage: { type: Type.NUMBER },
                      marketValueUsd: { type: Type.NUMBER }
                    },
                    required: ["element", "percentage", "marketValueUsd"]
                  }
                }
              },
              required: ["co2SavedKg", "materialsSaved", "hazards", "recyclabilityScore", "metalRecovery"]
            },
            handlingSteps: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["name", "brand", "model", "category", "estimatedPoints", "description", "impact", "handlingSteps"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No analysis received.");
    return JSON.parse(text.trim());
  } catch (error) {
    console.error("AI Analysis Error:", error);
    throw new Error("Analysis failed. Please try a clearer picture of the device.");
  }
};

export interface GroundingResult {
  text: string;
  links: { title: string; uri: string }[];
}

export const findRecyclingCenters = async (query: string, lat?: number, lng?: number): Promise<GroundingResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("API Key not configured.");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: `Find certified e-waste recycling centers for: ${query}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: (lat && lng) ? { latitude: lat, longitude: lng } : undefined
          }
        }
      },
    });

    const text = response.text || "No centers found nearby.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        title: c.maps.title || "View Location",
        uri: c.maps.uri
      }));

    return { text, links };
  } catch (error) {
    console.error("Grounding Error:", error);
    throw new Error("Search failed.");
  }
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraLive, setIsCameraLive] = useState(false);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      setError(null);
      setIsCameraLive(false);

      // Stop any existing tracks
      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      // Constraints for mobile: facing environment (back camera)
      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: { ideal: 'environment' },
          width: { ideal: 1280 },
          height: { ideal: 720 }
        },
        audio: false
      };

      // This call triggers the OS Permission Prompt
      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        videoRef.current.srcObject = s;
        // Native mobile browsers need an explicit play() call
        try {
          await videoRef.current.play();
          setIsCameraLive(true);
        } catch (playError) {
          console.warn("Autoplay blocked, user interaction required", playError);
          // If play() fails, it's usually an OS restriction that requires a click
        }
      }
    } catch (err: any) {
      console.error("Camera Hardware/Permission Error:", err);
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Camera access was denied. Please enable it in your phone settings.");
      } else {
        setError("Unable to access camera hardware. Please try again.");
      }
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraLive(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      console.error("AI Capture Error:", err);
      setError(err.message || "Failed to analyze device. Ensure the image is clear.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    // If the stream is not live yet, try to force play (user gesture)
    if (!isCameraLive) {
      try {
        await videoRef.current.play();
        setIsCameraLive(true);
        return; // Let user see the stream before capturing
      } catch (e) {
        startCamera();
        return;
      }
    }

    const canvas = canvasRef.current;
    const video = videoRef.current;

    // Match dimensions to the actual video feed for high resolution
    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');

    if (ctx) {
      ctx.drawImage(video, 0, 0);
      const base64 = canvas.toDataURL('image/jpeg', 0.9);
      await processImage(base64);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        brand: result.brand,
        model: result.model,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
        impact: result.impact,
        handlingSteps: result.handlingSteps
      });
      onClose();
    }
  };

  // Trigger camera on mount
  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col font-sans select-none overflow-hidden">
      {/* Header Bar */}
      <div className="p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/80 to-transparent z-50">
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full ${isCameraLive ? 'bg-emerald-500 shadow-[0_0_10px_#10b981] animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[11px] uppercase tracking-[0.4em]">AI Deep Scan</h2>
        </div>
        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center bg-white/10 backdrop-blur-xl rounded-full border border-white/10 active:scale-90 transition-all">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      {/* Camera Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center">
        {!previewImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              webkit-playsinline="true"
              onCanPlay={() => setIsCameraLive(true)}
              className={`w-full h-full object-cover transition-opacity duration-1000 ${isCameraLive ? 'opacity-100' : 'opacity-0'}`} 
            />

            {/* HUD Overlay */}
            {isCameraLive && (
              <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center">
                <div className="w-64 h-64 border-2 border-white/20 rounded-[40px] relative">
                  <div className="absolute -top-1 -left-1 w-10 h-10 border-t-4 border-l-4 border-emerald-500 rounded-tl-xl"></div>
                  <div className="absolute -top-1 -right-1 w-10 h-10 border-t-4 border-r-4 border-emerald-500 rounded-tr-xl"></div>
                  <div className="absolute -bottom-1 -left-1 w-10 h-10 border-b-4 border-l-4 border-emerald-500 rounded-bl-xl"></div>
                  <div className="absolute -bottom-1 -right-1 w-10 h-10 border-b-4 border-r-4 border-emerald-500 rounded-br-xl"></div>
                  <div className="absolute left-0 right-0 top-1/2 h-[1px] bg-emerald-500/40 animate-[scan_2.5s_infinite]"></div>
                </div>
                <p className="mt-6 text-white/50 text-[9px] font-black uppercase tracking-[0.3em]">Position product within frame</p>
              </div>
            )}

            {/* If camera is stuck, show manual start button (Autoplay bypass) */}
            {!isCameraLive && !error && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900 z-10 px-10 text-center">
                 <button 
                  onClick={startCamera}
                  className="w-20 h-20 bg-emerald-600 rounded-full flex items-center justify-center text-white shadow-2xl mb-6 active:scale-95 transition-transform"
                 >
                    <svg className="w-10 h-10 ml-1" fill="currentColor" viewBox="0 0 20 20"><path d="M4.516 7.548c0-.923.651-1.623 1.302-2.285l9.99-9.99c.66-.662 1.348-.309 1.348.651v19.992c0 .96-.688 1.313-1.348.651l-9.99-9.99c-.651-.662-1.302-1.362-1.302-2.285z"/></svg>
                 </button>
                 <h3 className="text-white font-black text-sm uppercase tracking-widest">Activate Camera</h3>
                 <p className="text-zinc-500 text-[10px] mt-2 leading-relaxed">Tap to grant permission and start the live analysis feed.</p>
              </div>
            )}
          </>
        ) : (
          <div className="w-full h-full p-8 bg-zinc-900 flex items-center justify-center">
            <img src={previewImage} className="max-w-full max-h-full rounded-[40px] shadow-2xl animate-in zoom-in-95 duration-700" />
          </div>
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-2xl flex flex-col items-center justify-center z-[60] p-10 text-center">
            <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-8"></div>
            <h3 className="text-white font-black text-2xl mb-2 tracking-tight">AI Analysis...</h3>
            <p className="text-emerald-400 text-[10px] font-black uppercase tracking-[0.3em]">Extracting material properties</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-8 top-1/2 -translate-y-1/2 bg-white rounded-[40px] p-10 text-center shadow-2xl z-50">
            <div className="w-16 h-16 bg-red-100 text-red-600 rounded-3xl flex items-center justify-center mx-auto mb-6">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            </div>
            <p className="text-zinc-900 font-bold mb-8 leading-relaxed text-sm">{error}</p>
            <div className="flex flex-col gap-3">
              <button 
                onClick={startCamera}
                className="w-full py-4 bg-zinc-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest"
              >
                Try Again
              </button>
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full py-4 bg-zinc-100 text-zinc-600 rounded-2xl font-black text-xs uppercase tracking-widest"
              >
                Upload from Gallery
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Control Panel */}
      <div className="bg-white rounded-t-[56px] p-10 pb-16 shadow-[0_-20px_60px_rgba(0,0,0,0.15)] z-50 overflow-y-auto max-h-[80vh]">
        {!result ? (
          <div className="flex flex-col items-center gap-10">
            <div className="text-center">
              <h4 className="text-zinc-900 font-black text-2xl tracking-tighter mb-1 uppercase">Material Discovery</h4>
              <p className="text-zinc-400 text-[10px] font-black uppercase tracking-[0.3em]">Point camera at electronic device</p>
            </div>

            <div className="flex items-center gap-10">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-16 h-16 bg-zinc-50 border-2 border-zinc-100 text-zinc-400 rounded-3xl flex items-center justify-center active:scale-90 transition-all shadow-sm"
               >
                 <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
               </button>

               <button 
                onClick={capture} 
                disabled={isScanning || (!isCameraLive && !error)} 
                className={`w-28 h-28 rounded-full p-2 transition-all shadow-2xl ${isCameraLive ? 'bg-emerald-600 ring-[12px] ring-emerald-50 active:scale-90' : 'bg-zinc-200 ring-[12px] ring-zinc-50 cursor-not-allowed'}`}
               >
                <div className="w-full h-full rounded-full border-4 border-white/20 flex items-center justify-center">
                  <div className="w-12 h-12 rounded-full bg-white shadow-lg"></div>
                </div>
               </button>

               <button 
                onClick={() => { stopCamera(); startCamera(); }}
                className="w-16 h-16 bg-zinc-50 border-2 border-zinc-100 text-zinc-400 rounded-3xl flex items-center justify-center active:scale-90 transition-all shadow-sm"
               >
                 <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
               </button>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload} 
            />
          </div>
        ) : (
          <div className="space-y-10 animate-in slide-in-from-bottom duration-700">
            <header className="flex justify-between items-start gap-4">
              <div className="flex-1 min-w-0">
                <span className="inline-block px-3 py-1 bg-emerald-50 text-emerald-700 text-[10px] font-black uppercase tracking-widest rounded-lg mb-3">{result.category}</span>
                <h3 className="text-3xl font-black text-zinc-900 leading-[1.1] truncate">{result.brand} {result.model}</h3>
                <p className="text-zinc-500 text-sm font-semibold mt-1">{result.name}</p>
              </div>
              <div className="bg-emerald-600 text-white px-6 py-5 rounded-[28px] text-center shadow-xl shadow-emerald-200">
                <p className="text-[10px] font-black uppercase opacity-60 mb-0.5">Value</p>
                <p className="text-2xl font-black">{result.estimatedPoints}</p>
              </div>
            </header>

            <div className="grid grid-cols-2 gap-5">
               <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
                  <p className="text-[10px] font-black text-zinc-400 uppercase mb-4 tracking-widest">Recyclability</p>
                  <div className="flex items-center gap-3">
                    <span className="text-3xl font-black text-zinc-900">{result.impact.recyclabilityScore}%</span>
                  </div>
               </div>
               <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
                  <p className="text-[10px] font-black text-zinc-400 uppercase mb-4 tracking-widest">CO2 Impact</p>
                  <p className="text-3xl font-black text-zinc-900">{result.impact.co2SavedKg}<span className="text-sm ml-1 opacity-40">kg</span></p>
               </div>
            </div>

            <div className="flex gap-5 sticky bottom-0 bg-white pt-4 pb-2">
              <button 
                onClick={() => { setResult(null); setPreviewImage(null); startCamera(); }} 
                className="flex-1 py-6 bg-zinc-100 text-zinc-500 rounded-[28px] font-black text-xs uppercase tracking-[0.2em]"
              >
                Retake
              </button>
              <button 
                onClick={handleSave} 
                className="flex-1 py-6 bg-emerald-600 text-white rounded-[28px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-emerald-200 active:scale-95 transition-all"
              >
                Save Item
              </button>
            </div>
          </div>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
      <style>{`
        @keyframes scan {
          0%, 100% { top: 0%; opacity: 0; }
          50% { top: 100%; opacity: 1; }
        }
      `}</style>
    </div>
  );
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraLive, setIsCameraLive] = useState(false);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      setError(null);
      setIsCameraLive(false);

      // 1. Check for Secure Context (Critical for Mobile)
      if (!window.isSecureContext && window.location.hostname !== 'localhost') {
        setError("Camera requires a secure connection (HTTPS). Please use HTTPS to access this feature on mobile.");
        return;
      }

      // 2. Check if MediaDevices is supported
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        setError("Your browser does not support camera access. Try Chrome or Safari.");
        return;
      }

      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: { ideal: 'environment' },
          width: { ideal: 1280 },
          height: { ideal: 720 }
        },
        audio: false
      };

      // Requesting permission
      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        videoRef.current.srcObject = s;
        // Mobile browsers require playsinline and often explicit play()
        try {
          await videoRef.current.play();
          setIsCameraLive(true);
        } catch (playError) {
          console.warn("Autoplay blocked, waiting for user interaction", playError);
          // Don't set error yet, let the user tap the manual start button
        }
      }
    } catch (err: any) {
      console.error("Camera Error:", err);
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Camera permission denied. Please allow camera access in your browser settings.");
      } else {
        setError(`Camera error: ${err.message || 'Hardware not available'}`);
      }
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraLive(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      console.error("AI Capture Error:", err);
      setError(err.message || "Failed to analyze device. Ensure lighting is good.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    // If the stream exists but isn't playing, try to play it (User Gesture)
    if (!isCameraLive && stream) {
      try {
        await videoRef.current.play();
        setIsCameraLive(true);
        return;
      } catch (e) {
        console.error("Manual play failed", e);
      }
    }

    const canvas = canvasRef.current;
    const video = videoRef.current;

    if (video.videoWidth === 0) return;

    canvas.width = video.videoWidth;
    canvas.height = video.videoHeight;
    const ctx = canvas.getContext('2d');

    if (ctx) {
      ctx.drawImage(video, 0, 0);
      const base64 = canvas.toDataURL('image/jpeg', 0.9);
      await processImage(base64);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        brand: result.brand,
        model: result.model,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
        impact: result.impact,
        handlingSteps: result.handlingSteps
      });
      onClose();
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col font-sans select-none overflow-hidden">
      {/* Header */}
      <div className="p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/80 to-transparent z-50">
        <div className="flex items-center gap-3">
          <div className={`w-2 h-2 rounded-full ${isCameraLive ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[10px] uppercase tracking-[0.4em]">Lens Terminal</h2>
        </div>
        <button onClick={onClose} className="w-10 h-10 flex items-center justify-center bg-white/10 backdrop-blur-md rounded-full">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      {/* Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center">
        {!previewImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              webkit-playsinline="true"
              onCanPlay={() => setIsCameraLive(true)}
              className={`w-full h-full object-cover transition-opacity duration-700 ${isCameraLive ? 'opacity-100' : 'opacity-30'}`} 
            />

            {/* Visual HUD */}
            {isCameraLive && (
              <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center">
                <div className="w-64 h-64 border border-white/10 rounded-[40px] relative">
                  <div className="absolute -top-1 -left-1 w-8 h-8 border-t-2 border-l-2 border-emerald-500 rounded-tl-xl"></div>
                  <div className="absolute -top-1 -right-1 w-8 h-8 border-t-2 border-r-2 border-emerald-500 rounded-tr-xl"></div>
                  <div className="absolute -bottom-1 -left-1 w-8 h-8 border-b-2 border-l-2 border-emerald-500 rounded-bl-xl"></div>
                  <div className="absolute -bottom-1 -right-1 w-8 h-8 border-b-2 border-r-2 border-emerald-500 rounded-br-xl"></div>
                  <div className="absolute left-0 right-0 top-1/2 h-0.5 bg-emerald-500/20 animate-[scan_3s_infinite]"></div>
                </div>
              </div>
            )}

            {/* Manual Activation if Autoplay is blocked */}
            {!isCameraLive && !error && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900/50 backdrop-blur-sm z-10 p-10 text-center">
                 <button 
                  onClick={startCamera}
                  className="w-20 h-20 bg-emerald-600 rounded-full flex items-center justify-center text-white shadow-2xl mb-6 active:scale-95"
                 >
                    <svg className="w-10 h-10 ml-1" fill="currentColor" viewBox="0 0 20 20"><path d="M4.516 7.548c0-.923.651-1.623 1.302-2.285l9.99-9.99c.66-.662 1.348-.309 1.348.651v19.992c0 .96-.688 1.313-1.348.651l-9.99-9.99c-.651-.662-1.302-1.362-1.302-2.285z"/></svg>
                 </button>
                 <h3 className="text-white font-black text-xs uppercase tracking-widest">Connect to Hardware</h3>
              </div>
            )}
          </>
        ) : (
          <div className="w-full h-full p-6 flex items-center justify-center bg-zinc-900">
            <img src={previewImage} className="max-w-full max-h-full rounded-3xl shadow-2xl animate-in zoom-in-95 duration-500" />
          </div>
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/80 backdrop-blur-xl flex flex-col items-center justify-center z-[60] p-10 text-center">
            <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-6"></div>
            <h3 className="text-white font-black text-xl mb-2">Analyzing...</h3>
            <p className="text-emerald-400 text-[10px] font-black uppercase tracking-widest">Identifying Materials</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-8 top-1/2 -translate-y-1/2 bg-white rounded-[32px] p-8 text-center shadow-2xl z-50">
            <div className="w-14 h-14 bg-red-100 text-red-600 rounded-2xl flex items-center justify-center mx-auto mb-4">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            </div>
            <p className="text-zinc-900 font-bold mb-8 text-sm leading-relaxed">{error}</p>
            <div className="flex flex-col gap-3">
              <button onClick={startCamera} className="w-full py-4 bg-zinc-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest">Retry Access</button>
              <button onClick={() => fileInputRef.current?.click()} className="w-full py-4 bg-zinc-100 text-zinc-600 rounded-2xl font-black text-xs uppercase tracking-widest">Use Gallery</button>
            </div>
          </div>
        )}
      </div>

      {/* Controls */}
      <div className="bg-white rounded-t-[48px] p-8 pb-12 shadow-[0_-20px_50px_rgba(0,0,0,0.1)] z-50">
        {!result ? (
          <div className="flex flex-col items-center gap-8">
            <div className="text-center">
              <h4 className="text-zinc-900 font-black text-xl mb-1 uppercase">Vision Discovery</h4>
              <p className="text-zinc-400 text-[9px] font-black uppercase tracking-widest">Detecting circuit components</p>
            </div>

            <div className="flex items-center gap-10">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-14 h-14 bg-zinc-50 border border-zinc-100 text-zinc-400 rounded-2xl flex items-center justify-center active:scale-90 transition-all"
               >
                 <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
               </button>

               <button 
                onClick={capture} 
                disabled={isScanning || (!isCameraLive && !error && !stream)} 
                className={`w-24 h-24 rounded-full p-2 transition-all shadow-xl ${isCameraLive || stream ? 'bg-emerald-600 ring-8 ring-emerald-50 active:scale-90' : 'bg-zinc-200 ring-8 ring-zinc-50 cursor-not-allowed'}`}
               >
                <div className="w-full h-full rounded-full border-4 border-white/20 flex items-center justify-center">
                  <div className="w-10 h-10 rounded-full bg-white"></div>
                </div>
               </button>

               <button 
                onClick={() => { stopCamera(); startCamera(); }}
                className="w-14 h-14 bg-zinc-50 border border-zinc-100 text-zinc-400 rounded-2xl flex items-center justify-center active:scale-90 transition-all"
               >
                 <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
               </button>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload} 
            />
          </div>
        ) : (
          <div className="space-y-6 animate-in slide-in-from-bottom duration-500">
            <header className="flex justify-between items-start gap-4">
              <div className="flex-1 min-w-0">
                <span className="inline-block px-2 py-0.5 bg-emerald-50 text-emerald-700 text-[9px] font-black uppercase tracking-widest rounded mb-2">{result.category}</span>
                <h3 className="text-2xl font-black text-zinc-900 leading-tight truncate">{result.brand} {result.model}</h3>
              </div>
              <div className="bg-emerald-600 text-white px-4 py-3 rounded-2xl text-center shadow-lg">
                <p className="text-[9px] font-black uppercase opacity-60">Value</p>
                <p className="text-lg font-black">{result.estimatedPoints}</p>
              </div>
            </header>

            <div className="flex gap-4">
              <button 
                onClick={() => { setResult(null); setPreviewImage(null); startCamera(); }} 
                className="flex-1 py-4 bg-zinc-100 text-zinc-500 rounded-2xl font-black text-xs uppercase tracking-widest"
              >
                Retake
              </button>
              <button 
                onClick={handleSave} 
                className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-emerald-200"
              >
                Save Analysis
              </button>
            </div>
          </div>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
      <style>{`
        @keyframes scan {
          0%, 100% { top: 0%; opacity: 0; }
          50% { top: 100%; opacity: 1; }
        }
      `}</style>
    </div>
  );
};

