import React, { useRef, useState, useCallback, useEffect } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraLive, setIsCameraLive] = useState(false);
  const [hasRequestedPermission, setHasRequestedPermission] = useState(false);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      setError(null);
      setIsCameraLive(false);
      setHasRequestedPermission(true);

      // Check for secure context - Mandatory for mobile camera
      if (!window.isSecureContext && window.location.hostname !== 'localhost') {
        setError("Camera requires HTTPS. Please access the app via a secure connection.");
        return;
      }

      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: { ideal: 'environment' },
          width: { ideal: 1280 },
          height: { ideal: 720 }
        },
        audio: false
      };

      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        videoRef.current.srcObject = s;
        // iOS Safari requires these attributes to be set via setAttribute
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.setAttribute('webkit-playsinline', 'true');
        videoRef.current.muted = true;

        try {
          await videoRef.current.play();
          setIsCameraLive(true);
        } catch (playError) {
          console.warn("Autoplay blocked:", playError);
          // If play() fails, it's usually a user interaction requirement
        }
      }
    } catch (err: any) {
      console.error("Camera Hardware Error:", err);
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Permission denied. Please allow camera access in your phone settings.");
      } else {
        setError(`Camera error: ${err.message || 'Device not found'}`);
      }
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraLive(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      console.error("AI Analysis Error:", err);
      setError(err.message || "Failed to identify device. Ensure lighting is clear.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    // If stream is ready but not playing, try to play (satisfies user gesture)
    if (!isCameraLive && stream) {
      try {
        await videoRef.current.play();
        setIsCameraLive(true);
        return;
      } catch (e) {
        console.error("Manual start failed", e);
      }
    }

    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (video.videoWidth === 0) return;

    // Mobile-Safe Downscaling: Max width of 800px to prevent memory crashes
    const MAX_WIDTH = 800;
    const scale = Math.min(1, MAX_WIDTH / video.videoWidth);
    canvas.width = video.videoWidth * scale;
    canvas.height = video.videoHeight * scale;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
      // Use lower quality (0.7) for faster upload and memory safety
      const base64 = canvas.toDataURL('image/jpeg', 0.7);

      if (!base64 || base64.length < 1000) {
