          <h2 className="font-black text-[10px] uppercase tracking-[0.4em]">AI Lens</h2>
        </div>
        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center bg-white/10 backdrop-blur-md rounded-full active:scale-90 transition-all">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      {/* Viewport Area */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center">
        {!previewImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              className={`w-full h-full object-cover transition-opacity duration-700 ${isCameraLive ? 'opacity-100' : 'opacity-0'}`} 
            />

            {/* Permission / Start Prompt */}
            {!isCameraLive && !error && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900 z-10 p-10 text-center animate-in fade-in duration-500">
                 <div className="w-20 h-20 bg-emerald-600/20 text-emerald-500 rounded-full flex items-center justify-center mb-8">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                 </div>
                 <h3 className="text-white font-black text-xl mb-4">Grant Camera Access</h3>
                 <p className="text-zinc-500 text-sm mb-8 leading-relaxed">We need your camera to identify materials and calculate recyclability points.</p>
