    } catch (err: any) {
      console.error("AI Analysis Error:", err);
      setError(err.message || "Failed to identify device. Check connection and lighting.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    if (!videoRef.current || !canvasRef.current) return;

    // User gesture bypass if autoplay was blocked
    if (!isCameraLive && stream) {
      try {
        await videoRef.current.play();
        setIsCameraLive(true);
        return;
      } catch (e) {
        console.error("Manual start failure", e);
      }
    }

    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (video.videoWidth === 0) return;

    // FIX: Force mobile-safe resolution to prevent memory crashes
    const MAX_WIDTH = 640;
    const scale = MAX_WIDTH / video.videoWidth;
    canvas.width = MAX_WIDTH;
    canvas.height = video.videoHeight * scale;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, canvas.width, canvas.height);

      // FIX: Lower quality (0.6) for mobile memory stability
      const base64 = canvas.toDataURL('image/jpeg', 0.6);

      if (!base64 || base64.length < 1000) {
        setError("Mobile capture failed. Please use the gallery upload option.");
        return;
      }

      await processImage(base64);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        brand: result.brand,
        model: result.model,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
        impact: result.impact,
        handlingSteps: result.handlingSteps
      });
      onClose();
    }
  };

  useEffect(() => {
    // IMPORTANT: No auto-start in useEffect to comply with iOS security
    return () => stopCamera();
  }, [stopCamera]);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col font-sans select-none overflow-hidden">
      {/* Dynamic Header */}
      <div className="p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/80 to-transparent z-50">
        <div className="flex items-center gap-3">
          <div className={`w-2 h-2 rounded-full ${isCameraLive ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[10px] uppercase tracking-[0.4em]">AI Visual Scanner</h2>
        </div>
        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center bg-white/10 backdrop-blur-md rounded-full active:scale-90 transition-all">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      {/* Main Viewport */}
      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center">
        {!previewImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              className={`w-full h-full object-cover transition-opacity duration-700 ${isCameraLive ? 'opacity-100' : 'opacity-0'}`} 
            />

            {/* User Interaction Guard */}
            {!isCameraLive && !error && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-900 z-10 p-10 text-center animate-in fade-in duration-500">
                 <div className="w-20 h-20 bg-emerald-600/10 text-emerald-500 rounded-3xl flex items-center justify-center mb-10 shadow-inner">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                 </div>
                 <h3 className="text-white font-black text-2xl mb-4 tracking-tight">Camera Required</h3>
                 <p className="text-zinc-500 text-sm mb-10 leading-relaxed max-w-[240px]">Tap the button below to grant permission and activate the AI Lens.</p>
                 <button 
                  onClick={startCamera}
                  className="px-10 py-5 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl shadow-emerald-600/30 active:scale-95 transition-all"
                 >
                    {hasRequestedPermission ? 'Retry Access' : 'Connect to Camera'}
                 </button>
              </div>
            )}

            {/* Visual Scan HUD */}
            {isCameraLive && (
              <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center">
                <div className="w-64 h-64 border border-white/10 rounded-[48px] relative">
                  <div className="absolute -top-1 -left-1 w-12 h-12 border-t-4 border-l-4 border-emerald-500 rounded-tl-2xl"></div>
                  <div className="absolute -top-1 -right-1 w-12 h-12 border-t-4 border-r-4 border-emerald-500 rounded-tr-2xl"></div>
                  <div className="absolute -bottom-1 -left-1 w-12 h-12 border-b-4 border-l-4 border-emerald-500 rounded-bl-2xl"></div>
                  <div className="absolute -bottom-1 -right-1 w-12 h-12 border-b-4 border-r-4 border-emerald-500 rounded-br-2xl"></div>
                  <div className="absolute left-0 right-0 top-1/2 h-0.5 bg-emerald-500/40 animate-[scan_2.5s_infinite]"></div>
                </div>
                <p className="mt-10 text-white/40 text-[10px] font-black uppercase tracking-[0.4em]">Ready for Analysis</p>
              </div>
            )}
          </>
        ) : (
          <div className="w-full h-full p-8 flex items-center justify-center bg-zinc-900">
            <img src={previewImage} className="max-w-full max-h-full rounded-[40px] shadow-2xl animate-in zoom-in-95 duration-500 border border-white/5" />
          </div>
        )}

        {/* Global States */}
        {isScanning && (
          <div className="absolute inset-0 bg-black/90 backdrop-blur-3xl flex flex-col items-center justify-center z-[60] p-10 text-center">
            <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-8 shadow-inner shadow-emerald-500/20"></div>
            <h3 className="text-white font-black text-2xl mb-3 tracking-tight">AI Identification</h3>
            <p className="text-emerald-400 text-[10px] font-black uppercase tracking-[0.3em]">Extracting technical specs</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-8 top-1/2 -translate-y-1/2 bg-white rounded-[40px] p-10 text-center shadow-2xl z-50 animate-in slide-in-from-bottom-10 duration-500">
            <div className="w-16 h-16 bg-red-100 text-red-600 rounded-3xl flex items-center justify-center mx-auto mb-6">
              <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            </div>
            <p className="text-zinc-900 font-bold mb-8 text-sm leading-relaxed">{error}</p>
            <div className="flex flex-col gap-3">
              <button onClick={startCamera} className="w-full py-4 bg-zinc-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all">Try Access Again</button>
              <button onClick={() => fileInputRef.current?.click()} className="w-full py-4 bg-zinc-100 text-zinc-600 rounded-2xl font-black text-xs uppercase tracking-widest">Select From Photos</button>
            </div>
          </div>
        )}
      </div>

      {/* Control Panel */}
      <div className="bg-white rounded-t-[56px] p-10 pb-16 shadow-[0_-20px_60px_rgba(0,0,0,0.15)] z-50">
        {!result ? (
          <div className="flex flex-col items-center gap-10">
            <div className="text-center">
              <h4 className="text-zinc-900 font-black text-2xl tracking-tighter mb-1 uppercase">Object Analysis</h4>
              <p className="text-zinc-400 text-[10px] font-black uppercase tracking-widest leading-none">Detection Active</p>
            </div>

            <div className="flex items-center gap-10">
               <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-16 h-16 bg-zinc-50 border-2 border-zinc-100 text-zinc-400 rounded-3xl flex items-center justify-center active:scale-90 transition-all shadow-sm"
               >
                 <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
               </button>

               <button 
                onClick={capture} 
                disabled={isScanning || (!isCameraLive && !error)} 
                className={`w-28 h-28 rounded-full p-2 transition-all shadow-2xl ${isCameraLive ? 'bg-emerald-600 ring-[14px] ring-emerald-50 active:scale-90' : 'bg-zinc-200 ring-[14px] ring-zinc-50 cursor-not-allowed'}`}
               >
                <div className="w-full h-full rounded-full border-4 border-white/20 flex items-center justify-center">
                  <div className="w-12 h-12 rounded-full bg-white shadow-xl"></div>
                </div>
               </button>

               <button 
                onClick={() => { stopCamera(); startCamera(); }}
                className="w-16 h-16 bg-zinc-50 border-2 border-zinc-100 text-zinc-400 rounded-3xl flex items-center justify-center active:scale-90 transition-all shadow-sm"
               >
                 <svg className="w-7 h-7" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg>
               </button>
            </div>

            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="image/*" 
              onChange={handleFileUpload} 
            />
          </div>
        ) : (
          <div className="space-y-10 animate-in slide-in-from-bottom-10 duration-700">
            <header className="flex justify-between items-start gap-4">
              <div className="flex-1 min-w-0">
                <span className="inline-block px-3 py-1 bg-emerald-50 text-emerald-700 text-[10px] font-black uppercase tracking-widest rounded-lg mb-3">{result.category}</span>
                <h3 className="text-3xl font-black text-zinc-900 leading-[1.1] truncate tracking-tight">{result.brand} {result.model}</h3>
                <p className="text-zinc-500 text-sm font-semibold mt-1">{result.name}</p>
              </div>
              <div className="bg-emerald-600 text-white px-6 py-5 rounded-[28px] text-center shadow-2xl shadow-emerald-600/20">
                <p className="text-[10px] font-black uppercase opacity-60 mb-0.5 tracking-widest">Points</p>
                <p className="text-2xl font-black">{result.estimatedPoints}</p>
              </div>
            </header>

            <div className="grid grid-cols-2 gap-5">
               <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
                  <p className="text-[10px] font-black text-zinc-400 uppercase mb-4 tracking-[0.2em]">Efficiency</p>
                  <div className="flex items-center gap-3">
                    <span className="text-3xl font-black text-zinc-900">{result.impact.recyclabilityScore}%</span>
                  </div>
               </div>
               <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
                  <p className="text-[10px] font-black text-zinc-400 uppercase mb-4 tracking-[0.2em]">CO2 Offset</p>
                  <p className="text-3xl font-black text-zinc-900">{result.impact.co2SavedKg}<span className="text-sm ml-1 opacity-40">kg</span></p>
               </div>
            </div>

            <div className="flex gap-5 sticky bottom-0 bg-white pt-4 pb-2">
              <button 
                onClick={() => { setResult(null); setPreviewImage(null); startCamera(); }} 
                className="flex-1 py-6 bg-zinc-100 text-zinc-500 rounded-[28px] font-black text-xs uppercase tracking-[0.2em] active:scale-95 transition-all"
              >
                Clear
              </button>
              <button 
                onClick={handleSave} 
                className="flex-1 py-6 bg-emerald-600 text-white rounded-[28px] font-black text-xs uppercase tracking-[0.2em] shadow-2xl shadow-emerald-600/30 active:scale-95 transition-all"
              >
                Log Device
              </button>
            </div>
          </div>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
      <style>{`
        @keyframes scan {
          0%, 100% { top: 0%; opacity: 0; }
          50% { top: 100%; opacity: 1; }
        }
      `}</style>
    </div>
  );
};

import React, { Suspense } from 'react';
import { AppProvider, useApp } from './store';
import { Role } from './types';
import { UserDashboard, CollectorDashboard, AdminDashboard } from './components/Dashboards';
import { Auth } from './components/Auth';

const ConfigCheck: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const apiKey = process.env.API_KEY;
  const isKeyMissing = !apiKey || apiKey === "undefined" || apiKey === "";

  if (isKeyMissing) {
    return (
      <div className="min-h-screen bg-zinc-950 flex items-center justify-center p-8 text-center animate-in fade-in duration-700">
        <div className="max-w-xs space-y-6">
          <div className="w-20 h-20 bg-red-500/20 text-red-500 rounded-3xl mx-auto flex items-center justify-center shadow-2xl shadow-red-500/10 border border-red-500/30">
            <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
          </div>
          <h2 className="text-white text-2xl font-black tracking-tight">System Halted</h2>
          <p className="text-zinc-400 text-sm leading-relaxed">
            The <span className="text-emerald-400 font-mono">Gemini API Key</span> is required for AI-powered e-waste classification.
          </p>
          <div className="bg-zinc-900 p-4 rounded-2xl text-[10px] text-zinc-300 border border-zinc-800 text-left overflow-x-auto font-mono">
            VITE_GEMINI_API_KEY=your_key
          </div>
          <button 
            onClick={() => window.location.reload()}
            className="w-full py-4 bg-white text-black font-black rounded-2xl active:scale-95 transition-all shadow-xl shadow-white/5"
          >
            Check Configuration
          </button>
        </div>
      </div>
    );
  }

  return <children>{children}</children>;
};

const AppContent: React.FC = () => {
  const { currentUser, logout } = useApp();

  if (!currentUser) {
    return <Auth />;
  }

  const renderDashboard = () => {
    switch (currentUser.role) {
      case Role.USER: return <UserDashboard />;
      case Role.COLLECTOR: return <CollectorDashboard />;
      case Role.ADMIN: return <AdminDashboard />;
      default: return <div className="p-10 text-center font-black">Access Denied</div>;
    }
  };

  const getThemeColor = () => {
    switch (currentUser.role) {
      case Role.USER: return 'bg-emerald-600';
      case Role.COLLECTOR: return 'bg-indigo-700';
      case Role.ADMIN: return 'bg-zinc-900';
      default: return 'bg-emerald-600';
    }
  };

  return (
    <div className="max-w-md mx-auto min-h-screen flex flex-col relative bg-zinc-50 shadow-2xl overflow-hidden font-sans selection:bg-emerald-100 selection:text-emerald-900">
      <header className={`px-6 pt-[env(safe-area-inset-top)] h-24 bg-white/80 backdrop-blur-lg flex justify-between items-center sticky top-0 z-[60] border-b border-zinc-100 transition-all duration-700`}>
        <div className="flex items-center gap-4">
          <div className={`w-12 h-12 ${getThemeColor()} rounded-[14px] flex items-center justify-center text-white font-black text-2xl shadow-xl shadow-opacity-20 transition-all duration-700 rotate-[-4deg]`}>
            R
          </div>
          <div>
            <h1 className="text-xl font-black text-zinc-900 leading-none tracking-tighter flex items-baseline gap-1">
              Redo <span className="text-xs font-bold opacity-60 tracking-normal">Pro</span>
            </h1>
            <p className="text-[9px] text-zinc-400 font-black uppercase tracking-[0.2em] mt-1">{currentUser.role} TERMINAL</p>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <button 
             onClick={logout}
             className="w-12 h-12 bg-zinc-100 rounded-[14px] flex items-center justify-center text-zinc-500 hover:bg-red-50 hover:text-red-500 transition-all active:scale-90"
             title="Sign Out"
           >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
           </button>
           <div className="w-12 h-12 p-0.5 rounded-[14px] border-2 border-zinc-100 overflow-hidden shadow-sm">
             <img src={`https://api.dicebear.com/7.x/shapes/svg?seed=${currentUser.email}`} className="w-full h-full object-cover bg-zinc-50" alt="Avatar" />
           </div>
        </div>
      </header>

      <main className="flex-1 p-6 relative">
        <Suspense fallback={<div className="flex items-center justify-center h-full"><div className="w-8 h-8 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div></div>}>
          {renderDashboard()}
        </Suspense>
      </main>

      {/* Mobile Home Indicator Spacing */}
      <div className="h-[env(safe-area-inset-bottom)] bg-white"></div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <ConfigCheck>
      <AppProvider>
        <AppContent />
      </AppProvider>
    </ConfigCheck>
  );
};

export default App;

import React, { useState } from 'react';
import { useApp } from '../store';
import { Role } from '../types';

export const Auth: React.FC = () => {
  const [isLogin, setIsLogin] = useState(true);
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');
  const [role, setRole] = useState<Role>(Role.USER);
