        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-zinc-400 uppercase tracking-widest mb-2 ml-1">Full Name</label>
              <input
                type="text"
