              value={email}
              onChange={e => setEmail(e.target.value)}
            />
          </div>

          {!isLogin && (
            <div>
              <label className="block text-xs font-bold text-zinc-400 uppercase tracking-widest mb-2 ml-1">Account Role</label>
              <select
                className="w-full px-5 py-4 bg-zinc-50 border border-zinc-100 rounded-2xl focus:ring-2 focus:ring-emerald-500 outline-none transition-all font-medium appearance-none"
                value={role}
                onChange={e => setRole(e.target.value as Role)}
              >
                <option value={Role.USER}>Consumer / User</option>
                <option value={Role.COLLECTOR}>Logistics / Collector</option>
                <option value={Role.ADMIN}>System Administrator</option>
              </select>
            </div>
          )}

          {error && (
            <div className="p-4 bg-red-50 text-red-500 text-sm font-bold rounded-2xl flex items-center gap-2">
              <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" /></svg>
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={isLoading}
            className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-bold text-lg shadow-lg shadow-emerald-100 hover:bg-emerald-700 transition-all flex items-center justify-center gap-2"
          >
            {isLoading ? (
              <div className="w-6 h-6 border-3 border-white/30 border-t-white rounded-full animate-spin"></div>
