import React, { useRef, useState, useCallback, useEffect } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraLive, setIsCameraLive] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);
  const [hasRequestedPermission, setHasRequestedPermission] = useState(false);
  const { addItem } = useApp();

  // Enhanced iOS detection including modern iPads
  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || 
                (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);

  const startCamera = async () => {
    try {
      setError(null);
      setIsCameraLive(false);
      setIsInitializing(true);
      setHasRequestedPermission(true);

      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Your browser doesn't support camera access. Try using Chrome or Safari.");
      }

      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: { ideal: 'environment' },
          width: isIOS ? { ideal: 1080 } : { ideal: 1920 },
          height: isIOS ? { ideal: 1920 } : { ideal: 1080 }
        },
        audio: false
      };

      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        const video = videoRef.current;
        video.srcObject = s;

        // Critical for iOS Safari
        video.setAttribute('playsinline', 'true');
        video.setAttribute('webkit-playsinline', 'true');
        video.muted = true;
        video.autoplay = true;

        // Use event to trigger live state rather than just play promise
        video.onloadedmetadata = () => {
          video.play().then(() => {
            setIsCameraLive(true);
            setIsInitializing(false);
          }).catch(e => {
            console.warn("Autoplay blocked, waiting for interaction", e);
            setIsInitializing(false);
          });
        };
      }
    } catch (err: any) {
      console.error("Camera Initialization Error:", err);
      setIsInitializing(false);
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        setError("Camera permission denied. Please allow camera access in your browser or phone settings.");
      } else {
        setError(`Camera error: ${err.message || 'Check your device hardware'}`);
      }
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraLive(false);
    setIsInitializing(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      console.error("AI Analysis Error:", err);
      setError(err.message || "Could not identify this object. Try a clearer angle with better lighting.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || video.readyState < 2) {
      setError("Camera is not ready yet. Please wait a moment.");
      return;
    }

    // Ensure video is playing
    if (video.paused) {
      try {
        await video.play();
      } catch (e) {
        setError("Camera is paused. Tap 'Retry Access'.");
        return;
      }
    }

    if (video.videoWidth === 0 || video.videoHeight === 0) {
      setError("Waiting for valid camera stream...");
      return;
    }

    // Force safe processing resolution to avoid mobile memory crashes
    const MAX_DIMENSION = 800;
    let width = video.videoWidth;
    let height = video.videoHeight;

    if (width > height) {
      if (width > MAX_DIMENSION) {
        height *= MAX_DIMENSION / width;
        width = MAX_DIMENSION;
      }
    } else {
      if (height > MAX_DIMENSION) {
        width *= MAX_DIMENSION / height;
        height = MAX_DIMENSION;
      }
    }

    canvas.width = width;
    canvas.height = height;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, width, height);

      // JPEG quality 0.7 balances clarity with string length for mobile
      const base64 = canvas.toDataURL('image/jpeg', 0.7);

      if (!base64 || base64.length < 500) {
        setError("Capture failed. Try picking an image from your gallery instead.");
        return;
      }

      await processImage(base64);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        processImage(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (result && previewImage) {
      addItem({
        name: result.name,
        brand: result.brand,
        model: result.model,
        category: result.category,
        description: result.description,
        estimatedPoints: result.estimatedPoints,
        imageUrl: previewImage,
        impact: result.impact,
        handlingSteps: result.handlingSteps
      });
      onClose();
    }
  };

  useEffect(() => {
    return () => stopCamera();
  }, [stopCamera]);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col font-sans select-none overflow-hidden animate-in fade-in duration-300">
      {/* Header Overlay */}
      <div className="absolute top-0 inset-x-0 p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/80 to-transparent z-[110]">
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full shadow-[0_0_10px_rgba(16,185,129,0.5)] ${isCameraLive ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[10px] uppercase tracking-[0.4em] drop-shadow-md">AI Visual Engine</h2>
        </div>
        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center bg-white/10 backdrop-blur-md rounded-2xl active:scale-90 transition-all border border-white/10">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
