import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === "undefined") return null;
  return new GoogleGenAI({ apiKey });
};

export interface ClassificationResult {
  name: string;
  brand: string;
  model: string;
  category: string;
  estimatedPoints: number;
  description: string;
  impact: {
    co2SavedKg: number;
    materialsSaved: string[];
    hazards: string[];
    recyclabilityScore: number;
    metalRecovery: { element: string, percentage: number, marketValueUsd: number }[];
  };
  handlingSteps: string[];
}

export const classifyEWaste = async (base64Image: string): Promise<ClassificationResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("AI Engine not initialized. Please check API settings.");

  const base64Data = base64Image.includes('base64,') 
    ? base64Image.split('base64,')[1] 
    : base64Image;

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: 'image/jpeg',
              data: base64Data
            }
          },
          {
            text: `Technical Analysis Request:
            Object: E-Waste device.
            Tasks:
            1. Identify precise Brand and Model.
            2. Assign technical category (e.g., Personal Audio, Mobile Computing, Power Management).
            3. Calculate environmental impact metrics based on standard lifecycle assessments.
            4. Provide recovery statistics for precious and industrial metals.
            5. Outline hazardous chemical composition (Lead, Mercury, etc.).
            6. Generate safe handling and disassembly steps.

            Format: Strict JSON as defined by the provided schema.`
          }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            brand: { type: Type.STRING },
            model: { type: Type.STRING },
            category: { type: Type.STRING },
            estimatedPoints: { type: Type.NUMBER, description: "Recycling credit value based on scarcity (10-1000)" },
            description: { type: Type.STRING },
            impact: {
              type: Type.OBJECT,
              properties: {
                co2SavedKg: { type: Type.NUMBER },
                materialsSaved: { type: Type.ARRAY, items: { type: Type.STRING } },
                hazards: { type: Type.ARRAY, items: { type: Type.STRING } },
                recyclabilityScore: { type: Type.NUMBER },
                metalRecovery: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      element: { type: Type.STRING },
                      percentage: { type: Type.NUMBER },
                      marketValueUsd: { type: Type.NUMBER }
                    },
                    required: ["element", "percentage", "marketValueUsd"]
                  }
                }
              },
              required: ["co2SavedKg", "materialsSaved", "hazards", "recyclabilityScore", "metalRecovery"]
            },
            handlingSteps: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["name", "brand", "model", "category", "estimatedPoints", "description", "impact", "handlingSteps"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("AI engine failed to produce metadata.");
    return JSON.parse(text.trim());
  } catch (error: any) {
    console.error("AI Analysis Error:", error);
    throw new Error(error.message || "Identification engine timed out. Try again with a closer shot.");
  }
};

export interface GroundingResult {
  text: string;
  links: { title: string; uri: string }[];
}

export const findRecyclingCenters = async (query: string, lat?: number, lng?: number): Promise<GroundingResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("Search engine not available.");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-lite-latest",
      contents: `Search for official and certified e-waste recycling centers for: ${query}. Location bias: ${lat},${lng}`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: (lat && lng) ? { latitude: lat, longitude: lng } : undefined
          }
        }
      },
    });

    const text = response.text || "No certified centers found in the immediate vicinity.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks
      .filter((c: any) => c.maps)
      .map((c: any) => ({
        title: c.maps.title || "Facility Details",
        uri: c.maps.uri
      }));

    return { text, links };
  } catch (error) {
    console.error("Grounding Error:", error);
    throw new Error("Local mapping service unavailable.");
  }
};

import React, { useRef, useState, useCallback, useEffect } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraLive, setIsCameraLive] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);
  const { addItem } = useApp();

  const isIOS = /iPad|iPhone|iPod/.test(navigator.userAgent) || 
                (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);

  const startCamera = async () => {
    try {
      setError(null);
      setIsCameraLive(false);
      setIsInitializing(true);

      if (!navigator.mediaDevices?.getUserMedia) {
        throw new Error("Camera API not found. Please use a modern mobile browser.");
      }

      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: { ideal: 'environment' },
          width: { ideal: 1280 },
          height: { ideal: 720 }
        },
        audio: false
      };

      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        const video = videoRef.current;
        video.srcObject = s;

        // Mobile specific attributes
        video.setAttribute('playsinline', 'true');
        video.setAttribute('webkit-playsinline', 'true');
        video.muted = true;
        video.autoplay = true;

        video.onloadedmetadata = async () => {
          try {
            await video.play();
            setIsCameraLive(true);
            setIsInitializing(false);
          } catch (e) {
            console.error("Video play failed:", e);
            setError("Tap the screen to enable camera feed.");
            setIsInitializing(false);
          }
        };
      }
    } catch (err: any) {
      console.error("Camera Hardware Error:", err);
      setIsInitializing(false);
      setError(err.name === 'NotAllowedError' ? "Camera access denied. Enable permissions in settings." : err.message);
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraLive(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "Identification failed. Check your connection.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || video.readyState < 2) return;

    const MAX_SIZE = 800;
    let w = video.videoWidth;
    let h = video.videoHeight;

    if (w > h) {
      if (w > MAX_SIZE) { h *= MAX_SIZE / w; w = MAX_SIZE; }
    } else {
      if (h > MAX_SIZE) { w *= MAX_SIZE / h; h = MAX_SIZE; }
    }

    canvas.width = w;
    canvas.height = h;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, w, h);
      const base64 = canvas.toDataURL('image/jpeg', 0.8);
      await processImage(base64);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[100] flex flex-col font-sans select-none overflow-hidden animate-in fade-in duration-300">
      <div className="absolute top-0 inset-x-0 p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/80 to-transparent z-[110]">
        <div className="flex items-center gap-3">
          <div className={`w-2 h-2 rounded-full ${isCameraLive ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[9px] uppercase tracking-[0.4em]">AI Optical Core</h2>
        </div>
        <button onClick={onClose} className="w-10 h-10 flex items-center justify-center bg-white/10 backdrop-blur-md rounded-xl active:scale-90 transition-all">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center">
        {!previewImage ? (
          <>
            <video ref={videoRef} autoPlay playsInline muted className={`w-full h-full object-cover transition-opacity duration-700 ${isCameraLive ? 'opacity-100' : 'opacity-0'}`} />

            {isInitializing && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950 z-10">
                <div className="w-12 h-12 border-4 border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin mb-4"></div>
                <p className="text-emerald-500 text-[9px] font-black uppercase tracking-widest">Warming Up...</p>
              </div>
            )}

            {isCameraLive && (
              <div className="absolute inset-0 pointer-events-none flex flex-col items-center justify-center">
                <div className="w-64 h-64 border border-white/20 rounded-[48px] relative">
                  <div className="absolute -top-1 -left-1 w-10 h-10 border-t-4 border-l-4 border-emerald-500 rounded-tl-2xl"></div>
                  <div className="absolute -top-1 -right-1 w-10 h-10 border-t-4 border-r-4 border-emerald-500 rounded-tr-2xl"></div>
                  <div className="absolute -bottom-1 -left-1 w-10 h-10 border-b-4 border-l-4 border-emerald-500 rounded-bl-2xl"></div>
                  <div className="absolute -bottom-1 -right-1 w-10 h-10 border-b-4 border-r-4 border-emerald-500 rounded-br-2xl"></div>
                </div>
              </div>
            )}
          </>
        ) : (
          <img src={previewImage} className="max-w-full max-h-[70vh] rounded-[40px] shadow-2xl border border-white/10 animate-in zoom-in-95 duration-500" alt="Device" />
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/90 backdrop-blur-xl flex flex-col items-center justify-center z-[120]">
            <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-6"></div>
            <h3 className="text-white font-black text-xl mb-2 tracking-tight">AI Identification</h3>
            <p className="text-emerald-400 text-[8px] font-black uppercase tracking-widest animate-pulse">Analyzing Circuitry</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-8 top-1/2 -translate-y-1/2 bg-white rounded-[40px] p-8 text-center shadow-2xl z-[130]">
            <p className="text-zinc-900 font-bold mb-6">{error}</p>
            <button onClick={startCamera} className="w-full py-4 bg-zinc-900 text-white rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all">Retry Camera</button>
          </div>
        )}
      </div>

      <div className="bg-white rounded-t-[48px] p-8 pb-[env(safe-area-inset-bottom,24px)] shadow-[0_-20px_40px_rgba(0,0,0,0.1)] z-[110]">
        {!result ? (
          <div className="flex flex-col items-center gap-8">
            <div className="flex items-center gap-10">
               <button onClick={() => fileInputRef.current?.click()} className="w-14 h-14 bg-zinc-50 border border-zinc-100 text-zinc-400 rounded-2xl flex items-center justify-center active:scale-90 transition-all">
