declare var L: any; // Leaflet global

const M3Chip = ({ status }: { status: string }) => {
    const colors: Record<string, string> = {
        [ItemStatus.STORED]: 'bg-blue-100 text-blue-800 border-blue-200',
        [ItemStatus.PICKUP_REQUESTED]: 'bg-amber-100 text-amber-800 border-amber-200',
        [ItemStatus.IN_PROGRESS]: 'bg-indigo-100 text-indigo-800 border-indigo-200',
        [ItemStatus.COMPLETED]: 'bg-emerald-100 text-emerald-800 border-emerald-200',
        [PickupStatus.PENDING]: 'bg-zinc-100 text-zinc-800 border-zinc-200',
    };
    return (
        <span className={`px-3 py-1 rounded-lg text-[10px] font-bold uppercase border ${colors[status] || 'bg-zinc-100'}`}>
            {status.replace('_', ' ')}
        </span>
    );
}

const M3Card: React.FC<{ children: React.ReactNode; className?: string; onClick?: () => void }> = ({ children, className = "", onClick }) => (
  <div 
    onClick={onClick}
    className={`bg-white rounded-[28px] p-5 shadow-sm border border-zinc-100/50 ${className} ${onClick ? 'cursor-pointer active:scale-95 transition-all' : ''}`}
  >
    {children}
  </div>
);

const LogisticsMap: React.FC<{ 
    pickup: PickupRequest; 
    onClose: () => void;
    onComplete: () => void;
}> = ({ pickup, onClose, onComplete }) => {
    const mapRef = useRef<any>(null);
    const [collectorPos, setCollectorPos] = useState<{lat: number, lng: number} | null>(null);
    const [route, setRoute] = useState<EcoRouteResult | null>(null);
    const [loading, setLoading] = useState(true);

    const targetPos = pickup.location.coords || { lat: 37.7749, lng: -122.4194 }; // Default to SF if missing

    useEffect(() => {
        // Start GPS tracking
        const watchId = navigator.geolocation.watchPosition(
            (pos) => setCollectorPos({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
            () => setCollectorPos({ lat: targetPos.lat - 0.01, lng: targetPos.lng - 0.01 }), // Simulation offset
            { enableHighAccuracy: true }
        );

        return () => navigator.geolocation.clearWatch(watchId);
    }, []);

    useEffect(() => {
        if (!collectorPos) return;

        const initMapAndRoute = async () => {
            try {
                const data = await getEcoFriendlyRoute(collectorPos, targetPos);
                setRoute(data);

                if (!mapRef.current) {
                    mapRef.current = L.map('logistics-map', { zoomControl: false }).setView([collectorPos.lat, collectorPos.lng], 14);
                    L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
                        attribution: '&copy; OpenStreetMap contributors'
                    }).addTo(mapRef.current);
                }

                const map = mapRef.current;
                map.eachLayer((layer: any) => { if (layer instanceof L.Marker || layer instanceof L.Polyline) map.removeLayer(layer); });

                // Icons
                const collectorIcon = L.divIcon({ className: 'bg-indigo-600 w-4 h-4 rounded-full border-2 border-white shadow-lg' });
                const targetIcon = L.divIcon({ className: 'bg-emerald-600 w-4 h-4 rounded-full border-2 border-white shadow-lg' });

                L.marker([collectorPos.lat, collectorPos.lng], { icon: collectorIcon }).addTo(map);
                L.marker([targetPos.lat, targetPos.lng], { icon: targetIcon }).addTo(map);

                // Eco-friendly Polyline
                const latlngs = data.waypoints.map(p => [p.lat, p.lng]);
                L.polyline(latlngs, { 
                    color: '#10b981', 
                    weight: 6, 
                    opacity: 0.8,
                    className: 'eco-route-path'
                }).addTo(map);

                map.fitBounds(L.polyline(latlngs).getBounds(), { padding: [50, 50] });
                setLoading(false);
            } catch (err) {
                console.error(err);
                setLoading(false);
            }
        };

        initMapAndRoute();
    }, [collectorPos]);

    return (
        <div className="fixed inset-0 bg-white z-[80] flex flex-col font-sans animate-in slide-in-from-bottom duration-500">
            <header className="p-6 pt-12 flex justify-between items-center border-b border-zinc-100 bg-white/90 backdrop-blur-xl sticky top-0 z-10">
                <div className="flex items-center gap-3">
                    <button onClick={onClose} className="p-2 -ml-2 text-zinc-400">
                        <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15 19l-7-7 7-7" /></svg>
                    </button>
                    <div>
                        <h2 className="text-sm font-black text-zinc-900 uppercase tracking-widest leading-none">Logistics Core</h2>
                        <p className="text-[10px] font-bold text-emerald-600 uppercase mt-1">Eco-Optimized Route</p>
                    </div>
                </div>
                {route && (
                    <div className="text-right">
                        <p className="text-[10px] font-black text-zinc-400 uppercase">Save</p>
                        <p className="text-xs font-black text-zinc-900">{route.co2SavedGrams}g CO2</p>
                    </div>
                )}
            </header>

            <div className="flex-1 relative">
                <div id="logistics-map" className="w-full h-full bg-zinc-50"></div>
                {loading && (
                    <div className="absolute inset-0 bg-white/80 backdrop-blur-md flex flex-col items-center justify-center z-20">
                        <div className="w-12 h-12 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
                        <p className="text-[10px] font-black uppercase tracking-widest text-zinc-400">Mapping Carbon Pathway...</p>
                    </div>
                )}

                {route && (
                    <div className="absolute bottom-6 inset-x-6 z-20 space-y-3">
                        <div className="bg-white rounded-[28px] p-5 shadow-2xl border border-zinc-100">
                            <div className="flex justify-between items-center mb-4">
                                <div className="flex items-center gap-2">
                                    <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
                                    <span className="text-[10px] font-black uppercase tracking-widest text-emerald-600">Active Navigation</span>
                                </div>
                                <span className="text-xs font-black text-zinc-900">{route.distanceKm} KM • {route.estimatedTimeMins} MIN</span>
                            </div>
                            <p className="text-xs font-medium text-zinc-600 leading-relaxed mb-4">{route.instruction}</p>
                            <button 
                                onClick={onComplete}
                                className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-emerald-100 active:scale-95 transition-all"
                            >
                                Mark as Collected
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

