import React, { createContext, useContext, useState, useEffect } from 'react';
import { Role, AppState, EWasteItem, PickupRequest, ItemStatus, PickupStatus, User } from './types';

interface AppContextType extends AppState {
  login: (email: string, password: string) => Promise<void>;
  signup: (name: string, email: string, role: Role) => Promise<void>;
  logout: () => void;
  addItem: (item: Omit<EWasteItem, 'id' | 'status' | 'userId' | 'createdAt'>) => void;
  requestPickup: (itemIds: string[], address: string, coords?: { lat: number, lng: number }) => void;
  assignPickup: (pickupId: string, collectorId: string) => void;
  updatePickupStatus: (pickupId: string, status: PickupStatus) => void;
  deleteItem: (id: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

const STORAGE_KEY_USERS = 'ecocycle_users';
const STORAGE_KEY_SESSION = 'ecocycle_session';
const STORAGE_KEY_ITEMS = 'ecocycle_items';
const STORAGE_KEY_PICKUPS = 'ecocycle_pickups';

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [registeredUsers, setRegisteredUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_USERS);
    return saved ? JSON.parse(saved) : [
      { id: 'u1', name: 'Demo User', email: 'user@eco.com', role: Role.USER, points: 1250, totalCo2Saved: 14.5 },
      { id: 'c1', name: 'Eco Collector', email: 'collector@eco.com', role: Role.COLLECTOR, points: 0, totalCo2Saved: 0 },
      { id: 'a1', name: 'System Admin', email: 'admin@eco.com', role: Role.ADMIN, points: 0, totalCo2Saved: 0 }
    ];
  });

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const session = localStorage.getItem(STORAGE_KEY_SESSION);
    return session ? JSON.parse(session) : null;
  });

  const [items, setItems] = useState<EWasteItem[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_ITEMS);
    return saved ? JSON.parse(saved) : [];
  });

  const [pickups, setPickups] = useState<PickupRequest[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PICKUPS);
    return saved ? JSON.parse(saved) : [];
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(registeredUsers));
  }, [registeredUsers]);

  useEffect(() => {
    if (currentUser) {
      localStorage.setItem(STORAGE_KEY_SESSION, JSON.stringify(currentUser));
    } else {
      localStorage.removeItem(STORAGE_KEY_SESSION);
    }
  }, [currentUser]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ITEMS, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PICKUPS, JSON.stringify(pickups));
  }, [pickups]);

  const login = async (email: string, _password: string) => {
    const user = registeredUsers.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user) {
      setCurrentUser(user);
    } else {
      throw new Error("User not found. Please sign up.");
    }
  };

  const signup = async (name: string, email: string, role: Role) => {
    if (registeredUsers.some(u => u.email === email)) {
      throw new Error("User already exists.");
    }
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      email,
      role,
      points: 0,
      totalCo2Saved: 0
    };
    setRegisteredUsers(prev => [...prev, newUser]);
    setCurrentUser(newUser);
  };

  const logout = () => {
    setCurrentUser(null);
  };

  const addItem = (itemData: Omit<EWasteItem, 'id' | 'status' | 'userId' | 'createdAt'>) => {
    if (!currentUser) return;
    const newItem: EWasteItem = {
      ...itemData,
      id: Math.random().toString(36).substr(2, 9),
      status: ItemStatus.STORED,
      userId: currentUser.id,
      createdAt: Date.now(),
    };
    setItems(prev => [newItem, ...prev]);
  };

  const deleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const requestPickup = (itemIds: string[], address: string, coords?: { lat: number, lng: number }) => {
    if (!currentUser) return;
    const selectedItems = items.filter(i => itemIds.includes(i.id));
    const totalPoints = selectedItems.reduce((acc, curr) => acc + curr.estimatedPoints, 0);

    const newPickup: PickupRequest = {
      id: `p-${Math.random().toString(36).substr(2, 5)}`,
      userId: currentUser.id,
      itemIds,
      status: PickupStatus.PENDING,
      location: { address, coords },
      totalPoints,
      createdAt: Date.now(),
    };

    setPickups(prev => [newPickup, ...prev]);
    setItems(prev => prev.map(item => 
      itemIds.includes(item.id) ? { ...item, status: ItemStatus.PICKUP_REQUESTED } : item
    ));
  };

  const updatePickupStatus = (pickupId: string, status: PickupStatus) => {
    setPickups(prev => {
      const pickupIndex = prev.findIndex(p => p.id === pickupId);
      if (pickupIndex === -1) return prev;

      const p = prev[pickupIndex];
      const updatedPickup = { ...p, status };

      if (status === PickupStatus.IN_PROGRESS && currentUser?.role === Role.COLLECTOR) {
        updatedPickup.collectorId = currentUser.id;
      }

      if (status === PickupStatus.COMPLETED) {
        updatedPickup.completedAt = Date.now();

        const pickupItems = items.filter(item => p.itemIds.includes(item.id));
        const sessionCo2 = pickupItems.reduce((acc, item) => acc + (item.impact?.co2SavedKg || 0), 0);
        const sessionPoints = p.totalPoints;

        // Update current user points in session
        if (currentUser && currentUser.id === p.userId) {
          setCurrentUser(prevUser => {
            if (!prevUser) return null;
            return {
              ...prevUser,
              points: prevUser.points + sessionPoints,
              totalCo2Saved: prevUser.totalCo2Saved + sessionCo2
            };
          });
        }

        // Update stored users
        setRegisteredUsers(prevUsers => prevUsers.map(u => 
          u.id === p.userId ? {
            ...u,
            points: u.points + sessionPoints,
            totalCo2Saved: u.totalCo2Saved + sessionCo2
          } : u
        ));

        // Mark items as completed
        setItems(prevItems => prevItems.map(item => 
          p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.COMPLETED } : item
        ));
      } else if (status === PickupStatus.IN_PROGRESS) {
        setItems(prevItems => prevItems.map(item => 
          p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.IN_PROGRESS } : item
        ));
      }

      const newPickups = [...prev];
      newPickups[pickupIndex] = updatedPickup;
      return newPickups;
    });
  };

  const assignPickup = (pickupId: string, collectorId: string) => {
    setPickups(prev => prev.map(p => 
      p.id === pickupId ? { ...p, collectorId, status: PickupStatus.IN_PROGRESS } : p
    ));
    const pickup = pickups.find(p => p.id === pickupId);
    if (pickup) {
        setItems(prev => prev.map(item => 
            pickup.itemIds.includes(item.id) ? { ...item, status: ItemStatus.IN_PROGRESS } : item
        ));
    }
  };

  return (
    <AppContext.Provider value={{ 
      currentUser, items, pickups, login, signup, logout, addItem, requestPickup, assignPickup, updatePickupStatus, deleteItem 
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within an AppProvider');
  return context;
};

import React, { useState, useMemo, useEffect, useRef } from 'react';
import { useApp } from '../store';
import { Role, ItemStatus, PickupStatus, EWasteItem, PickupRequest } from '../types';
import { Scanner } from './Scanner';
import { PickupRequestModal } from './PickupRequestModal';
import { DownloadPanel } from './DownloadPanel';
import { MapSearch } from './MapSearch';
import { getEcoFriendlyRoute, EcoRouteResult } from '../geminiService';

declare var L: any; // Leaflet global

const M3Chip = ({ status }: { status: string }) => {
    const colors: Record<string, string> = {
        [ItemStatus.STORED]: 'bg-blue-100 text-blue-800 border-blue-200',
        [ItemStatus.PICKUP_REQUESTED]: 'bg-amber-100 text-amber-800 border-amber-200',
        [ItemStatus.IN_PROGRESS]: 'bg-indigo-100 text-indigo-800 border-indigo-200',
        [ItemStatus.COMPLETED]: 'bg-emerald-100 text-emerald-800 border-emerald-200',
        [PickupStatus.PENDING]: 'bg-zinc-100 text-zinc-800 border-zinc-200',
    };
    return (
        <span className={`px-3 py-1 rounded-lg text-[10px] font-bold uppercase border ${colors[status] || 'bg-zinc-100'}`}>
            {status.replace('_', ' ')}
        </span>
    );
}

const M3Card: React.FC<{ children: React.ReactNode; className?: string; onClick?: () => void }> = ({ children, className = "", onClick }) => (
  <div 
    onClick={onClick}
    className={`bg-white rounded-[28px] p-5 shadow-sm border border-zinc-100/50 ${className} ${onClick ? 'cursor-pointer active:scale-95 transition-all' : ''}`}
  >
    {children}
  </div>
);

// --- LEVELING LOGIC ---
const getLevelInfo = (points: number) => {
    const levels = [
        { name: 'Eco-Seed', min: 0, max: 500 },
        { name: 'Green Sprout', min: 501, max: 1500 },
        { name: 'Nature Guardian', min: 1501, max: 3500 },
        { name: 'Planet Protector', min: 3501, max: 7000 },
        { name: 'Earth Hero', min: 7001, max: Infinity }
    ];
    const levelIndex = levels.findIndex(l => points <= l.max);
    const current = levels[levelIndex === -1 ? levels.length - 1 : levelIndex];
    const levelNumber = levelIndex === -1 ? levels.length : levelIndex + 1;
    const progress = levelIndex === -1 ? 100 : ((points - current.min) / (current.max - current.min)) * 100;

    return { levelNumber, rankName: current.name, progress, nextMax: current.max };
};

// --- COLLECTOR COMPONENTS ---

const CollectorFleetMap: React.FC<{ 
    pickups: PickupRequest[];
    onSelectPickup: (p: PickupRequest) => void;
    activeRoutePickup?: PickupRequest | null;
}> = ({ pickups, onSelectPickup, activeRoutePickup }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapRef = useRef<any>(null);
    const markersRef = useRef<Map<string, any>>(new Map());
    const collectorMarkerRef = useRef<any>(null);
    const routeLayerRef = useRef<any>(null);
    const [collectorPos, setCollectorPos] = useState<{lat: number, lng: number} | null>(null);
    const [routeData, setRouteData] = useState<EcoRouteResult | null>(null);

    // Track Collector Location
    useEffect(() => {
        const watchId = navigator.geolocation.watchPosition(
            (pos) => {
                const newPos = { lat: pos.coords.latitude, lng: pos.coords.longitude };
                setCollectorPos(newPos);
            },
            (err) => {
                console.warn("GPS Access Denied, using simulation:", err);
                // Fallback to a simulation position in SF if GPS is blocked
                setCollectorPos({ lat: 37.7749, lng: -122.4194 });
            },
            { enableHighAccuracy: true }
        );
        return () => navigator.geolocation.clearWatch(watchId);
    }, []);

    // Initialize Map
    useEffect(() => {
        if (!mapContainerRef.current || mapRef.current) return;

        mapRef.current = L.map(mapContainerRef.current, { 
          zoomControl: false, 
          attributionControl: false 
        }).setView([37.7749, -122.4194], 13);

        L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png').addTo(mapRef.current);
    }, []);

    // Update Collector Marker Position
    useEffect(() => {
        if (!mapRef.current || !collectorPos) return;

        if (!collectorMarkerRef.current) {
            collectorMarkerRef.current = L.marker([collectorPos.lat, collectorPos.lng], {
                icon: L.divIcon({ className: 'collector-dot', iconSize: [20, 20] })
            }).addTo(mapRef.current);
            mapRef.current.setView([collectorPos.lat, collectorPos.lng], 13);
        } else {
            collectorMarkerRef.current.setLatLng([collectorPos.lat, collectorPos.lng]);
        }
    }, [collectorPos]);

    // Handle Route Generation for Active Target
    useEffect(() => {
        if (!activeRoutePickup || !collectorPos || activeRoutePickup.status !== PickupStatus.IN_PROGRESS) {
            if (routeLayerRef.current) mapRef.current.removeLayer(routeLayerRef.current);
            setRouteData(null);
            return;
        }

        const fetchRoute = async () => {
            const target = activeRoutePickup.location.coords || { lat: 37.78, lng: -122.42 };
            try {
                const data = await getEcoFriendlyRoute(collectorPos, target);
                setRouteData(data);

                if (routeLayerRef.current) mapRef.current.removeLayer(routeLayerRef.current);

                const latlngs = data.waypoints.map(w => [w.lat, w.lng]);
                routeLayerRef.current = L.polyline(latlngs, {
                    color: '#4f46e5',
                    weight: 6,
                    opacity: 0.8,
                    dashArray: '10, 10',
                    className: 'eco-route-path'
                }).addTo(mapRef.current);

                mapRef.current.fitBounds(routeLayerRef.current.getBounds(), { padding: [100, 100] });
            } catch (err) {
                console.error("Routing error:", err);
            }
        };

        fetchRoute();
    }, [activeRoutePickup, collectorPos]);

    // Update Pickup Markers
    useEffect(() => {
        if (!mapRef.current) return;

        // IDs of current markers to manage updates/deletions
        const currentPickupIds = new Set(pickups.map(p => p.id));

        // Remove markers that are no longer in the pickups list
        markersRef.current.forEach((marker, id) => {
            if (!currentPickupIds.has(id)) {
                mapRef.current.removeLayer(marker);
                markersRef.current.delete(id);
            }
        });

        // Add or update markers
        pickups.forEach(p => {
            const coords = p.location.coords || { lat: 37.77 + (Math.random() * 0.02), lng: -122.41 + (Math.random() * 0.02) };
            const isAccepted = p.status === PickupStatus.IN_PROGRESS;
            const markerClass = isAccepted ? 'pin-marker pin-accepted' : 'pin-marker pin-pending';

            let marker = markersRef.current.get(p.id);
            if (!marker) {
                marker = L.marker([coords.lat, coords.lng], {
                    icon: L.divIcon({ 
                        className: markerClass, 
                        html: `<span>${p.itemIds.length}</span>`,
                        iconSize: [24, 24] 
                    })
                }).addTo(mapRef.current);
                marker.on('click', () => onSelectPickup(p));
                markersRef.current.set(p.id, marker);
            } else {
                marker.setLatLng([coords.lat, coords.lng]);
                marker.setIcon(L.divIcon({ 
                    className: markerClass, 
                    html: `<span>${p.itemIds.length}</span>`,
                    iconSize: [24, 24] 
                }));
            }
        });

        if (!activeRoutePickup && markersRef.current.size > 0 && collectorPos) {
           // Maybe fit bounds to include collector and all points occasionally
        }

        mapRef.current.invalidateSize();
    }, [pickups, activeRoutePickup, onSelectPickup]);

    return (
        <div className="relative w-full h-full">
            <div ref={mapContainerRef} className="w-full h-full" />

            {routeData && (
                <div className="absolute top-4 inset-x-4 z-[10] pointer-events-none">
                    <div className="bg-white/90 backdrop-blur-xl rounded-2xl p-4 shadow-2xl border border-indigo-100 pointer-events-auto">
                        <div className="flex justify-between items-center mb-1">
                            <h4 className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">Eco-Logistics Engine</h4>
                            <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full">-{routeData.co2SavedGrams}g CO2</span>
                        </div>
                        <p className="text-xs font-bold text-zinc-900 truncate mb-1">{routeData.summary}</p>
                        <div className="flex items-center gap-3">
                            <span className="text-xs font-black text-zinc-400">{routeData.distanceKm}km</span>
                            <span className="text-xs font-black text-zinc-400">Est. {routeData.estimatedTimeMins}m</span>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

