  // Derived currentUser ensures we always have the latest data from the users array
  const currentUser = useMemo(() => {
    return registeredUsers.find(u => u.id === currentUserId) || null;
  }, [registeredUsers, currentUserId]);

  const [items, setItems] = useState<EWasteItem[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_ITEMS);
    return saved ? JSON.parse(saved) : [];
  });

  const [pickups, setPickups] = useState<PickupRequest[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PICKUPS);
    return saved ? JSON.parse(saved) : [];
  });

  // Persistence Effects
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(registeredUsers));
  }, [registeredUsers]);

  useEffect(() => {
    if (currentUserId) {
      localStorage.setItem(STORAGE_KEY_SESSION_ID, currentUserId);
    } else {
      localStorage.removeItem(STORAGE_KEY_SESSION_ID);
    }
  }, [currentUserId]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ITEMS, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PICKUPS, JSON.stringify(pickups));
  }, [pickups]);

  const login = async (email: string, _password: string) => {
    const user = registeredUsers.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user) {
      setCurrentUserId(user.id);
    } else {
      throw new Error("User not found. Please sign up.");
    }
  };

  const signup = async (name: string, email: string, role: Role) => {
    if (registeredUsers.some(u => u.email === email)) {
      throw new Error("User already exists.");
    }
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      email,
      role,
      points: 0,
      lifetimePoints: 0,
      totalCo2Saved: 0
    };
    setRegisteredUsers(prev => [...prev, newUser]);
    setCurrentUserId(newUser.id);
  };

  const logout = () => {
    setCurrentUserId(null);
  };

  const addItem = (itemData: Omit<EWasteItem, 'id' | 'status' | 'userId' | 'createdAt'>) => {
    if (!currentUser) return;
    const newItem: EWasteItem = {
      ...itemData,
      id: Math.random().toString(36).substr(2, 9),
      status: ItemStatus.STORED,
      userId: currentUser.id,
      createdAt: Date.now(),
    };
    setItems(prev => [newItem, ...prev]);
  };

  const deleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const requestPickup = (itemIds: string[], address: string, coords?: { lat: number, lng: number }) => {
    if (!currentUser) return;
    const selectedItems = items.filter(i => itemIds.includes(i.id));
    const totalPoints = selectedItems.reduce((acc, curr) => acc + curr.estimatedPoints, 0);

    const newPickup: PickupRequest = {
      id: `p-${Math.random().toString(36).substr(2, 5)}`,
      userId: currentUser.id,
      itemIds,
      status: PickupStatus.PENDING,
      location: { address, coords },
      totalPoints,
      createdAt: Date.now(),
    };

    setPickups(prev => [newPickup, ...prev]);
    setItems(prev => prev.map(item => 
      itemIds.includes(item.id) ? { ...item, status: ItemStatus.PICKUP_REQUESTED } : item
    ));
  };

  const updatePickupStatus = (pickupId: string, status: PickupStatus) => {
    setPickups(prevPickups => {
      const pickupIndex = prevPickups.findIndex(p => p.id === pickupId);
      if (pickupIndex === -1) return prevPickups;

      const p = prevPickups[pickupIndex];
      const updatedPickup = { ...p, status };

      if (status === PickupStatus.IN_PROGRESS && currentUser?.role === Role.COLLECTOR) {
        updatedPickup.collectorId = currentUser.id;
      }

      if (status === PickupStatus.COMPLETED) {
        updatedPickup.completedAt = Date.now();

        // Find points and impact for this pickup
        const pickupItems = items.filter(item => p.itemIds.includes(item.id));
        const sessionCo2 = pickupItems.reduce((acc, item) => acc + (item.impact?.co2SavedKg || 0), 0);
        const sessionPoints = p.totalPoints;

        // Update the requester's score in the master users list
        setRegisteredUsers(prevUsers => prevUsers.map(u => 
          u.id === p.userId ? {
            ...u,
            points: u.points + sessionPoints,
            lifetimePoints: u.lifetimePoints + sessionPoints,
            totalCo2Saved: u.totalCo2Saved + sessionCo2
          } : u
        ));

        // Mark items as completed in items list
        setItems(prevItems => prevItems.map(item => 
          p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.COMPLETED } : item
        ));
      } else if (status === PickupStatus.IN_PROGRESS) {
        setItems(prevItems => prevItems.map(item => 
          p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.IN_PROGRESS } : item
        ));
      }

      const newPickups = [...prevPickups];
      newPickups[pickupIndex] = updatedPickup;
      return newPickups;
    });
  };

  const assignPickup = (pickupId: string, collectorId: string) => {
    setPickups(prev => prev.map(p => 
      p.id === pickupId ? { ...p, collectorId, status: PickupStatus.IN_PROGRESS } : p
    ));
    const pickup = pickups.find(p => p.id === pickupId);
    if (pickup) {
        setItems(prev => prev.map(item => 
            pickup.itemIds.includes(item.id) ? { ...item, status: ItemStatus.IN_PROGRESS } : item
        ));
    }
  };

  return (
    <AppContext.Provider value={{ 
      currentUser, items, pickups, login, signup, logout, addItem, requestPickup, assignPickup, updatePickupStatus, deleteItem 
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within an AppProvider');
  return context;
};

