declare var L: any; // Leaflet global

const calculateDistance = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371; // km
    const dLat = (lat2 - lat1) * Math.PI / 180;
    const dLon = (lon2 - lon1) * Math.PI / 180;
    const a = 
        Math.sin(dLat/2) * Math.sin(dLat/2) +
        Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * 
        Math.sin(dLon/2) * Math.sin(dLon/2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
    return R * c;
};

const M3Chip = ({ status }: { status: string }) => {
    const colors: Record<string, string> = {
        [ItemStatus.STORED]: 'bg-blue-100 text-blue-800 border-blue-200',
        [ItemStatus.PICKUP_REQUESTED]: 'bg-amber-100 text-amber-800 border-amber-200',
        [ItemStatus.IN_PROGRESS]: 'bg-indigo-100 text-indigo-800 border-indigo-200',
        [ItemStatus.COMPLETED]: 'bg-emerald-100 text-emerald-800 border-emerald-200',
        [PickupStatus.PENDING]: 'bg-zinc-100 text-zinc-800 border-zinc-200',
    };
    return (
        <span className={`px-3 py-1 rounded-lg text-[9px] font-black uppercase border ${colors[status] || 'bg-zinc-100'}`}>
            {status.replace('_', ' ')}
        </span>
    );
}

const M3Card: React.FC<{ children: React.ReactNode; className?: string; onClick?: () => void }> = ({ children, className = "", onClick }) => (
  <div 
    onClick={onClick}
    className={`bg-white rounded-[32px] p-6 shadow-sm border border-zinc-100/50 ${className} ${onClick ? 'cursor-pointer active:scale-[0.98] transition-all' : ''}`}
  >
    {children}
  </div>
);

const getLevelInfo = (points: number) => {
    const levels = [
        { name: 'Eco-Seed', min: 0, max: 500 },
        { name: 'Green Sprout', min: 501, max: 1500 },
        { name: 'Nature Guardian', min: 1501, max: 3500 },
        { name: 'Planet Protector', min: 3501, max: 7000 },
        { name: 'Earth Hero', min: 7001, max: Infinity }
    ];
    const levelIndex = levels.findIndex(l => points <= l.max);
    const current = levels[levelIndex === -1 ? levels.length - 1 : levelIndex];
    const levelNumber = levelIndex === -1 ? levels.length : levelIndex + 1;
    const progress = levelIndex === -1 ? 100 : ((points - current.min) / (current.max - current.min)) * 100;

    return { levelNumber, rankName: current.name, progress, nextMax: current.max };
};

const CollectorFleetMap: React.FC<{ 
    pickups: PickupRequest[];
    onSelectPickup: (p: PickupRequest) => void;
    activeRoutePickup?: PickupRequest | null;
    collectorPos: {lat: number, lng: number} | null;
}> = ({ pickups, onSelectPickup, activeRoutePickup, collectorPos }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapRef = useRef<any>(null);
    const markersRef = useRef<Map<string, any>>(new Map());
    const collectorMarkerRef = useRef<any>(null);
    const radiusCircleRef = useRef<any>(null);

    useEffect(() => {
        if (!mapContainerRef.current || mapRef.current || !L) return;
        mapRef.current = L.map(mapContainerRef.current, { zoomControl: false, attributionControl: false }).setView([37.7749, -122.4194], 12);
        L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png').addTo(mapRef.current);
        setTimeout(() => mapRef.current?.invalidateSize(), 500);
    }, []);

    useEffect(() => {
        if (!mapRef.current || !collectorPos || !L) return;

        if (!collectorMarkerRef.current) {
            collectorMarkerRef.current = L.marker([collectorPos.lat, collectorPos.lng], {
                icon: L.divIcon({ className: 'collector-dot', iconSize: [20, 20] })
            }).addTo(mapRef.current);

            radiusCircleRef.current = L.circle([collectorPos.lat, collectorPos.lng], {
                radius: 25000,
                color: '#4f46e5',
                weight: 1.5,
                fillColor: '#4f46e5',
                fillOpacity: 0.05,
                dashArray: '5, 10'
            }).addTo(mapRef.current);

            mapRef.current.setView([collectorPos.lat, collectorPos.lng], 10);
        } else {
            collectorMarkerRef.current.setLatLng([collectorPos.lat, collectorPos.lng]);
            radiusCircleRef.current.setLatLng([collectorPos.lat, collectorPos.lng]);
        }
    }, [collectorPos]);

    useEffect(() => {
        if (!mapRef.current || !collectorPos || !L) return;

        const filteredPickups = pickups.filter(p => {
            const coords = p.location.coords || { lat: 37.77, lng: -122.41 };
            return calculateDistance(collectorPos.lat, collectorPos.lng, coords.lat, coords.lng) <= 25; 
        });

        const currentIds = new Set(filteredPickups.map(p => p.id));
        markersRef.current.forEach((m, id) => { if (!currentIds.has(id)) { mapRef.current.removeLayer(m); markersRef.current.delete(id); } });

        filteredPickups.forEach(p => {
            const coords = p.location.coords || { lat: 37.77, lng: -122.41 };
            const isAccepted = p.status === PickupStatus.IN_PROGRESS;
            let marker = markersRef.current.get(p.id);
            if (!marker) {
                marker = L.marker([coords.lat, coords.lng], {
                    icon: L.divIcon({ 
                        className: `pin-marker ${isAccepted ? 'pin-accepted' : 'pin-pending'}`, 
                        html: `<span>${p.itemIds.length}</span>`,
                        iconSize: [28, 28] 
                    })
                }).addTo(mapRef.current);
                marker.on('click', () => onSelectPickup(p));
                markersRef.current.set(p.id, marker);
            }
        });
    }, [pickups, collectorPos, onSelectPickup]);

    return <div ref={mapContainerRef} className="absolute inset-0 w-full h-full" />;
};

