const PermissionInitializer: React.FC = () => {
  useEffect(() => {
    /**
     * Proactively requests permissions to trigger the native bridge dialogs.
     * This addresses the issue where permissions are not visible in 'App Info'.
     * Note: You must also ensure these permissions are in your AndroidManifest.xml.
     */
    const requestInitialPermissions = async () => {
      try {
        // Trigger Geolocation
        if ("geolocation" in navigator) {
          navigator.geolocation.getCurrentPosition(
            () => { console.debug("Initial location check success"); },
            (e) => { console.debug("Initial location check skipped/denied", e); },
            { timeout: 3000, enableHighAccuracy: false }
          );
        }

        // Trigger Camera
        if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
          try {
            const s = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' }, audio: false });
            s.getTracks().forEach(t => t.stop());
            console.debug("Initial camera check success");
          } catch (e) {
            console.debug("Initial camera check skipped/denied", e);
          }
        }
      } catch (e) {
        console.debug("Overall initial permission request failed", e);
      }
    };

    // Slight delay to ensure bridge is ready
    const timer = setTimeout(requestInitialPermissions, 1000);
    return () => clearTimeout(timer);
  }, []);
  return null;
};

