/**
 * PermissionInitializer proactively requests system permissions on mount.
 * This is critical for mobile environments to trigger the native bridge pop-ups
 * and ensure permissions appear in the system's "App Info" settings.
 */
const PermissionInitializer: React.FC = () => {
  useEffect(() => {
    const requestInitialPermissions = async () => {
      console.debug("PermissionInitializer: Triggering native prompts...");

      // 1. Trigger Geolocation Popup
      if ("geolocation" in navigator) {
        navigator.geolocation.getCurrentPosition(
          (pos) => console.debug("Initial location access granted"),
          (err) => console.warn("Initial location access denied or timeout", err),
          { timeout: 5000, enableHighAccuracy: false }
        );
      }

      // 2. Trigger Camera Popup
      if (navigator.mediaDevices && navigator.mediaDevices.getUserMedia) {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ 
            video: { facingMode: 'environment' }, 
            audio: false 
          });
          // Immediately stop tracks so the camera light doesn't stay on
          stream.getTracks().forEach(track => track.stop());
          console.debug("Initial camera access granted");
        } catch (err) {
          console.warn("Initial camera access denied", err);
        }
      }
    };

    // Delay slightly to ensure the WebView bridge is fully initialized
    const timer = setTimeout(requestInitialPermissions, 1500);
    return () => clearTimeout(timer);
  }, []);

  return null;
};

