import React, { useRef, useState, useCallback, useEffect } from 'react';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraLive, setIsCameraLive] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      setError(null);
      setIsCameraLive(false);
      setIsInitializing(true);

      if (!navigator.mediaDevices?.getUserMedia) {
        throw new Error("Camera API not found. Please use a modern mobile browser.");
      }

      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: { ideal: 'environment' },
          width: { ideal: 1280 },
          height: { ideal: 720 }
        },
        audio: false
      };

      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        const video = videoRef.current;
        video.srcObject = s;
        video.setAttribute('playsinline', 'true');
        video.muted = true;

        // Force play and handle the promise
        video.play().catch(e => {
          console.error("Autoplay prevented:", e);
          setError("Tap 'Retry' to enable camera feed.");
        });
      }
    } catch (err: any) {
      console.error("Camera Hardware Error:", err);
      setIsInitializing(false);
      setError(err.name === 'NotAllowedError' ? "Camera access denied. Enable permissions in settings." : err.message);
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraLive(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "Identification failed. Check your connection.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || video.readyState < 2) {
      console.warn("Video not ready for capture");
      return;
    };

    const MAX_SIZE = 1024;
    let w = video.videoWidth;
    let h = video.videoHeight;

    if (w > h) {
      if (w > MAX_SIZE) { h *= MAX_SIZE / w; w = MAX_SIZE; }
    } else {
      if (h > MAX_SIZE) { w *= MAX_SIZE / h; h = MAX_SIZE; }
    }

    canvas.width = w;
    canvas.height = h;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, w, h);
      const base64 = canvas.toDataURL('image/jpeg', 0.85);
      await processImage(base64);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[200] flex flex-col font-sans select-none overflow-hidden animate-in fade-in duration-300">
      {/* Top Navigation */}
      <div className="absolute top-0 inset-x-0 p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/90 to-transparent z-[220]">
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full ${isCameraLive ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[10px] uppercase tracking-[0.4em]">AI Optical Core</h2>
        </div>
