                 <h4 className="font-black text-zinc-900 truncate">{item.name}</h4>
                 <p className="text-[10px] font-bold text-zinc-500 uppercase">+{item.estimatedPoints} PTS | {item.impact?.co2SavedKg}kg CO2</p>
