      >
        <svg className="w-6 h-6 text-emerald-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M12 4v16m8-8H4" /></svg>
        <span className="text-[10px] font-black uppercase tracking-[0.2em]">Scan Device</span>
      </button>

      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white/95 backdrop-blur-2xl border-t border-zinc-100 h-24 flex justify-around items-center px-4 z-[90] pb-[env(safe-area-inset-bottom)]">
        {[{id:'home',l:'Dashboard'},{id:'items',l:'Inventory'},{id:'centers',l:'Grounding'},{id:'history',l:'Impact'}].map(t => (
          <button key={t.id} onClick={() => setActiveTab(t.id as any)} className={`flex flex-col items-center gap-1 transition-all ${activeTab === t.id ? 'text-emerald-600' : 'text-zinc-400'}`}><div className={`w-1 h-1 rounded-full ${activeTab === t.id ? 'bg-emerald-600' : 'bg-transparent'}`}></div><span className={`uppercase text-[9px] font-black tracking-widest ${activeTab === t.id ? 'opacity-100' : 'opacity-60'}`}>{t.l}</span></button>
