                    }}
                    className="w-full h-2 bg-indigo-100 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
                <div className="flex justify-between px-1">
                    <span className="text-[8px] font-bold text-zinc-400">25KM</span>
