                                <div className="bg-emerald-50 px-3 py-1.5 rounded-xl flex items-center gap-2">
                                    <span className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">+{activePickup.totalPoints} PTS</span>
                                </div>
                            </div>
                        </div>
                        <button onClick={() => { setActivePickup(null); setActiveRoute(null); }} className="w-10 h-10 bg-zinc-50 rounded-2xl flex items-center justify-center text-zinc-300 active:scale-90 transition-all"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg></button>
                    </div>

                    {/* AI ECO ROUTE INTELLIGENCE */}
                    {activeRoute ? (
                      <div className="mb-6 p-5 bg-emerald-50/50 rounded-[24px] border border-emerald-100 animate-in zoom-in-95 duration-300">
