export const CollectorDashboard: React.FC = () => {
  const { pickups, updatePickupStatus, currentUser } = useApp();
  const [activePickup, setActivePickup] = useState<PickupRequest | null>(null);
  const [activeRoute, setActiveRoute] = useState<EcoRouteResult | null>(null);
  const [collectorPos, setCollectorPos] = useState<{lat: number, lng: number} | null>(null);
  const [isAnalyzingRoute, setIsAnalyzingRoute] = useState(false);
  const [rangeKm, setRangeKm] = useState(25);

  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => setCollectorPos({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => setCollectorPos({ lat: 37.7749, lng: -122.4194 }),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  const visiblePickups = useMemo(() => {
    if (!collectorPos) return [];
    return pickups.filter(p => {
        const coords = p.location.coords;
        if (!coords) return false; // Ensure coords exist for map display
        const dist = calculateDistance(collectorPos.lat, collectorPos.lng, coords.lat, coords.lng);
        const isWithinRange = dist <= rangeKm;
        const isAvailable = p.status === PickupStatus.PENDING || (p.collectorId === currentUser?.id && p.status === PickupStatus.IN_PROGRESS);
        return isWithinRange && isAvailable;
    });
  }, [pickups, currentUser, collectorPos, rangeKm]);

  // Handle automatic route calculation when mission starts
  const handleAnalyzeRoute = useCallback(async (targetPickup?: PickupRequest) => {
    const p = targetPickup || activePickup;
    if (!p || !collectorPos || !p.location.coords) return;
    setIsAnalyzingRoute(true);
    try {
      const route = await getEcoFriendlyRoute(collectorPos, p.location.coords);
      setActiveRoute(route);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzingRoute(false);
    }
  }, [activePickup, collectorPos]);

  useEffect(() => {
    // If we have an active in-progress pickup, auto-trigger analysis
    const inProgress = pickups.find(p => p.collectorId === currentUser?.id && p.status === PickupStatus.IN_PROGRESS);
    if (inProgress && !activeRoute && !isAnalyzingRoute) {
        setActivePickup(inProgress);
        handleAnalyzeRoute(inProgress);
    }
  }, [pickups, currentUser, activeRoute, isAnalyzingRoute, handleAnalyzeRoute]);

  const acceptedCount = visiblePickups.filter(p => p.status === PickupStatus.IN_PROGRESS).length;

  return (
    <div className="flex-1 relative flex flex-col h-full overflow-hidden">
      <div className="flex-1 relative bg-zinc-100">
        <CollectorFleetMap 
          pickups={visiblePickups} 
          onSelectPickup={(p) => { 
            setActivePickup(p); 
            // If already accepted, keep existing route
            if (p.status !== PickupStatus.IN_PROGRESS) setActiveRoute(null); 
          }}
          activeRoute={activeRoute}
          collectorPos={collectorPos}
          rangeKm={rangeKm}
          activePickupId={activePickup?.id || null}
        />

        <div className="absolute top-6 left-6 right-6 z-[80] pointer-events-none flex flex-col gap-3">
            <div className="bg-white/80 backdrop-blur-2xl p-5 rounded-[32px] shadow-2xl border border-zinc-100 pointer-events-auto flex items-center justify-between">
                <div>
                    <h3 className="text-sm font-black text-zinc-900 leading-none mb-1">Carrier Command</h3>
                    <div className="flex items-center gap-2">
                        <span className="w-1.5 h-1.5 rounded-full bg-indigo-500 animate-pulse"></span>
                        <span className="text-[9px] font-black uppercase tracking-widest text-zinc-400">{acceptedCount} Active Assignments</span>
                    </div>
                </div>
                <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 11c0 3.517-1.009 6.799-2.753 9.571m-3.44-2.04l.054-.09A10.003 10.003 0 0012 3c1.268 0 2.39.246 3.407.691m-7.381 2.75c.795.347 1.53.774 2.2 1.258M11 11a1 1 0 112 0v4.586l1.293-1.293a1 1 0 111.414 1.414l-3 3a1 1 0 01-1.414 0l-3-3a1 1 0 111.414-1.414L11 15.586V11z" /></svg>
                </div>
            </div>

            <div className="bg-white/90 backdrop-blur-xl p-4 px-6 rounded-[32px] shadow-xl border border-zinc-100 pointer-events-auto flex flex-col gap-3">
                <div className="flex justify-between items-center">
                    <div>
                        <span className="text-[9px] font-black uppercase tracking-[0.2em] text-indigo-600 block mb-0.5">Operational Radius</span>
                        <span className="text-[11px] font-black text-indigo-900">Current: {rangeKm}KM</span>
                    </div>
                    <div className="bg-indigo-600 text-white px-3 py-1 rounded-full flex items-center gap-1.5 animate-in fade-in duration-300">
                        <span className="w-1.5 h-1.5 rounded-full bg-white animate-pulse"></span>
                        <span className="text-[9px] font-black uppercase tracking-widest">{visiblePickups.length} Pickups</span>
                    </div>
                </div>
