                    }}
                    className="w-full h-2 bg-indigo-100 rounded-lg appearance-none cursor-pointer accent-indigo-600"
                />
            </div>
        </div>

        {activePickup && (
            <div className="absolute bottom-10 inset-x-6 z-[95] animate-in slide-in-from-bottom-10 duration-500">
                <div className="bg-white/95 backdrop-blur-3xl rounded-[40px] p-8 shadow-2xl border border-white/20">
                    <div className="flex justify-between items-start mb-4">
                        <div className="flex-1 pr-6">
                            <h4 className="text-xl font-black text-zinc-900 leading-tight mb-2 truncate">{activePickup.location.address}</h4>
