/**
 * Diagnostic Check: Validates if the device hardware is accessible.
 */
const HardwareDiagnostic: React.FC<{ onValidated: () => void }> = ({ onValidated }) => {
  const [status, setStatus] = useState({
    camera: 'pending',
    location: 'pending',
    secure: window.isSecureContext ? 'ok' : 'fail'
  });
  const [error, setError] = useState<string | null>(null);

  const runCheck = async () => {
    setError(null);
    const newStatus = { ...status };

    // 1. Check Camera
    try {
      if (!navigator.mediaDevices) throw new Error("API Missing");
      const stream = await navigator.mediaDevices.getUserMedia({ video: true });
      stream.getTracks().forEach(t => t.stop());
      newStatus.camera = 'ok';
    } catch (e: any) {
      console.warn("Camera check failed:", e);
      newStatus.camera = 'fail';
      setError("Camera access is blocked by the system.");
    }

    // 2. Check Location
    try {
      await new Promise((res, rej) => {
        navigator.geolocation.getCurrentPosition(res, rej, { timeout: 5000 });
      });
      newStatus.location = 'ok';
    } catch (e: any) {
      console.warn("Location check failed:", e);
      newStatus.location = 'fail';
    }

    setStatus(newStatus);
    if (newStatus.camera === 'ok' && newStatus.location === 'ok') {
      onValidated();
    }
  };

  useEffect(() => {
    runCheck();
  }, []);

  if (status.camera === 'ok' && status.location === 'ok') return null;

  return (
    <div className="fixed inset-0 bg-zinc-950 z-[999] flex flex-col items-center justify-center p-8 text-center">
      <div className="w-20 h-20 bg-emerald-500/10 rounded-3xl flex items-center justify-center mb-8 border border-emerald-500/20">
        <svg className="w-10 h-10 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" /></svg>
      </div>
      <h2 className="text-white text-2xl font-black mb-4 tracking-tight">Hardware Sync Required</h2>
      <p className="text-zinc-400 text-sm mb-8 leading-relaxed max-w-xs">
        Redo Pro needs to establish a secure bridge with your device's Camera and GPS modules.
      </p>

      <div className="w-full space-y-3 mb-10">
        <div className={`flex items-center justify-between p-4 rounded-2xl border ${status.camera === 'ok' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
          <span className="text-[10px] font-black uppercase tracking-widest">Neural Vision (Camera)</span>
          <span className="text-[10px] font-bold">{status.camera.toUpperCase()}</span>
        </div>
        <div className={`flex items-center justify-between p-4 rounded-2xl border ${status.location === 'ok' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
          <span className="text-[10px] font-black uppercase tracking-widest">Spatial Sync (GPS)</span>
          <span className="text-[10px] font-bold">{status.location.toUpperCase()}</span>
        </div>
      </div>

      <button 
        onClick={runCheck}
        className="w-full py-5 bg-white text-black rounded-2xl font-black text-xs uppercase tracking-[0.2em] active:scale-95 transition-all shadow-2xl shadow-emerald-500/20"
      >
        Authorize & Link Hardware
      </button>
      {error && <p className="mt-4 text-red-500 text-[10px] font-bold uppercase tracking-tight">{error}</p>}
    </div>
  );
};

