export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [isScanning, setIsScanning] = useState(false);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isCameraLive, setIsCameraLive] = useState(false);
  const [isInitializing, setIsInitializing] = useState(false);
  const { addItem } = useApp();

  const startCamera = async () => {
    try {
      setError(null);
      setIsCameraLive(false);
      setIsInitializing(true);

      // Deep Check for Mobile WebView support
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("This device/browser does not support camera hardware bridging.");
      }

      if (stream) {
        stream.getTracks().forEach(t => t.stop());
      }

      const constraints: MediaStreamConstraints = {
        video: {
          facingMode: 'environment', // Essential for e-waste scanning
          width: { ideal: 1280 },
          height: { ideal: 720 }
        },
        audio: false
      };

      const s = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(s);

      if (videoRef.current) {
        videoRef.current.srcObject = s;
        videoRef.current.setAttribute('playsinline', 'true');
        videoRef.current.muted = true;

        // Force immediate play
        await videoRef.current.play();
        setIsCameraLive(true);
      }
    } catch (err: any) {
      console.error("Camera Hardware Error:", err);
      setIsInitializing(false);

      let msg = "Camera failed to initialize.";
      if (err.name === 'NotAllowedError') msg = "Permissions denied at the OS level. Please check your phone settings.";
      if (err.name === 'NotFoundError') msg = "No camera hardware detected on this device.";
      if (err.name === 'NotReadableError') msg = "The camera is currently being used by another application.";

      setError(msg);
    } finally {
      setIsInitializing(false);
    }
  };

  const stopCamera = useCallback(() => {
    if (stream) {
      stream.getTracks().forEach(track => track.stop());
      setStream(null);
    }
    setIsCameraLive(false);
  }, [stream]);

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "Identification failed. Check your connection.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
      stopCamera();
    }
  };

  const capture = async () => {
    const video = videoRef.current;
    const canvas = canvasRef.current;

    if (!video || !canvas || !isCameraLive) return;

    const w = video.videoWidth;
    const h = video.videoHeight;
    canvas.width = w;
    canvas.height = h;

    const ctx = canvas.getContext('2d');
    if (ctx) {
      ctx.drawImage(video, 0, 0, w, h);
      const base64 = canvas.toDataURL('image/jpeg', 0.8);
      await processImage(base64);
    }
  };

  useEffect(() => {
    startCamera();
    return () => stopCamera();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[200] flex flex-col font-sans select-none overflow-hidden animate-in fade-in duration-300">
      <div className="absolute top-0 inset-x-0 p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/90 to-transparent z-[220]">
        <div className="flex items-center gap-3">
          <div className={`w-2.5 h-2.5 rounded-full ${isCameraLive ? 'bg-emerald-500 animate-pulse' : 'bg-red-500'}`}></div>
          <h2 className="font-black text-[10px] uppercase tracking-[0.4em]">Hardware Link: {isCameraLive ? 'ACTIVE' : 'OFFLINE'}</h2>
        </div>
        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center bg-white/10 backdrop-blur-xl rounded-2xl active:scale-90 transition-all border border-white/10">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center overflow-hidden">
        {!previewImage ? (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted 
              className={`w-full h-full object-cover transition-opacity duration-700 ${isCameraLive ? 'opacity-100' : 'opacity-20'}`} 
            />

            {(isInitializing || !isCameraLive) && !error && (
              <div className="absolute inset-0 flex flex-col items-center justify-center bg-zinc-950/80 z-[215] backdrop-blur-md">
                <div className="w-14 h-14 border-[5px] border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin mb-6"></div>
                <p className="text-emerald-500 text-[10px] font-black uppercase tracking-[0.3em] animate-pulse">Requesting Native Stream...</p>
              </div>
            )}
          </>
        ) : (
          <div className="w-full h-full p-4 flex items-center justify-center">
             <img src={previewImage} className="max-w-full max-h-[80%] rounded-[48px] shadow-2xl border-4 border-white/20 animate-in zoom-in-95 duration-500 object-contain" alt="Captured" />
          </div>
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/95 backdrop-blur-2xl flex flex-col items-center justify-center z-[250]">
            <div className="relative mb-8">
               <div className="w-20 h-20 border-[6px] border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin"></div>
            </div>
            <h3 className="text-white font-black text-2xl mb-2 tracking-tighter">AI NEURAL ANALYSIS</h3>
            <p className="text-emerald-400 text-[9px] font-black uppercase tracking-[0.4em] animate-pulse">Decomposing Material Data</p>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-10 top-1/2 -translate-y-1/2 bg-white rounded-[48px] p-10 text-center shadow-2xl z-[260]">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-3xl mx-auto flex items-center justify-center mb-6">
               <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
            </div>
            <p className="text-zinc-900 font-black text-sm mb-8">{error}</p>
            <button onClick={startCamera} className="w-full py-5 bg-zinc-950 text-white rounded-2xl font-black text-xs uppercase tracking-widest active:scale-95 transition-all">Retry Bridge</button>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 inset-x-0 bg-white rounded-t-[56px] p-10 pb-[calc(env(safe-area-inset-bottom,24px)+24px)] shadow-2xl z-[230] border-t border-zinc-50">
        {!result ? (
          <div className="flex items-center justify-center gap-10">
             <button onClick={() => fileInputRef.current?.click()} className="w-14 h-14 bg-zinc-100 text-zinc-400 rounded-2xl flex items-center justify-center active:scale-90 transition-all border border-zinc-200">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" /></svg>
             </button>

             <div className="relative">
                <button 
                  onClick={capture} 
                  disabled={isScanning || !isCameraLive} 
                  className={`w-24 h-24 rounded-full p-2.5 transition-all duration-300 ${isCameraLive ? 'bg-emerald-600 shadow-2xl active:scale-90' : 'bg-zinc-200 opacity-50'}`}
                >
                  <div className="w-full h-full rounded-full border-[5px] border-white/30 flex items-center justify-center">
                    <div className="w-12 h-12 rounded-full bg-white"></div>
                  </div>
                </button>
             </div>

             <button onClick={onClose} className="w-14 h-14 bg-zinc-100 text-zinc-400 rounded-2xl flex items-center justify-center active:scale-90 transition-all border border-zinc-200">
               <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 12H5m7 7l-7-7 7-7" /></svg>
             </button>
          </div>
        ) : (
          <div className="space-y-8 animate-in slide-in-from-bottom-4 duration-500">
