import React, { useRef, useState, useCallback, useEffect } from 'react';
import { Camera, CameraResultType, CameraSource } from '@capacitor/camera';
import { classifyEWaste, ClassificationResult } from '../geminiService';
import { useApp } from '../store';

export const Scanner: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [isScanning, setIsScanning] = useState(false);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [previewImage, setPreviewImage] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const { addItem } = useApp();

  const takePhoto = async () => {
    try {
      setError(null);
      const image = await Camera.getPhoto({
        quality: 90,
        allowEditing: false,
        resultType: CameraResultType.Base64,
        source: CameraSource.Camera,
      });

      if (image.base64String) {
        const base64 = `data:image/jpeg;base64,${image.base64String}`;
        await processImage(base64);
      }
    } catch (err: any) {
      if (err.message !== 'User cancelled photos app') {
        setError("Camera Error: " + err.message);
      }
    }
  };

  const processImage = async (base64: string) => {
    setIsScanning(true);
    setError(null);
    setPreviewImage(base64);

    try {
      const data = await classifyEWaste(base64);
      setResult(data);
    } catch (err: any) {
      setError(err.message || "Identification failed.");
      setPreviewImage(null);
    } finally {
      setIsScanning(false);
    }
  };

  useEffect(() => {
    // Automatically trigger native camera on mount
    takePhoto();
  }, []);

  return (
    <div className="fixed inset-0 bg-black z-[200] flex flex-col font-sans select-none overflow-hidden animate-in fade-in duration-300">
      <div className="absolute top-0 inset-x-0 p-6 pt-12 flex justify-between items-center text-white bg-gradient-to-b from-black/90 to-transparent z-[220]">
        <h2 className="font-black text-[10px] uppercase tracking-[0.4em]">Hardware Link: ACTIVE</h2>
        <button onClick={onClose} className="w-12 h-12 flex items-center justify-center bg-white/10 backdrop-blur-xl rounded-2xl">
          <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
        </button>
      </div>

      <div className="flex-1 relative bg-zinc-950 flex items-center justify-center">
        {previewImage && (
          <div className="w-full h-full p-4 flex items-center justify-center">
             <img src={previewImage} className="max-w-full max-h-[80%] rounded-[48px] shadow-2xl border-4 border-white/20 object-contain" alt="Captured" />
          </div>
        )}

        {isScanning && (
          <div className="absolute inset-0 bg-black/95 backdrop-blur-2xl flex flex-col items-center justify-center z-[250]">
            <div className="w-20 h-20 border-[6px] border-emerald-500/20 border-t-emerald-500 rounded-full animate-spin mb-8"></div>
            <h3 className="text-white font-black text-2xl mb-2 tracking-tighter uppercase">AI Neural Analysis</h3>
          </div>
        )}

        {error && (
          <div className="absolute inset-x-10 top-1/2 -translate-y-1/2 bg-white rounded-[48px] p-10 text-center shadow-2xl z-[260]">
            <p className="text-zinc-900 font-black text-sm mb-8">{error}</p>
            <button onClick={takePhoto} className="w-full py-5 bg-zinc-950 text-white rounded-2xl font-black text-xs uppercase tracking-widest">Retry Camera</button>
          </div>
        )}
      </div>

      <div className="fixed bottom-0 inset-x-0 bg-white rounded-t-[56px] p-10 pb-[calc(env(safe-area-inset-bottom,24px)+24px)] shadow-2xl z-[230]">
        {!result ? (
          <div className="flex items-center justify-center gap-10">
             <button onClick={takePhoto} className="w-24 h-24 rounded-full bg-emerald-600 p-2.5 shadow-2xl active:scale-90">
                <div className="w-full h-full rounded-full border-[5px] border-white/30 flex items-center justify-center">
                  <div className="w-12 h-12 rounded-full bg-white"></div>
