                <h3 className="text-2xl font-black text-zinc-900 leading-tight">{result.brand} {result.model}</h3>
              </div>
              <div className="bg-emerald-600 text-white px-5 py-4 rounded-[28px] text-center">
                <p className="text-[9px] font-black uppercase opacity-60">ECO PTS</p>
                <p className="text-2xl font-black">{result.estimatedPoints}</p>
