            <div className="flex gap-4">
              <button onClick={() => { setResult(null); setPreviewImage(null); takePhoto(); }} className="flex-1 py-5 bg-zinc-100 text-zinc-600 rounded-2xl font-black text-[11px] uppercase tracking-widest">Retake</button>
