import React, { useState } from 'react';
import { Geolocation } from '@capacitor/geolocation';
import { useApp } from '../store';
import { EWasteItem } from '../types';
import { geocodeAddress } from '../geminiService';

interface Props {
  onClose: () => void;
  selectedItems: EWasteItem[];
}

export const PickupRequestModal: React.FC<Props> = ({ onClose, selectedItems }) => {
  const [address, setAddress] = useState('');
  const [coords, setCoords] = useState<{ lat: number; lng: number } | undefined>();
  const [isLoadingLocation, setIsLoadingLocation] = useState(false);
  const [isVerifying, setIsVerifying] = useState(false);
  const { requestPickup } = useApp();

  const handleGetCurrentLocation = async () => {
    setIsLoadingLocation(true);
    try {
      const position = await Geolocation.getCurrentPosition();
      setCoords({
        lat: position.coords.latitude,
        lng: position.coords.longitude
      });
      setAddress(`Lat: ${position.coords.latitude.toFixed(4)}, Lng: ${position.coords.longitude.toFixed(4)}`);
    } catch (err) {
      alert("Unable to access GPS hardware. Ensure location is enabled on your device.");
    } finally {
      setIsLoadingLocation(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!address.trim()) return;

    let finalCoords = coords;

    if (!finalCoords) {
      setIsVerifying(true);
      try {
        const resolved = await geocodeAddress(address);
        if (resolved) finalCoords = resolved;
        else {
          alert("Location could not be verified.");
          setIsVerifying(false);
          return;
        }
      } catch (err) {
        setIsVerifying(false);
        return;
      }
    }

    requestPickup(selectedItems.map(i => i.id), address, finalCoords);
    onClose();
  };

  const totalPoints = selectedItems.reduce((acc, curr) => acc + curr.estimatedPoints, 0);

  return (
    <div className="fixed inset-0 bg-black/60 z-[200] flex items-end sm:items-center justify-center p-0 animate-in fade-in duration-300">
      <div className="bg-white w-full max-w-lg rounded-t-[40px] sm:rounded-[40px] overflow-hidden shadow-2xl">

        {isVerifying && (
          <div className="absolute inset-0 bg-white/90 backdrop-blur-sm z-50 flex flex-col items-center justify-center p-8">
             <div className="w-16 h-16 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin mb-4"></div>
             <p className="text-zinc-900 font-black">AI GEOSPATIAL VERIFICATION</p>
          </div>
        )}

        <div className="p-8 border-b border-zinc-100 flex justify-between items-center">
          <h2 className="text-2xl font-black text-zinc-900 tracking-tighter">Fleet Dispatch</h2>
          <button onClick={onClose} className="w-10 h-10 bg-zinc-50 rounded-2xl flex items-center justify-center text-zinc-400">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8">
          <div className="mb-8">
            <div className="bg-emerald-50 p-6 rounded-[24px] border border-emerald-100 flex justify-between items-center">
               <span className="text-[10px] font-black text-emerald-800 uppercase tracking-widest">Est. Rewards</span>
               <span className="text-2xl font-black text-emerald-600">+{totalPoints} PTS</span>
            </div>
          </div>

          <div className="mb-8">
            <label className="text-[10px] font-black text-zinc-400 uppercase tracking-[0.2em] mb-2 block">Pickup Location</label>
            <textarea
              required
              className="w-full px-5 py-4 bg-zinc-50 border border-zinc-200 rounded-2xl outline-none resize-none font-medium text-sm"
              rows={2}
              placeholder="Enter Address..."
              value={address}
              onChange={(e) => { setAddress(e.target.value); if (coords) setCoords(undefined); }}
            />
            <button
              type="button"
              onClick={handleGetCurrentLocation}
              disabled={isLoadingLocation}
              className="mt-4 w-full py-4 flex items-center justify-center gap-3 bg-white border border-zinc-200 rounded-2xl text-zinc-600 font-black text-[10px] uppercase tracking-widest shadow-sm active:scale-95 transition-all"
            >
              <svg className={`w-4 h-4 text-emerald-500 ${isLoadingLocation ? 'animate-spin' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /></svg>
              {isLoadingLocation ? 'Syncing with GPS...' : 'Use My Exact Location'}
            </button>
          </div>

          <button type="submit" className="w-full bg-zinc-950 text-white py-5 rounded-[24px] font-black text-xs uppercase tracking-[0.3em] shadow-2xl active:scale-[0.98]">Confirm Fleet Pickup</button>
        </form>
      </div>
    </div>
  );
};

