const HardwareDiagnostic: React.FC<{ onValidated: () => void }> = ({ onValidated }) => {
  const [status, setStatus] = useState({
    camera: 'pending',
    location: 'pending'
  });
  const [error, setError] = useState<string | null>(null);

  const runCheck = async () => {
    setError(null);
    let camOk = false;
    let locOk = false;

    try {
      const camPerm = await Camera.requestPermissions();
      if (camPerm.camera === 'granted') camOk = true;
    } catch (e) { console.warn(e); }

    try {
      const locPerm = await Geolocation.requestPermissions();
      if (locPerm.location === 'granted') locOk = true;
    } catch (e) { console.warn(e); }

    setStatus({
      camera: camOk ? 'ok' : 'fail',
      location: locOk ? 'ok' : 'fail'
    });

    if (camOk && locOk) {
      onValidated();
    } else {
      setError("Please grant permissions in system settings to use hardware features.");
    }
  };

  useEffect(() => {
    runCheck();
  }, []);

  if (status.camera === 'ok' && status.location === 'ok') return null;

  return (
    <div className="fixed inset-0 bg-zinc-950 z-[999] flex flex-col items-center justify-center p-8 text-center">
      <div className="w-20 h-20 bg-emerald-500/10 rounded-3xl flex items-center justify-center mb-8 border border-emerald-500/20">
