      <div className="w-full space-y-3 mb-10">
        <div className={`flex items-center justify-between p-4 rounded-2xl border ${status.camera === 'ok' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
          <span className="text-[10px] font-black uppercase tracking-widest">Camera Module</span>
          <span className="text-[10px] font-bold">{status.camera.toUpperCase()}</span>
        </div>
        <div className={`flex items-center justify-between p-4 rounded-2xl border ${status.location === 'ok' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
