          <span className="text-[10px] font-bold">{status.location.toUpperCase()}</span>
        </div>
      </div>

      <button onClick={runCheck} className="w-full py-5 bg-emerald-600 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] active:scale-95 transition-all shadow-2xl shadow-emerald-500/20">Link Hardware Now</button>
      {error && <p className="mt-4 text-red-500 text-[10px] font-bold uppercase tracking-tight">{error}</p>}
    </div>
  );
};

