const HardwareDiagnostic: React.FC<{ onValidated: () => void }> = ({ onValidated }) => {
  const [status, setStatus] = useState({
    camera: 'pending',
    location: 'pending'
  });
  const [error, setError] = useState<string | null>(null);
  const [isChecking, setIsChecking] = useState(false);

  const runCheck = async () => {
    setIsChecking(true);
    setError(null);
    let camOk = false;
    let locOk = false;

    try {
      // First, check current status
      const camStatus = await Camera.checkPermissions();
      if (camStatus.camera === 'granted') {
        camOk = true;
      } else {
        const camReq = await Camera.requestPermissions();
        if (camReq.camera === 'granted') camOk = true;
      }
    } catch (e) { 
      console.warn("Camera check failed", e); 
    }

    try {
      const locStatus = await Geolocation.checkPermissions();
      if (locStatus.location === 'granted') {
        locOk = true;
      } else {
        const locReq = await Geolocation.requestPermissions();
        if (locReq.location === 'granted') locOk = true;
      }
    } catch (e) { 
      console.warn("Location check failed", e); 
    }

    setStatus({
      camera: camOk ? 'ok' : 'fail',
      location: locOk ? 'ok' : 'fail'
    });

    setIsChecking(false);

    if (camOk && locOk) {
      onValidated();
    } else {
      setError("Permissions required. If the popups didn't appear, please check your System Settings.");
    }
  };

  useEffect(() => {
    // Attempt initial check without forcing popups immediately to see if already granted
    const initialCheck = async () => {
      const cam = await Camera.checkPermissions();
      const loc = await Geolocation.checkPermissions();
      if (cam.camera === 'granted' && loc.location === 'granted') {
        onValidated();
      }
    };
    initialCheck();
  }, []);

  return (
    <div className="fixed inset-0 bg-zinc-950 z-[999] flex flex-col items-center justify-center p-8 text-center">
      <div className="w-20 h-20 bg-emerald-500/10 rounded-3xl flex items-center justify-center mb-8 border border-emerald-500/20">
