const HardwareDiagnostic: React.FC<{ onValidated: () => void }> = ({ onValidated }) => {
  const [status, setStatus] = useState({
    camera: 'pending',
    location: 'pending'
  });
  const [error, setError] = useState<string | null>(null);
  const [isChecking, setIsChecking] = useState(false);

  const runCheck = async () => {
    setIsChecking(true);
    setError(null);
    let camOk = false;
    let locOk = false;

    try {
      const camStatus = await Camera.checkPermissions();
      if (camStatus.camera === 'granted') camOk = true;
      else {
        const camReq = await Camera.requestPermissions();
        if (camReq.camera === 'granted') camOk = true;
      }
    } catch (e: any) { 
      setError(`Camera Link Failure: ${e.message}`);
    }

    try {
      const locStatus = await Geolocation.checkPermissions();
      if (locStatus.location === 'granted') locOk = true;
      else {
        const locReq = await Geolocation.requestPermissions();
        if (locReq.location === 'granted') locOk = true;
      }
    } catch (e: any) { 
      setError(`GPS Link Failure: ${e.message}`);
    }

    setStatus({
      camera: camOk ? 'ok' : 'fail',
      location: locOk ? 'ok' : 'fail'
    });

    setIsChecking(false);
    if (camOk && locOk) onValidated();
  };

  return (
    <div className="fixed inset-0 bg-zinc-950 z-[999] flex flex-col items-center justify-center p-8 text-center">
      <div className="w-20 h-20 bg-emerald-500/10 rounded-3xl flex items-center justify-center mb-8 border border-emerald-500/20">
        <svg className="w-10 h-10 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
        </svg>
      </div>
      <h2 className="text-white text-2xl font-black mb-4 tracking-tight uppercase">Hardware Bridge</h2>
      <p className="text-zinc-400 text-sm mb-10 leading-relaxed max-w-xs">Linking AI core to physical sensors.</p>

      <div className="w-full space-y-3 mb-12">
        <div className={`flex items-center justify-between p-5 rounded-3xl border transition-all ${status.camera === 'ok' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
           <span className="text-[10px] font-black uppercase tracking-widest">Camera</span>
           <span className="text-[10px] font-black">{status.camera === 'ok' ? 'LINKED' : 'READY'}</span>
        </div>
        <div className={`flex items-center justify-between p-5 rounded-3xl border transition-all ${status.location === 'ok' ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-500' : 'bg-zinc-900 border-zinc-800 text-zinc-500'}`}>
           <span className="text-[10px] font-black uppercase tracking-widest">GPS</span>
           <span className="text-[10px] font-black">{status.location === 'ok' ? 'LINKED' : 'READY'}</span>
