const mountApp = () => {
  const rootElement = document.getElementById('root');
  if (!rootElement) {
    console.error("Critical: Root element not found.");
    return;
  }
  const root = ReactDOM.createRoot(rootElement);
  root.render(
    <React.StrictMode>
      <App />
    </React.StrictMode>
  );
};

// Safe initialization of PWA Elements for Camera/Files support
const init = async () => {
  try {
    // We import dynamically to avoid blocking the initial mount if it fails
    // @ts-ignore
    const { defineCustomElements } = await import('@capacitor/pwa-elements/loader');
    if (defineCustomElements) {
      defineCustomElements(window);
    }
  } catch (err) {
    console.warn("PWA Elements (Camera/Photo) could not be initialized:", err);
  } finally {
    mountApp();
  }
};

init();

