  EnvironmentalImpact({
    required this.co2SavedKg,
    required this.materialsSaved,
    required this.hazards,
    required this.recyclabilityScore,
    this.metalRecovery,
  });

  factory EnvironmentalImpact.fromMap(Map<String, dynamic> map) => EnvironmentalImpact(
    co2SavedKg: (map['co2SavedKg'] as num).toDouble(),
    materialsSaved: List<String>.from(map['materialsSaved'] ?? []),
