import 'package:google_generative_ai/google_generative_ai.dart';
import 'models.dart';

class GeminiService {
  // Use environment variable as per instructions
  static const String _apiKey = String.fromEnvironment('API_KEY');

  static GenerativeModel _getModel(String modelName, {List<Tool>? tools, List<Content>? systemInstruction}) {
    return GenerativeModel(
      model: modelName,
      apiKey: _apiKey,
      tools: tools,
      systemInstruction: systemInstruction != null ? systemInstruction.first : null,
    );
  }

  static Future<Map<String, dynamic>> classifyEWaste(Uint8List imageBytes) async {
    final model = _getModel('gemini-3-flash-preview');
    final prompt = [
      Content.multi([
        DataPart('image/jpeg', imageBytes),
        TextPart("Analyze this e-waste. Provide Brand, Model, Category, Environmental Impact, hazards, and handling steps in JSON. Return ONLY the JSON object.")
      ])
    ];

    final response = await model.generateContent(prompt);
    final text = response.text;
    if (text == null) throw Exception("AI response empty");

    // Simple cleaning for common markdown backticks
    final jsonStr = text.replaceAll('```json', '').replaceAll('```', '').trim();
    return jsonDecode(jsonStr);
  }

  static Future<Map<String, dynamic>> findRecyclingCenters(String query, {double? lat, double? lng}) async {
    // Maps grounding requires Gemini 2.5
    final model = _getModel('gemini-2.5-flash-latest', tools: [
      Tool(googleSearchRetrieval: GoogleSearchRetrieval())
    ]);

    final prompt = [Content.text("Search for certified e-waste recycling centers for: $query. Provide location details and links.")];

    // In Dart SDK, toolConfig is handled through content/context if not explicitly in GenerateContent
    final response = await model.generateContent(prompt);

    return {
      "text": response.text,
      "links": response.candidates.first.groundingMetadata?.groundingChunks?.map((c) => {
        "title": c.web?.title ?? "Facility",
        "uri": c.web?.uri ?? ""
      }).toList() ?? []
    };
  }

  static Future<Map<String, dynamic>> getEcoFriendlyRoute(double startLat, double startLng, double endLat, double endLng) async {
    final model = _getModel('gemini-2.5-flash-latest', tools: [
      Tool(googleSearchRetrieval: GoogleSearchRetrieval())
    ]);

    final prompt = [
      Content.text("Calculate a street-accurate eco-friendly route from [$startLat, $startLng] to [$endLat, $endLng]. Respond ONLY with JSON containing summary, distanceKm, estimatedTimeMins, co2SavedGrams, efficiencyScore, and waypoints (list of {lat, lng}).")
    ];

    final response = await model.generateContent(prompt);
    final jsonStr = response.text?.replaceAll('```json', '').replaceAll('```', '').trim();
    return jsonDecode(jsonStr ?? "{}");
  }
}

import 'package:flutter/material.dart';
import 'models.dart';

class AppStateProvider with ChangeNotifier {
  User? _currentUser;
  final List<EWasteItem> _items = [];
  final List<PickupRequest> _pickups = [];

  User? get currentUser => _currentUser;
  List<EWasteItem> get items => _items;
  List<PickupRequest> get pickups => _pickups;

  void login(String email) {
    // Mock authentication matching store.tsx
    _currentUser = User(
      id: 'u1',
      name: 'Demo User',
      email: email,
      role: email.contains('collector') ? Role.collector : Role.user,
      points: 1250,
      lifetimePoints: 1250,
      totalCo2Saved: 14.5,
    );
    notifyListeners();
  }

  void logout() {
    _currentUser = null;
    notifyListeners();
  }

  void addItem(EWasteItem item) {
    _items.insert(0, item);
    notifyListeners();
  }

  void requestPickup(List<String> itemIds, String address, double? lat, double? lng) {
    if (_currentUser == null) return;

    final selectedItems = _items.where((i) => itemIds.contains(i.id)).toList();
    final totalPoints = selectedItems.fold(0, (sum, i) => sum + i.estimatedPoints);

    final request = PickupRequest(
      id: 'p-${DateTime.now().millisecondsSinceEpoch}',
      userId: _currentUser!.id,
      itemIds: itemIds,
      status: PickupStatus.pending,
      address: address,
      lat: lat,
      lng: lng,
      totalPoints: totalPoints,
      createdAt: DateTime.now(),
    );

    _pickups.insert(0, request);
    for (var i in _items) {
      if (itemIds.contains(i.id)) i.status = ItemStatus.pickupRequested;
    }
    notifyListeners();
  }

  void updatePickupStatus(String pickupId, PickupStatus status) {
    final index = _pickups.indexWhere((p) => p.id == pickupId);
    if (index == -1) return;

    final p = _pickups[index];
    p.status = status;

    if (status == PickupStatus.inProgress && _currentUser?.role == Role.collector) {
      p.collectorId = _currentUser!.id;
    }

    if (status == PickupStatus.completed) {
      // Logic from store.tsx: transfer points and co2
      final pickupItems = _items.where((i) => p.itemIds.contains(i.id));
      final co2 = pickupItems.fold(0.0, (sum, i) => sum + (i.impact?.co2SavedKg ?? 0));

      _currentUser!.points += p.totalPoints;
      _currentUser!.lifetimePoints += p.totalPoints;
      _currentUser!.totalCo2Saved += co2;

      for (var i in _items) {
        if (p.itemIds.contains(i.id)) i.status = ItemStatus.completed;
      }
    }

    notifyListeners();
  }
}

