          Positioned(
            top: 64, left: 24, right: 24,
            child: Row(
              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              children: [
                const Text("HARDWARE LINK: ACTIVE", style: TextStyle(fontSize: 10, fontWeight: FontWeight.black, color: Colors.white70, letterSpacing: 2)),
