    status: ItemStatus.STORED,
    userId: 'u1',
    createdAt: Date.now() - 10000000,
    impact: {
      co2SavedKg: 25.5,
      materialsSaved: ['Aluminum', 'Gold', 'Copper'],
      hazards: ['Lithium Ion Battery'],
      recyclabilityScore: 85
    }
  },
  {
    id: 'i2',
    name: 'Galaxy S10',
    brand: 'Samsung',
    model: 'SM-G973F',
    category: 'Mobile Device',
    description: 'Water damaged, will not turn on.',
    estimatedPoints: 120,
    imageUrl: 'https://images.unsplash.com/photo-1512054502232-120bbc3a041c?auto=format&fit=crop&q=80&w=300',
    status: ItemStatus.PICKUP_REQUESTED,
    userId: 'u1',
    createdAt: Date.now() - 5000000,
    impact: {
      co2SavedKg: 8.2,
      materialsSaved: ['Glass', 'Cobalt'],
      hazards: ['Battery'],
      recyclabilityScore: 90
    }
  },
  {
    id: 'i3',
    name: 'Sony Bravia 42"',
    brand: 'Sony',
    model: 'KDL-42W650',
    category: 'Large Appliance',
    description: 'Dead pixels on screen.',
    estimatedPoints: 800,
    imageUrl: 'https://images.unsplash.com/photo-1593784991095-a205069470b6?auto=format&fit=crop&q=80&w=300',
    status: ItemStatus.COMPLETED,
    userId: 'u1',
    createdAt: Date.now() - 20000000,
    impact: {
      co2SavedKg: 45.0,
      materialsSaved: ['Plastic', 'Circuit Boards'],
      hazards: ['Capacitors'],
      recyclabilityScore: 70
    }
  }
];

const MOCK_PICKUPS: PickupRequest[] = [
  {
    id: 'p1',
    userId: 'u1',
    itemIds: ['i2'],
    status: PickupStatus.PENDING,
    location: {
      address: '123 Innovation Dr, Tech City',
      coords: { lat: 37.7749, lng: -122.4194 }
    },
    totalPoints: 120,
    createdAt: Date.now() - 100000,
  }
];

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [registeredUsers, setRegisteredUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_USERS);
    return saved ? JSON.parse(saved) : [
      { id: 'u1', name: 'Demo User', email: 'user@eco.com', role: Role.USER, points: 1370, lifetimePoints: 2500, totalCo2Saved: 78.7 },
      { id: 'c1', name: 'Eco Collector', email: 'collector@eco.com', role: Role.COLLECTOR, points: 0, lifetimePoints: 0, totalCo2Saved: 0 },
      { id: 'a1', name: 'System Admin', email: 'admin@eco.com', role: Role.ADMIN, points: 0, lifetimePoints: 0, totalCo2Saved: 0 }
    ];
  });

  const [currentUserId, setCurrentUserId] = useState<string | null>(() => {
    return localStorage.getItem(STORAGE_KEY_SESSION_ID);
  });

  const currentUser = useMemo(() => {
    return registeredUsers.find(u => u.id === currentUserId) || null;
  }, [registeredUsers, currentUserId]);

  const [items, setItems] = useState<EWasteItem[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_ITEMS);
    // Use MOCK_ITEMS default if storage is empty to ensure UI is populated
    return saved ? JSON.parse(saved) : MOCK_ITEMS;
  });

  const [pickups, setPickups] = useState<PickupRequest[]>(() => {
    const saved = localStorage.getItem(STORAGE_KEY_PICKUPS);
    return saved ? JSON.parse(saved) : MOCK_PICKUPS;
  });

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_USERS, JSON.stringify(registeredUsers));
  }, [registeredUsers]);

  useEffect(() => {
    if (currentUserId) {
      localStorage.setItem(STORAGE_KEY_SESSION_ID, currentUserId);
    } else {
      localStorage.removeItem(STORAGE_KEY_SESSION_ID);
    }
  }, [currentUserId]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_ITEMS, JSON.stringify(items));
  }, [items]);

  useEffect(() => {
    localStorage.setItem(STORAGE_KEY_PICKUPS, JSON.stringify(pickups));
  }, [pickups]);

  const login = async (email: string, _password: string) => {
    const user = registeredUsers.find(u => u.email.toLowerCase() === email.toLowerCase());
    if (user) {
      setCurrentUserId(user.id);
    } else {
      throw new Error("User not found.");
    }
  };

  const signup = async (name: string, email: string, role: Role) => {
    if (registeredUsers.some(u => u.email === email)) {
      throw new Error("User already exists.");
    }
    const newUser: User = {
      id: Math.random().toString(36).substr(2, 9),
      name,
      email,
      role,
      points: 0,
      lifetimePoints: 0,
      totalCo2Saved: 0
    };
    setRegisteredUsers(prev => [...prev, newUser]);
    setCurrentUserId(newUser.id);
  };

  const logout = () => {
    setCurrentUserId(null);
  };

  const addItem = (itemData: Omit<EWasteItem, 'id' | 'status' | 'userId' | 'createdAt'>) => {
    if (!currentUser) return;
    const newItem: EWasteItem = {
      ...itemData,
      id: Math.random().toString(36).substr(2, 9),
      status: ItemStatus.STORED,
      userId: currentUser.id,
      createdAt: Date.now(),
    };
    setItems(prev => [newItem, ...prev]);
  };

  const deleteItem = (id: string) => {
    setItems(prev => prev.filter(item => item.id !== id));
  };

  const requestPickup = (itemIds: string[], address: string, coords?: { lat: number, lng: number }) => {
    if (!currentUser) return;
    const selectedItems = items.filter(i => itemIds.includes(i.id));
    const totalPoints = selectedItems.reduce((acc, curr) => acc + curr.estimatedPoints, 0);

    const newPickup: PickupRequest = {
      id: `p-${Math.random().toString(36).substr(2, 5)}`,
      userId: currentUser.id,
      itemIds,
      status: PickupStatus.PENDING,
      location: { address, coords },
      totalPoints,
      createdAt: Date.now(),
    };

    setPickups(prev => [newPickup, ...prev]);
    setItems(prev => prev.map(item => 
      itemIds.includes(item.id) ? { ...item, status: ItemStatus.PICKUP_REQUESTED } : item
    ));
  };

  const updatePickupStatus = (pickupId: string, status: PickupStatus) => {
    setPickups(prevPickups => {
      const pickupIndex = prevPickups.findIndex(p => p.id === pickupId);
      if (pickupIndex === -1) return prevPickups;

      const p = prevPickups[pickupIndex];
      const updatedPickup = { ...p, status };

      if (status === PickupStatus.IN_PROGRESS && currentUser?.role === Role.COLLECTOR) {
        updatedPickup.collectorId = currentUser.id;
        setItems(prev => prev.map(item => 
          p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.IN_PROGRESS } : item
        ));
      }

      if (status === PickupStatus.COMPLETED) {
        updatedPickup.completedAt = Date.now();
        const pickupItems = items.filter(item => p.itemIds.includes(item.id));
        const sessionCo2 = pickupItems.reduce((acc, item) => acc + (item.impact?.co2SavedKg || 0), 0);
        const sessionPoints = p.totalPoints;

        setRegisteredUsers(prevUsers => prevUsers.map(u => 
          u.id === p.userId ? {
            ...u,
            points: u.points + sessionPoints,
            lifetimePoints: u.lifetimePoints + sessionPoints,
            totalCo2Saved: u.totalCo2Saved + sessionCo2
          } : u
        ));

        setItems(prevItems => prevItems.map(item => 
          p.itemIds.includes(item.id) ? { ...item, status: ItemStatus.COMPLETED } : item
        ));
      }

      const newPickups = [...prevPickups];
      newPickups[pickupIndex] = updatedPickup;
      return newPickups;
    });
  };

  const assignPickup = (pickupId: string, collectorId: string) => {
    setPickups(prev => prev.map(p => 
      p.id === pickupId ? { ...p, collectorId, status: PickupStatus.IN_PROGRESS } : p
    ));
  };

  return (
    <AppContext.Provider value={{ 
      currentUser, items, pickups, login, signup, logout, addItem, requestPickup, assignPickup, updatePickupStatus, deleteItem 
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within an AppProvider');
  return context;
};

import React, { Suspense, useEffect, useState } from 'react';
import { Camera } from '@capacitor/camera';
import { Geolocation } from '@capacitor/geolocation';
import { AppProvider, useApp } from './store';
import { Role } from './types';
import { UserDashboard, CollectorDashboard, AdminDashboard } from './components/Dashboards';
import { Auth } from './components/Auth';

const HardwareDiagnostic: React.FC<{ onValidated: () => void }> = ({ onValidated }) => {
  const [status, setStatus] = useState({
    camera: 'pending',
    location: 'pending'
  });
  const [error, setError] = useState<string | null>(null);
  const [isChecking, setIsChecking] = useState(false);

  // Auto-run check on mount for better UX
  useEffect(() => {
    runCheck();
  }, []);

  const runCheck = async () => {
    setIsChecking(true);
    setError(null);
    let camOk = false;
    let locOk = false;

    // Simulate delay for "Systems initializing" visual effect
    await new Promise(resolve => setTimeout(resolve, 1500));

    try {
      try {
        const camStatus = await Camera.checkPermissions();
        if (camStatus.camera === 'granted') camOk = true;
        else {
          const camReq = await Camera.requestPermissions();
          if (camReq.camera === 'granted') camOk = true;
        }
      } catch (e) {
        console.warn("Camera check failed (likely web preview), bypassing...", e);
        // Fallback for Web Preview so user isn't locked out
        camOk = true;
      }

      try {
        const locStatus = await Geolocation.checkPermissions();
        if (locStatus.location === 'granted') locOk = true;
        else {
          const locReq = await Geolocation.requestPermissions();
          if (locReq.location === 'granted') locOk = true;
        }
      } catch (e) {
        console.warn("Location check failed (likely web preview), bypassing...", e);
        // Fallback for Web Preview so user isn't locked out
        locOk = true;
      }
    } catch (e: any) { 
      // General fallback
      setError(`Diagnostic Warning: ${e.message}`);
      camOk = true;
      locOk = true;
    }

    setStatus({
      camera: camOk ? 'ok' : 'fail',
      location: locOk ? 'ok' : 'fail'
    });

    setIsChecking(false);

    // Proceed if passed or forced passed
    if (camOk && locOk) {
      setTimeout(onValidated, 800);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-950 z-[999] flex flex-col items-center justify-center p-8 text-center bg-[radial-gradient(circle_at_top,_var(--tw-gradient-stops))] from-emerald-900/20 via-slate-950 to-slate-950">
      <div className="w-28 h-28 bg-emerald-500/10 rounded-[40px] flex items-center justify-center mb-8 border border-emerald-500/20 shadow-[0_0_50px_rgba(16,185,129,0.15)] animate-pulse">
        <svg className="w-14 h-14 text-emerald-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M9 12l2 2 4-4m5.618-4.016A11.955 11.955 0 0112 2.944a11.955 11.955 0 01-8.618 3.04A12.02 12.02 0 003 9c0 5.591 3.824 10.29 9 11.622 5.176-1.332 9-6.03 9-11.622 0-1.042-.133-2.052-.382-3.016z" />
        </svg>
      </div>

      <div className="space-y-2 mb-12">
        <h2 className="text-white text-4xl font-black tracking-tighter uppercase">Hardware Bridge</h2>
        <p className="text-emerald-500/60 text-[10px] font-black uppercase tracking-[0.4em]">Establishing Neural Links</p>
      </div>

      <div className="w-full space-y-4 mb-16 max-w-xs">
        <div className={`group flex items-center justify-between p-6 rounded-[32px] border-2 transition-all duration-700 ${status.camera === 'ok' ? 'bg-emerald-500/10 border-emerald-500/40 text-emerald-400' : 'bg-slate-900/50 border-slate-800 text-slate-500'}`}>
           <div className="flex items-center gap-4">
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-colors ${status.camera === 'ok' ? 'bg-emerald-500 text-emerald-950' : 'bg-slate-800 text-slate-600'}`}>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
              </div>
              <span className="text-[11px] font-black uppercase tracking-widest">Optic Core</span>
           </div>
           <span className="text-[10px] font-black">{status.camera === 'ok' ? 'LOCKED' : (isChecking ? 'SYNCING...' : 'WAITING')}</span>
        </div>

        <div className={`group flex items-center justify-between p-6 rounded-[32px] border-2 transition-all duration-700 ${status.location === 'ok' ? 'bg-emerald-500/10 border-emerald-500/40 text-emerald-400' : 'bg-slate-900/50 border-slate-800 text-slate-500'}`}>
           <div className="flex items-center gap-4">
              <div className={`w-10 h-10 rounded-2xl flex items-center justify-center transition-colors ${status.location === 'ok' ? 'bg-emerald-500 text-emerald-950' : 'bg-slate-800 text-slate-600'}`}>
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
              </div>
              <span className="text-[11px] font-black uppercase tracking-widest">Geo Sync</span>
           </div>
           <span className="text-[10px] font-black">{status.location === 'ok' ? 'LOCKED' : (isChecking ? 'SYNCING...' : 'WAITING')}</span>
        </div>
      </div>

      <button 
        onClick={runCheck} 
        disabled={isChecking} 
        className="w-full max-w-xs py-6 bg-emerald-600 text-emerald-950 rounded-[32px] font-black text-xs uppercase tracking-[0.4em] active:scale-95 transition-all shadow-[0_20px_40px_rgba(16,185,129,0.3)] flex items-center justify-center gap-3 disabled:opacity-50"
      >
        {isChecking ? (
            <div className="w-5 h-5 border-3 border-emerald-950 border-t-transparent rounded-full animate-spin"></div>
        ) : 'Retry Sync'}
      </button>

      {error && (
        <div className="mt-10 px-6 py-4 bg-red-500/10 border border-red-500/30 rounded-2xl animate-in fade-in slide-in-from-bottom-2 duration-300">
          <p className="text-red-400 text-[10px] font-black uppercase tracking-widest">{error}</p>
        </div>
      )}

      <p className="mt-12 text-slate-600 text-[9px] font-black uppercase tracking-[0.2em]">Redo Pro Secure Environment v9.2</p>
    </div>
  );
};

const AppContent: React.FC = () => {
  const { currentUser, logout } = useApp();
  const [hardwareValidated, setHardwareValidated] = useState(false);

  if (!currentUser) return <Auth />;
  if (!hardwareValidated) return <HardwareDiagnostic onValidated={() => setHardwareValidated(true)} />;

  const renderDashboard = () => {
    switch (currentUser.role) {
      case Role.USER: return <UserDashboard />;
      case Role.COLLECTOR: return <CollectorDashboard />;
      case Role.ADMIN: return <AdminDashboard />;
      default: return <div className="p-10 text-center font-black text-zinc-400">Access Denied</div>;
    }
  };

  const isCollector = currentUser.role === Role.COLLECTOR;

  return (
    <div className="max-w-md mx-auto min-h-screen h-screen flex flex-col relative bg-zinc-50 shadow-2xl overflow-hidden font-sans">
      <header className="px-6 pt-[calc(env(safe-area-inset-top)+12px)] pb-4 bg-white flex justify-between items-center sticky top-0 z-[100] border-b border-zinc-100">
        <div className="flex items-center gap-3">
          <div className={`w-10 h-10 ${isCollector ? 'bg-indigo-600' : 'bg-emerald-600'} rounded-2xl flex items-center justify-center text-white font-black text-xl shadow-lg`}>R</div>
          <div>
            <h1 className="text-lg font-black text-zinc-900 leading-none tracking-tighter">Redo Pro</h1>
            <p className="text-[8px] text-zinc-400 font-black uppercase tracking-[0.2em] mt-0.5">{isCollector ? 'Logistics' : 'Consumer'}</p>
          </div>
        </div>
        <button onClick={logout} className="w-10 h-10 bg-zinc-100 rounded-2xl flex items-center justify-center text-zinc-400 active:scale-90 transition-all">
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" /></svg>
        </button>
      </header>

      <main className={`flex-1 relative flex flex-col overflow-hidden bg-white ${isCollector ? 'p-0' : 'p-6 overflow-y-auto'}`}>
        <Suspense fallback={<div className="flex items-center justify-center h-full"><div className="w-8 h-8 border-4 border-emerald-500 border-t-transparent rounded-full animate-spin"></div></div>}>
          {renderDashboard()}
        </Suspense>
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AppProvider>
      <AppContent />
    </AppProvider>
  );
};

export default App;

