export const CollectorDashboard: React.FC = () => {
  const { pickups, updatePickupStatus, currentUser } = useApp();
  const [activePickup, setActivePickup] = useState<PickupRequest | null>(null);
  const [activeRoute, setActiveRoute] = useState<EcoRouteResult | null>(null);
  const [collectorPos, setCollectorPos] = useState<{lat: number, lng: number} | null>(null);
  const [isAnalyzingRoute, setIsAnalyzingRoute] = useState(false);
  const [rangeKm, setRangeKm] = useState(25);

  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => setCollectorPos({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => setCollectorPos({ lat: 37.7749, lng: -122.4194 }),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  const visiblePickups = useMemo(() => {
    if (!collectorPos) return [];
    return pickups.filter(p => {
        const coords = p.location.coords;
        if (!coords) return false; 
        const dist = calculateDistance(collectorPos.lat, collectorPos.lng, coords.lat, coords.lng);
        const isWithinRange = dist <= rangeKm;
        const isAvailable = p.status === PickupStatus.PENDING || (p.collectorId === currentUser?.id && p.status === PickupStatus.IN_PROGRESS);
        return isWithinRange && isAvailable;
    });
  }, [pickups, currentUser, collectorPos, rangeKm]);

  const handleAnalyzeRoute = useCallback(async (targetPickup?: PickupRequest) => {
    const p = targetPickup || activePickup;
    if (!p || !collectorPos || !p.location.coords) return;
    setIsAnalyzingRoute(true);
    try {
      const route = await getEcoFriendlyRoute(collectorPos, p.location.coords);
      setActiveRoute(route);
    } catch (err) {
      console.error(err);
    } finally {
      setIsAnalyzingRoute(false);
    }
  }, [activePickup, collectorPos]);

  useEffect(() => {
    const inProgress = pickups.find(p => p.collectorId === currentUser?.id && p.status === PickupStatus.IN_PROGRESS);
    if (inProgress && (!activeRoute || activePickup?.id !== inProgress.id) && !isAnalyzingRoute) {
        setActivePickup(inProgress);
        handleAnalyzeRoute(inProgress);
    }
  }, [pickups, currentUser, activeRoute, isAnalyzingRoute, handleAnalyzeRoute, activePickup]);

  const acceptedCount = visiblePickups.filter(p => p.status === PickupStatus.IN_PROGRESS).length;

  return (
    <div className="flex flex-col h-full bg-zinc-50 relative">
      {/* MAP SECTION: Top 55% */}
      <div className="h-[55%] relative w-full z-10 shadow-2xl rounded-b-[40px] overflow-hidden border-b border-zinc-200">
        <CollectorFleetMap 
          pickups={visiblePickups} 
          onSelectPickup={(p) => { 
            setActivePickup(p); 
            if (p.status !== PickupStatus.IN_PROGRESS) setActiveRoute(null); 
          }}
          activeRoute={activeRoute}
          collectorPos={collectorPos}
          rangeKm={rangeKm}
          activePickupId={activePickup?.id || null}
        />

        {/* Floating Map Controls - Minimized */}
        <div className="absolute top-4 left-4 right-4 flex justify-between items-start pointer-events-none">
            <div className="bg-white/90 backdrop-blur-md px-4 py-2 rounded-2xl shadow-lg border border-zinc-100 pointer-events-auto">
                 <div className="flex items-center gap-2">
                    <span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span>
                    <span className="text-[10px] font-black uppercase tracking-widest text-zinc-600">Live Grid</span>
                </div>
            </div>
        </div>
      </div>

      {/* COMMAND DECK: Bottom 45% - Scrollable */}
      <div className="flex-1 overflow-y-auto bg-white relative z-0">
         <div className="p-6 pb-24 space-y-6">

            {/* Range & Stats Control */}
            <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
               <div className="flex justify-between items-center mb-4">
                  <div>
                      <h3 className="text-sm font-black text-zinc-900">Logistics Range</h3>
                      <p className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">{rangeKm}KM Radius</p>
                  </div>
                  <div className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-lg text-[10px] font-black">
                     {visiblePickups.length} JOBS FOUND
                  </div>
               </div>
               <input 
                  type="range" min="5" max="100" step="5" value={rangeKm}
                  onChange={(e) => setRangeKm(parseInt(e.target.value))}
                  className="w-full h-2 bg-zinc-200 rounded-lg appearance-none cursor-pointer accent-indigo-600"
               />
            </div>

            {/* Active Mission Panel OR Empty State */}
            {activePickup ? (
               <div className="animate-in slide-in-from-bottom-10 duration-500">
                  <div className="flex justify-between items-start mb-4">
                     <div>
