                     <button onClick={() => {setActivePickup(null); setActiveRoute(null);}} className="p-2 bg-zinc-100 rounded-xl text-zinc-400"><svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button>
                  </div>

                  {activeRoute ? (
                     <div className="bg-indigo-50/50 border border-indigo-100 p-5 rounded-[24px] mb-6 space-y-4">
                        <div className="flex justify-between items-end">
                           <div>
                              <p className="text-[9px] font-black text-indigo-400 uppercase tracking-widest mb-1">AI Route Optimization</p>
