                        </div>

                        <div className="grid grid-cols-2 gap-3">
                           <div className="bg-white p-3 rounded-xl flex items-center gap-3 shadow-sm">
                              <div className="w-8 h-8 rounded-lg bg-emerald-100 text-emerald-600 flex items-center justify-center shrink-0">
                                 <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z" clipRule="evenodd" /></svg>
                              </div>
                              <div>
                                 <p className="text-[8px] font-black text-zinc-400 uppercase">CO2 Savings</p>
                                 <p className="text-sm font-black text-emerald-600">{activeRoute.co2SavedGrams}g</p>
                              </div>
                           </div>
                           <div className="bg-white p-3 rounded-xl flex items-center gap-3 shadow-sm">
                              <div className="w-8 h-8 rounded-lg bg-blue-100 text-blue-600 flex items-center justify-center shrink-0">
                                 <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path d="M9 2a1 1 0 000 2h2a1 1 0 100-2H9z" /><path fillRule="evenodd" d="M4 5a2 2 0 012-2 3 3 0 003 3h2a3 3 0 003-3 2 2 0 012 2v11a2 2 0 01-2 2H6a2 2 0 01-2-2V5zm3 4a1 1 0 000 2h.01a1 1 0 100-2H7zm3 0a1 1 0 000 2h3a1 1 0 100-2h-3zm-3 4a1 1 0 100 2h.01a1 1 0 100-2H7zm3 0a1 1 0 100 2h3a1 1 0 100-2h-3z" clipRule="evenodd" /></svg>
                              </div>
                              <div>
                                 <p className="text-[8px] font-black text-zinc-400 uppercase">Distance</p>
                                 <p className="text-sm font-black text-zinc-800">{activeRoute.distanceKm} KM</p>
                              </div>
                           </div>
