export const CollectorDashboard: React.FC = () => {
  const { pickups, updatePickupStatus, currentUser, items } = useApp();
  const [activePickup, setActivePickup] = useState<PickupRequest | null>(null);
  const [activeRoute, setActiveRoute] = useState<EcoRouteResult | null>(null);
  const [collectorPos, setCollectorPos] = useState<{lat: number, lng: number} | null>(null);
  const [isAnalyzingRoute, setIsAnalyzingRoute] = useState(false);
  const [rangeKm, setRangeKm] = useState(25);
  const [currentView, setCurrentView] = useState<'mission' | 'vault'>('mission');

  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => setCollectorPos({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => setCollectorPos({ lat: 37.7749, lng: -122.4194 }),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  const visiblePickups = useMemo(() => {
    if (!collectorPos) return [];
    return pickups.filter(p => {
        const coords = p.location.coords;
        if (!coords) return false; 
        const dist = calculateDistance(collectorPos.lat, collectorPos.lng, coords.lat, coords.lng);
        return dist <= rangeKm && (p.status === PickupStatus.PENDING || (p.collectorId === currentUser?.id && p.status === PickupStatus.IN_PROGRESS));
    });
  }, [pickups, currentUser, collectorPos, rangeKm]);

  // Data for the Vault Visualization
  const pickedItems = useMemo(() => {
    return items.filter(i => {
        const p = pickups.find(pr => pr.itemIds.includes(i.id));
        return p && p.collectorId === currentUser?.id && p.status === PickupStatus.COMPLETED;
    });
  }, [items, pickups, currentUser]);

  const categoryData = useMemo(() => {
    const counts: Record<string, number> = {};
    pickedItems.forEach(i => { counts[i.category] = (counts[i.category] || 0) + 1; });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [pickedItems]);

  const handleAnalyzeRoute = useCallback(async (targetPickup?: PickupRequest) => {
    const p = targetPickup || activePickup;
    if (!p || !collectorPos || !p.location.coords) return;
    setIsAnalyzingRoute(true);
    try {
      const route = await getEcoFriendlyRoute(collectorPos, p.location.coords);
      setActiveRoute(route);
    } catch (err) { console.error(err); } 
    finally { setIsAnalyzingRoute(false); }
  }, [activePickup, collectorPos]);

  useEffect(() => {
    const inProgress = pickups.find(p => p.collectorId === currentUser?.id && p.status === PickupStatus.IN_PROGRESS);
    if (inProgress && (!activeRoute || activePickup?.id !== inProgress.id) && !isAnalyzingRoute) {
        setActivePickup(inProgress);
        handleAnalyzeRoute(inProgress);
    }
  }, [pickups, currentUser, activeRoute, isAnalyzingRoute, handleAnalyzeRoute, activePickup]);

  return (
    <div className="flex flex-col h-full bg-zinc-50 relative overflow-hidden">
      <div className="h-[50%] relative w-full z-10 shadow-2xl rounded-b-[40px] overflow-hidden border-b border-zinc-200">
        <CollectorFleetMap 
          pickups={visiblePickups} 
          onSelectPickup={(p) => { setActivePickup(p); setCurrentView('mission'); if (p.status !== PickupStatus.IN_PROGRESS) setActiveRoute(null); }}
          activeRoute={activeRoute}
          collectorPos={collectorPos}
          rangeKm={rangeKm}
          activePickupId={activePickup?.id || null}
        />
        <div className="absolute top-4 left-4 right-4 flex justify-between items-start pointer-events-none">
            <div className="bg-white/90 backdrop-blur-md px-4 py-2 rounded-2xl shadow-lg border border-zinc-100 pointer-events-auto">
                 <div className="flex items-center gap-2"><span className="w-2 h-2 rounded-full bg-indigo-500 animate-pulse"></span><span className="text-[10px] font-black uppercase tracking-widest text-zinc-600">Tactical Grid</span></div>
            </div>
            <div className="flex gap-2 pointer-events-auto">
                <button onClick={() => setCurrentView('mission')} className={`px-4 py-2 rounded-2xl font-black text-[9px] uppercase tracking-widest transition-all ${currentView === 'mission' ? 'bg-zinc-950 text-white shadow-xl' : 'bg-white/80 backdrop-blur text-zinc-500'}`}>Mission</button>
                <button onClick={() => setCurrentView('vault')} className={`px-4 py-2 rounded-2xl font-black text-[9px] uppercase tracking-widest transition-all ${currentView === 'vault' ? 'bg-indigo-600 text-white shadow-xl' : 'bg-white/80 backdrop-blur text-zinc-500'}`}>Vault</button>
            </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto bg-white relative z-0">
         <div className="p-6 pb-24 space-y-6">
            {currentView === 'mission' ? (
                <>
                    <div className="bg-zinc-50 rounded-[32px] p-6 border border-zinc-100">
                        <div className="flex justify-between items-center mb-4">
                            <div><h3 className="text-sm font-black text-zinc-900">Scanning Range</h3><p className="text-[10px] font-bold text-zinc-400 uppercase tracking-wider">{rangeKm}KM Radius</p></div>
                            <div className="bg-indigo-100 text-indigo-700 px-3 py-1 rounded-lg text-[10px] font-black">{visiblePickups.length} JOBS</div>
