import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

// Directly use process.env.API_KEY for initialization as per @google/genai guidelines
const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === "undefined" || apiKey === "") return null;

  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

/**
 * AI-Powered Geocoding: Resolves a text address into latitude and longitude.
 */
export const geocodeAddress = async (address: string): Promise<{ lat: number, lng: number } | null> => {
  const ai = getAIClient();
  if (!ai) return null;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Perform high-precision geocoding for this location: "${address}".`,
      config: {
        systemInstruction: "You are a precise geocoding engine. Respond ONLY with a raw JSON object: {\"lat\": number, \"lng\": number}. Do not include markdown formatting or any conversational text.",
        tools: [{ googleMaps: {} }],
      },
    });

    const text = response.text;
    if (!text) return null;

    // Robust JSON extraction: look for the first '{' and last '}'
    const startIndex = text.indexOf('{');
    const endIndex = text.lastIndexOf('}');

    if (startIndex !== -1 && endIndex !== -1) {
      const jsonStr = text.substring(startIndex, endIndex + 1);
      const result = JSON.parse(jsonStr.trim());
      if (typeof result.lat === 'number' && typeof result.lng === 'number') {
        return result;
      }
    }

    return null;
  } catch (error) {
    console.error("Geocoding Error:", error);
    return null;
  }
};

