const getLevelInfo = (points: number) => {
    const levels = [
        { name: 'Eco-Seed', min: 0, max: 500 },
        { name: 'Green Sprout', min: 501, max: 1500 },
        { name: 'Nature Guardian', min: 1501, max: 3500 },
        { name: 'Planet Protector', min: 3501, max: 7000 },
        { name: 'Earth Hero', min: 7001, max: Infinity }
    ];
    const levelIndex = levels.findIndex(l => points <= l.max);
    const current = levels[levelIndex === -1 ? levels.length - 1 : levelIndex];
    const progress = levelIndex === -1 ? 100 : ((points - current.min) / (current.max - current.min)) * 100;
    return { levelNumber: levelIndex === -1 ? levels.length : levelIndex + 1, rankName: current.name, progress };
};

const CollectorFleetMap: React.FC<{ 
    pickups: PickupRequest[];
    onSelectPickup: (p: PickupRequest) => void;
    activeRoute?: EcoRouteResult | null;
    collectorPos: {lat: number, lng: number} | null;
    rangeKm: number;
    activePickupId: string | null;
}> = ({ pickups, onSelectPickup, activeRoute, collectorPos, rangeKm, activePickupId }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapRef = useRef<any>(null);
    const markersRef = useRef<Map<string, any>>(new Map());
    const collectorMarkerRef = useRef<any>(null);
    const radiusCircleRef = useRef<any>(null);
    const polylineRef = useRef<any>(null);

    useEffect(() => {
        if (!mapContainerRef.current || mapRef.current || !L) return;
        mapRef.current = L.map(mapContainerRef.current, { 
            zoomControl: false, attributionControl: false, dragging: true, touchZoom: true 
        }).setView([37.7749, -122.4194], 12);
        L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png').addTo(mapRef.current);
        const resizeObserver = new ResizeObserver(() => { mapRef.current?.invalidateSize(); });
        resizeObserver.observe(mapContainerRef.current);
        return () => resizeObserver.disconnect();
    }, []);

    useEffect(() => {
        if (!mapRef.current || !collectorPos || !L) return;
        if (!collectorMarkerRef.current) {
            collectorMarkerRef.current = L.marker([collectorPos.lat, collectorPos.lng], {
                icon: L.divIcon({ className: 'collector-beacon', iconSize: [20, 20] })
            }).addTo(mapRef.current);
            radiusCircleRef.current = L.circle([collectorPos.lat, collectorPos.lng], {
                radius: rangeKm * 1000, color: '#4f46e5', weight: 1, fillColor: '#4f46e5', fillOpacity: 0.05, dashArray: '5, 5'
            }).addTo(mapRef.current);
        } else {
            collectorMarkerRef.current.setLatLng([collectorPos.lat, collectorPos.lng]);
            radiusCircleRef.current.setLatLng([collectorPos.lat, collectorPos.lng]);
            radiusCircleRef.current.setRadius(rangeKm * 1000);
        }
    }, [collectorPos, rangeKm]);

    useEffect(() => {
        if (!mapRef.current || !L) return;
        if (activeRoute && activeRoute.waypoints?.length) {
            if (polylineRef.current) mapRef.current.removeLayer(polylineRef.current);
            const latlngs = activeRoute.waypoints.map(w => [w.lat, w.lng]);
            polylineRef.current = L.polyline(latlngs, { color: '#10b981', weight: 6, opacity: 0.8, className: 'eco-route-path' }).addTo(mapRef.current);
            mapRef.current.fitBounds(polylineRef.current.getBounds(), { padding: [50, 50], animate: true });
        } else if (polylineRef.current) {
            mapRef.current.removeLayer(polylineRef.current);
            polylineRef.current = null;
        }
    }, [activeRoute]);

    useEffect(() => {
        if (!mapRef.current || !L) return;
        const currentIds = new Set(pickups.map(p => p.id));
        markersRef.current.forEach((m, id) => { if (!currentIds.has(id)) { mapRef.current.removeLayer(m); markersRef.current.delete(id); } });
        pickups.forEach(p => {
            const coords = p.location.coords;
            if (!coords) return; 
            const isAccepted = p.status === PickupStatus.IN_PROGRESS;
            const isActive = p.id === activePickupId;
            let marker = markersRef.current.get(p.id);
            const markerHtml = `<div class="pin-marker ${isAccepted ? 'pin-accepted' : 'pin-pending'} ${isActive ? 'ring-4 ring-white scale-125 shadow-2xl' : ''}"><span>${p.itemIds.length}</span></div>`;
            if (!marker) {
                marker = L.marker([coords.lat, coords.lng], { icon: L.divIcon({ className: '', html: markerHtml, iconSize: [28, 28] }) }).addTo(mapRef.current);
                marker.on('click', () => onSelectPickup(p));
                markersRef.current.set(p.id, marker);
            } else {
                marker.setLatLng([coords.lat, coords.lng]);
                marker.setIcon(L.divIcon({ className: '', html: markerHtml, iconSize: [28, 28] }));
            }
        });
    }, [pickups, onSelectPickup, activePickupId]);

    return <div ref={mapContainerRef} className="w-full h-full bg-slate-50" />;
};

