import { GoogleGenAI, Type, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey || apiKey === "undefined" || apiKey === "") return null;
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

/**
 * Helper to extract and parse JSON from conversational AI responses.
 */
const extractAndParseJson = (text: string) => {
  const startIndex = text.indexOf('{');
  const endIndex = text.lastIndexOf('}');
  if (startIndex === -1 || endIndex === -1) return null;
  try {
    const jsonStr = text.substring(startIndex, endIndex + 1);
    return JSON.parse(jsonStr.trim());
  } catch (e) {
    console.error("JSON Parse Error:", e);
    return null;
  }
};

export const geocodeAddress = async (address: string): Promise<{ lat: number, lng: number } | null> => {
  const ai = getAIClient();
  if (!ai) return null;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Identify the latitude and longitude for: "${address}".`,
      config: {
        systemInstruction: "You are a precise geocoding engine. Respond ONLY with raw JSON: {\"lat\": number, \"lng\": number}. Do not include conversational text or markdown.",
        tools: [{ googleMaps: {} }],
      },
    });

    return extractAndParseJson(response.text);
  } catch (error) {
    console.error("Geocoding Error:", error);
    return null;
  }
};

export interface EcoRouteResult {
  summary: string;
  distanceKm: number;
  estimatedTimeMins: number;
  co2SavedGrams: number;
  efficiencyScore: number;
  waypoints: { lat: number; lng: number }[];
  instruction: string;
  trafficNote?: string;
  optimizedOrder?: string[]; // IDs in optimal sequence
}

export const getOptimizedCollectionRoute = async (
  currentLocation: { lat: number; lng: number },
  stops: { id: string, lat: number, lng: number }[]
): Promise<EcoRouteResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("AI Engine offline.");

  try {
    const stopsText = stops.map(s => `[ID: ${s.id}, Coords: ${s.lat}, ${s.lng}]`).join(', ');
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Current Location: [${currentLocation.lat}, ${currentLocation.lng}]. Destinations: ${stopsText}.
      Analyze current traffic conditions and distance to provide an optimized eco-friendly pickup sequence.`,
      config: {
        systemInstruction: `You are a logistics pathfinder. Use Google Maps grounding to check real-time traffic.
        Optimize the sequence of stops to minimize total CO2 emissions and time.
        Respond ONLY with valid JSON: 
        { 
          "summary": string, 
          "distanceKm": number, 
          "estimatedTimeMins": number, 
          "co2SavedGrams": number, 
          "efficiencyScore": number, 
          "waypoints": [{ "lat": number, "lng": number }], 
          "instruction": string, 
          "trafficNote": string,
          "optimizedOrder": string[] (Array of stop IDs in the suggested order)
        }`,
        tools: [{ googleMaps: {} }],
      },
    });

    const parsed = extractAndParseJson(response.text);
    if (parsed) return parsed;

    throw new Error("Invalid AI optimization output.");
  } catch (error) {
    console.error("Optimization Error:", error);
    // Simple fallback: sequential order
    return {
      summary: "Manual Sequence (Link Error)",
      distanceKm: stops.length * 1.5,
      estimatedTimeMins: stops.length * 5,
      co2SavedGrams: 100,
      efficiencyScore: 80,
      waypoints: [currentLocation, ...stops.map(s => ({ lat: s.lat, lng: s.lng }))],
      instruction: "Proceed to stops sequentially. AI traffic data limited.",
      trafficNote: "Fallback routing active.",
      optimizedOrder: stops.map(s => s.id)
    };
  }
};

export const getEcoFriendlyRoute = async (
  start: { lat: number; lng: number },
  end: { lat: number; lng: number }
): Promise<EcoRouteResult> => {
  return getOptimizedCollectionRoute(start, [{ id: 'target', ...end }]);
};

export interface ClassificationResult {
  name: string;
  brand: string;
  model: string;
  category: string;
  estimatedPoints: number;
  description: string;
  impact: {
    co2SavedKg: number;
    materialsSaved: string[];
    hazards: string[];
    recyclabilityScore: number;
    metalRecovery: { element: string, percentage: number, marketValueUsd: number }[];
  };
  handlingSteps: string[];
}

export const classifyEWaste = async (base64Image: string): Promise<ClassificationResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("Neural Engine offline.");

  const base64Data = base64Image.includes('base64,') ? base64Image.split('base64,')[1] : base64Image;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { mimeType: 'image/jpeg', data: base64Data } },
          { text: "Analyze this e-waste device. Identify brand, model, recycling points, hazards, and environmental ROI." }
        ]
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            brand: { type: Type.STRING },
            model: { type: Type.STRING },
            category: { type: Type.STRING },
            estimatedPoints: { type: Type.NUMBER },
            description: { type: Type.STRING },
            impact: {
              type: Type.OBJECT,
              properties: {
                co2SavedKg: { type: Type.NUMBER },
                materialsSaved: { type: Type.ARRAY, items: { type: Type.STRING } },
                hazards: { type: Type.ARRAY, items: { type: Type.STRING } },
                recyclabilityScore: { type: Type.NUMBER },
                metalRecovery: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      element: { type: Type.STRING },
                      percentage: { type: Type.NUMBER },
                      marketValueUsd: { type: Type.NUMBER }
                    }
                  }
                }
              }
            },
            handlingSteps: { type: Type.ARRAY, items: { type: Type.STRING } }
          }
        }
      }
    });

    const parsed = extractAndParseJson(response.text);
    if (!parsed) throw new Error("Neural analysis returned unreadable data.");
    return parsed;
  } catch (error: any) {
    throw new Error("Neural Error: " + error.message);
  }
};

export interface GroundingResult {
  text: string;
  links: { title: string; uri: string }[];
}

export const findRecyclingCenters = async (query: string, lat?: number, lng?: number): Promise<GroundingResult> => {
  const ai = getAIClient();
  if (!ai) throw new Error("Grounding link offline.");

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: `Recycling centers for: ${query}.`,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: {
          retrievalConfig: {
            latLng: (lat && lng) ? { latitude: lat, longitude: lng } : undefined
          }
        }
      },
    });

    const text = response.text || "No facility found in current grid.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
    const links = chunks.filter((c: any) => c.maps).map((c: any) => ({ title: c.maps.title || "Facility", uri: c.maps.uri }));

    return { text, links };
  } catch (error) {
    throw new Error("Grounding verification failed.");
  }
};

