export const CollectorDashboard: React.FC = () => {
  const { pickups, updatePickupStatus, currentUser, items } = useApp();
  const [activePickup, setActivePickup] = useState<PickupRequest | null>(null);
  const [activeRoute, setActiveRoute] = useState<EcoRouteResult | null>(null);
  const [collectorPos, setCollectorPos] = useState<{lat: number, lng: number} | null>(null);
  const [isAnalyzingRoute, setIsAnalyzingRoute] = useState(false);
  const [currentView, setCurrentView] = useState<'mission' | 'vault'>('mission');

  // Multi-stop management
  const [acceptedPickupIds, setAcceptedPickupIds] = useState<string[]>([]);

  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => setCollectorPos({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => setCollectorPos({ lat: 37.7749, lng: -122.4194 }),
      { enableHighAccuracy: true }
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  const pickedItems = useMemo(() => {
    return items.filter(i => {
        const p = pickups.find(pr => pr.itemIds.includes(i.id));
        return p && p.collectorId === currentUser?.id && p.status === PickupStatus.COMPLETED;
    });
  }, [items, pickups, currentUser]);

  const categoryData = useMemo(() => {
    const counts: Record<string, number> = {};
    pickedItems.forEach(i => { counts[i.category] = (counts[i.category] || 0) + 1; });
    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  }, [pickedItems]);

  const handleOptimization = async () => {
    if (!collectorPos || acceptedPickupIds.length === 0) return;
    setIsAnalyzingRoute(true);
    try {
      const stops = pickups
        .filter(p => acceptedPickupIds.includes(p.id))
        .map(p => ({ id: p.id, lat: p.location.coords!.lat, lng: p.location.coords!.lng }));

      const route = await getOptimizedCollectionRoute(collectorPos, stops);
      setActiveRoute(route);
    } catch (e) {
      console.error(e);
    } finally {
      setIsAnalyzingRoute(false);
    }
  };

  const handleAccept = async (p: PickupRequest) => {
    setAcceptedPickupIds(prev => [...new Set([...prev, p.id])]);
    updatePickupStatus(p.id, PickupStatus.IN_PROGRESS);
    setActivePickup(p);
  };

  const currentAcceptedPickups = useMemo(() => {
    const list = pickups.filter(p => acceptedPickupIds.includes(p.id) && p.status !== PickupStatus.COMPLETED);
    // Sort based on optimized route order if available
