             <div><span className="text-[10px] font-black uppercase tracking-widest block leading-none">Neural Record</span><span className="text-[8px] font-bold text-zinc-400 uppercase mt-0.5">Repo Access</span></div>
          </div>
          <div className="bg-zinc-100 p-1 rounded-2xl flex gap-1">
              <button onClick={() => setCurrentView('mission')} className={`px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest ${currentView === 'mission' ? 'bg-zinc-900 text-white shadow-lg' : 'text-zinc-500'}`}>Grid</button>
              <button onClick={() => setCurrentView('vault')} className={`px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest ${currentView === 'vault' ? 'bg-indigo-600 text-white shadow-lg' : 'text-zinc-500'}`}>Vault</button>
