    // This prevents getting stuck on "Initializing Neural Bridge".
    const safetyTimer = setTimeout(() => {
        console.warn("Hardware check timed out - bypassing for web preview.");
        onValidated();
    }, 1000);

    return () => clearTimeout(safetyTimer);
  }, []);

  const runCheck = async () => {
    setIsChecking(true);
    let camOk = false;
    let locOk = false;

    try {
      // Optic Bridge Check
      try {
        // In a web browser, checkPermissions might hang or return 'prompt'
        const camPerms = await Camera.checkPermissions();
        camOk = camPerms.camera === 'granted';
      } catch (e) { 
        // If it fails (common in web preview), assume we can proceed
        camOk = true; 
